"""
Parameterized generator for GH937_airflow_63617.

Source PR:    https://github.com/apache/airflow/pull/63617
Source Issue: N/A

Seed varies: renames 'abs_path' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH937_airflow_63617'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH937_airflow_63617'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('abs_path', 'abs_path' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH937_airflow_63617',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'apache/airflow',
                "pr_number": 63617,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/apache/airflow/pull/63617",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'airflow-core/src/airflow/dag_processing/manager.py': '#\n# Licensed to the Apache Software Foundation (ASF) under one\n# or more contributor license agreements.  See the NOTICE file\n# distributed with this work for additional information\n# regarding copyright ownership.  The ASF licenses this file\n# to you under the Apache License, Version 2.0 (the\n# "License"); you may not use this file except in compliance\n# with the License.  You may obtain a copy of the License at\n#\n#   http://www.apache.org/licenses/LICENSE-2.0\n#\n# Unless required by applicable law or agreed to in writing,\n# software distributed under the License is distributed on an\n# "AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\n# KIND, either express or implied.  See the License for the\n# specific language governing permissions and limitations\n# under the License.\n"""Processes DAGs."""\n\nfrom __future__ import annotations\n\nimport contextlib\nimport functools\nimport gc\nimport inspect\nimport logging\nimport os\nimport random\nimport selectors\nimport signal\nimport sys\nimport time\nimport zipfile\nfrom collections import defaultdict, deque\nfrom dataclasses import dataclass, field\nfrom datetime import datetime, timedelta\nfrom operator import attrgetter, itemgetter\nfrom pathlib import Path\nfrom typing import TYPE_CHECKING, Any, Literal, NamedTuple, cast\n\nimport attrs\nimport structlog\nfrom sqlalchemy import select, update\nfrom sqlalchemy.orm import load_only\nfrom tabulate import tabulate\nfrom uuid6 import uuid7\n\nfrom airflow._shared.observability.metrics.stats import Stats, normalize_name_for_stats\nfrom airflow._shared.timezones import timezone\nfrom airflow.api_fastapi.execution_api.app import InProcessExecutionAPI\nfrom airflow.configuration import conf\nfrom airflow.dag_processing.bundles.base import BundleUsageTrackingManager\nfrom airflow.dag_processing.bundles.manager import DagBundlesManager\nfrom airflow.dag_processing.collection import update_dag_parsing_results_in_db\nfrom airflow.dag_processing.processor import DagFileParsingResult, DagFileProcessorProcess\nfrom airflow.exceptions import AirflowException\nfrom airflow.models.asset import remove_references_to_deleted_dags\nfrom airflow.models.dag import DagModel\nfrom airflow.models.dagbag import DagPriorityParsingRequest\nfrom airflow.models.dagbundle import DagBundleModel\nfrom airflow.models.dagwarning import DagWarning\nfrom airflow.models.db_callback_request import DbCallbackRequest\nfrom airflow.models.errors import ParseImportError\nfrom airflow.observability.metrics import stats_utils\nfrom airflow.sdk import SecretCache\nfrom airflow.sdk.log import init_log_file, logging_processors\nfrom airflow.typing_compat import assert_never\nfrom airflow.utils.file import list_py_file_paths, might_contain_dag\nfrom airflow.utils.log.logging_mixin import LoggingMixin\nfrom airflow.utils.net import get_hostname\nfrom airflow.utils.process_utils import (\n    kill_child_processes_by_pids,\n)\nfrom airflow.utils.retries import retry_db_transaction\nfrom airflow.utils.session import NEW_SESSION, create_session, provide_session\nfrom airflow.utils.sqlalchemy import prohibit_commit, with_row_locks\n\nif TYPE_CHECKING:\n    from collections.abc import Callable, Iterable, Iterator, Sequence\n    from socket import socket\n\n    from sqlalchemy.orm import Session\n    from sqlalchemy.sql import Select\n\n    from airflow.callbacks.callback_requests import CallbackRequest\n    from airflow.dag_processing.bundles.base import BaseDagBundle\n    from airflow.sdk.api.client import Client\n\n\nclass DagParsingStat(NamedTuple):\n    """Information on processing progress."""\n\n    done: bool\n    all_files_processed: bool\n\n\n@attrs.define\nclass DagFileStat:\n    """Information about single processing of one file."""\n\n    num_dags: int = 0\n    import_errors: int = 0\n    last_finish_time: datetime | None = None\n    last_duration: float | None = None\n    run_count: int = 0\n    last_num_of_db_queries: int = 0\n\n\n@dataclass(frozen=True)\nclass DagFileInfo:\n    """Information about a DAG file."""\n\n    rel_path: Path\n    bundle_name: str\n    bundle_path: Path | None = field(compare=False, default=None)\n    bundle_version: str | None = None\n\n    @property\n    def absolute_path(self) -> Path:\n        if not self.bundle_path:\n            raise ValueError("bundle_path not set")\n        return self.bundle_path / self.rel_path\n\n\ndef _config_int_factory(section: str, key: str):\n    return functools.partial(conf.getint, section, key)\n\n\ndef _config_bool_factory(section: str, key: str):\n    return functools.partial(conf.getboolean, section, key)\n\n\ndef _config_get_factory(section: str, key: str):\n    return functools.partial(conf.get, section, key)\n\n\ndef _resolve_path(instance: Any, attribute: attrs.Attribute, val: str | os.PathLike[str] | None):\n    if val is not None:\n        val = Path(val).resolve()\n    return val\n\n\ndef utc_epoch() -> datetime:\n    # pendulum utcnow() is not used as that sets a TimezoneInfo object\n    # instead of a Timezone. This is not picklable and also creates issues\n    # when using replace()\n    result = datetime(1970, 1, 1)\n    result = result.replace(tzinfo=timezone.utc)\n\n    return result\n\n\nclass _StubSelector(selectors.BaseSelector):\n    """\n    Stub to stand in until the real selector is created.\n\n    This is used in DagFileProcessorManager to keep Mypy happy, and emit a\n    slightly better error message than TypeError (if None is used) if a\n    contributor accidentally initializes a selector in a wrong place in the\n    future.\n\n    Some selectors do not work well in daemon mode after fork (exact reason\n    unknown; it\'s CPython internal). This stub allows us to delay creating a\n    selector until after forking and work around the issue.\n    """\n\n    def __getattribute__(self, name):\n        raise RuntimeError("Selector not initialized")\n\n    def register(self, fileobj, events, data=None): ...\n    def unregister(self, fileobj): ...\n    def select(self, timeout=None): ...\n    def get_map(self): ...\n\n\n@attrs.define(kw_only=True)\nclass DagFileProcessorManager(LoggingMixin):\n    """\n    Manage processes responsible for parsing DAGs.\n\n    Given a list of DAG definition files, this kicks off several processors\n    in parallel to process them and put the results to a multiprocessing.Queue\n    for DagFileProcessorAgent to harvest. The parallelism is limited and as the\n    processors finish, more are launched. The files are processed over and\n    over again, but no more often than the specified interval.\n\n    :param max_runs: The number of times to parse each file. -1 for unlimited.\n    :param bundle_names_to_parse: List of bundle names to parse. If None, all bundles are parsed.\n    :param processor_timeout: How long to wait before timing out a DAG file processor\n    """\n\n    max_runs: int\n    bundle_names_to_parse: list[str] | None = None\n    processor_timeout: float = attrs.field(\n        factory=_config_int_factory("dag_processor", "dag_file_processor_timeout")\n    )\n    selector: selectors.BaseSelector = attrs.field(factory=_StubSelector)\n\n    _parallelism: int = attrs.field(factory=_config_int_factory("dag_processor", "parsing_processes"))\n\n    parsing_cleanup_interval: float = attrs.field(\n        factory=_config_int_factory("scheduler", "parsing_cleanup_interval")\n    )\n    stale_bundle_cleanup_interval: float = attrs.field(\n        factory=_config_int_factory("dag_processor", "stale_bundle_cleanup_interval")\n    )\n    _file_process_interval: float = attrs.field(\n        factory=_config_int_factory("dag_processor", "min_file_process_interval")\n    )\n    stale_dag_threshold: float = attrs.field(\n        factory=_config_int_factory("dag_processor", "stale_dag_threshold")\n    )\n\n    _last_deactivate_stale_dags_time: float = attrs.field(default=0, init=False)\n    _last_stale_bundle_cleanup_time: float = attrs.field(default=0, init=False)\n    print_stats_interval: float = attrs.field(\n        factory=_config_int_factory("dag_processor", "print_stats_interval")\n    )\n    last_stat_print_time: float = attrs.field(default=0, init=False)\n\n    heartbeat: Callable[[], None] = attrs.field(default=lambda: None)\n    """An overridable heartbeat called once every time around the loop"""\n\n    _file_queue: deque[DagFileInfo] = attrs.field(factory=deque, init=False)\n    _file_stats: dict[DagFileInfo, DagFileStat] = attrs.field(\n        factory=lambda: defaultdict(DagFileStat), init=False\n    )\n\n    _dag_bundles: list[BaseDagBundle] = attrs.field(factory=list, init=False)\n    _bundle_versions: dict[str, str | None] = attrs.field(factory=dict, init=False)\n\n    _processors: dict[DagFileInfo, DagFileProcessorProcess] = attrs.field(factory=dict, init=False)\n\n    _parsing_start_time: float | None = attrs.field(default=None, init=False)\n    _num_run: int = attrs.field(default=0, init=False)\n\n    _callback_to_execute: dict[DagFileInfo, list[CallbackRequest]] = attrs.field(\n        factory=lambda: defaultdict(list), init=False\n    )\n\n    max_callbacks_per_loop: int = attrs.field(\n        factory=_config_int_factory("dag_processor", "max_callbacks_per_loop")\n    )\n\n    base_log_dir: str = attrs.field(\n        factory=_config_get_factory("logging", "dag_processor_child_process_log_directory")\n    )\n    _latest_log_symlink_date: datetime = attrs.field(factory=datetime.today, init=False)\n\n    bundle_refresh_check_interval: int = attrs.field(\n        factory=_config_int_factory("dag_processor", "bundle_refresh_check_interval")\n    )\n    _bundles_last_refreshed: float = attrs.field(default=0, init=False)\n    """Last time we checked if any bundles are ready to be refreshed"""\n    _force_refresh_bundles: set[str] = attrs.field(factory=set, init=False)\n    """List of bundles that need to be force refreshed in the next loop"""\n\n    _file_parsing_sort_mode: str = attrs.field(\n        factory=_config_get_factory("dag_processor", "file_parsing_sort_mode")\n    )\n\n    _api_server: InProcessExecutionAPI = attrs.field(init=False, factory=InProcessExecutionAPI)\n    """API server to interact with Metadata DB"""\n\n    def register_exit_signals(self):\n        """Register signals that stop child processes."""\n        signal.signal(signal.SIGINT, self._exit_gracefully)\n        signal.signal(signal.SIGTERM, self._exit_gracefully)\n        # So that we ignore the debug dump signal, making it easier to send\n        signal.signal(signal.SIGUSR2, signal.SIG_IGN)\n\n    def _exit_gracefully(self, signum, frame):\n        """Clean up DAG file processors to avoid leaving orphan processes."""\n        self.log.info("Exiting gracefully upon receiving signal %s", signum)\n        self.log.debug("Current Stacktrace is: %s", "\\n".join(map(str, inspect.stack())))\n        self.terminate()\n        self.end()\n        self.log.debug("Finished terminating DAG processors.")\n        sys.exit(os.EX_OK)\n\n    def sync_bundles(self) -> None:\n        """Sync configured DAG bundles to the metadata database."""\n        DagBundlesManager().sync_bundles_to_db()\n\n    def get_all_bundles(self) -> list[BaseDagBundle]:\n        """Return configured DAG bundles filtered by ``bundle_names_to_parse`` if provided."""\n        return list(DagBundlesManager().get_all_dag_bundles())\n\n    def run(self):\n        """\n        Use multiple processes to parse and generate tasks for the DAGs in parallel.\n\n        By processing them in separate processes, we can get parallelism and isolation\n        from potentially harmful user code.\n        """\n        # TODO: Temporary until AIP-92 removes DB access from DagProcessorManager.\n        # The manager needs MetastoreBackend to retrieve connections from the database\n        # during bundle initialization (e.g., GitDagBundle.__init__ → GitHook needs git credentials).\n        # This marks the manager as "server" context so ensure_secrets_backend_loaded() provides\n        # MetastoreBackend instead of falling back to EnvironmentVariablesBackend only.\n        # Child parser processes explicitly override this by setting _AIRFLOW_PROCESS_CONTEXT=client\n        # in _parse_file_entrypoint() to prevent inheriting server privileges.\n        # Related: https://github.com/apache/airflow/pull/57459\n        os.environ["_AIRFLOW_PROCESS_CONTEXT"] = "server"\n\n        # Initialization is delayed until here to avoid fork issues in some\n        # selector implementations. Also see _StubSelector documentation.\n        self.selector = selectors.DefaultSelector()\n\n        stats_factory = stats_utils.get_stats_factory(Stats)\n        Stats.initialize(factory=stats_factory)\n\n        self.register_exit_signals()\n\n        self.log.info("Processing files using up to %s processes at a time ", self._parallelism)\n        self.log.info("Process each file at most once every %s seconds", self._file_process_interval)\n\n        self.sync_bundles()\n        dag_bundles = self.get_all_bundles()\n        if self.bundle_names_to_parse:\n            dag_bundles = [b for b in dag_bundles if b.name in self.bundle_names_to_parse]\n        self._dag_bundles = dag_bundles\n\n        for bundle in self._dag_bundles:\n            self.log.info(\n                "Checking for new files in bundle %s every %s seconds", bundle.name, bundle.refresh_interval\n            )\n\n        self._symlink_latest_log_directory()\n\n        # To prevent COW in forked process parsing dag file\n        gc.freeze()\n\n        return self._run_parsing_loop()\n\n    def _scan_stale_dags(self):\n        """Scan and deactivate DAGs which are no longer present in files."""\n        now = time.monotonic()\n        elapsed_time_since_refresh = now - self._last_deactivate_stale_dags_time\n        if elapsed_time_since_refresh > self.parsing_cleanup_interval:\n            last_parsed = {\n                file_info: stat.last_finish_time\n                for file_info, stat in self._file_stats.items()\n                if stat.last_finish_time\n            }\n            self.deactivate_stale_dags(last_parsed=last_parsed)\n            self._last_deactivate_stale_dags_time = time.monotonic()\n\n    def _cleanup_stale_bundle_versions(self):\n        if self.stale_bundle_cleanup_interval <= 0:\n            return\n        now = time.monotonic()\n        elapsed_time_since_cleanup = now - self._last_stale_bundle_cleanup_time\n        if elapsed_time_since_cleanup < self.stale_bundle_cleanup_interval:\n            return\n        try:\n            self.cleanup_stale_bundle_versions()\n        except Exception:\n            self.log.exception("Error removing stale bundle versions")\n        finally:\n            self._last_stale_bundle_cleanup_time = now\n\n    def cleanup_stale_bundle_versions(self) -> None:\n        """Clean up stale DAG bundle version usage records."""\n        BundleUsageTrackingManager().remove_stale_bundle_versions()\n\n    @provide_session\n    def deactivate_stale_dags(\n        self,\n        last_parsed: dict[DagFileInfo, datetime | None],\n        session: Session = NEW_SESSION,\n    ):\n        """Detect and deactivate DAGs which are no longer present in files."""\n        to_deactivate = set()\n        bundle_names = {b.name for b in self._dag_bundles}\n        query = select(\n            DagModel.dag_id,\n            DagModel.bundle_name,\n            DagModel.fileloc,\n            DagModel.last_parsed_time,\n            DagModel.relative_fileloc,\n        ).where(~DagModel.is_stale, DagModel.bundle_name.in_(bundle_names))\n        dags_parsed = session.execute(query)\n\n        for dag in dags_parsed:\n            # When the Dag\'s last_parsed_time is more than the stale_dag_threshold older than the\n            # Dag file\'s last_finish_time, the Dag is considered stale as has apparently been removed from the file,\n            # This is especially relevant for Dag files that generate Dags in a dynamic manner.\n            file_info = DagFileInfo(rel_path=Path(dag.relative_fileloc), bundle_name=dag.bundle_name)\n            if last_finish_time := last_parsed.get(file_info, None):\n                if dag.last_parsed_time + timedelta(seconds=self.stale_dag_threshold) < last_finish_time:\n                    self.log.info(\n                        "Deactivating stale DAG %s. Not parsed for %s seconds (last parsed: %s).",\n                        dag.dag_id,\n                        int((last_finish_time - dag.last_parsed_time).total_seconds()),\n                        dag.last_parsed_time,\n                    )\n                    to_deactivate.add(dag.dag_id)\n\n        if to_deactivate:\n            deactivated_dagmodel = session.execute(\n                update(DagModel)\n                .where(DagModel.dag_id.in_(to_deactivate))\n                .values(is_stale=True)\n                .execution_options(synchronize_session="fetch")\n            )\n            deactivated = getattr(deactivated_dagmodel, "rowcount", 0)\n            if deactivated:\n                self.log.info("Deactivated %i DAGs which are no longer present in file.", deactivated)\n\n    def _run_parsing_loop(self):\n        # initialize cache to mutualize calls to Variable.get in DAGs\n        # needs to be done before this process is forked to create the DAG parsing processes.\n        SecretCache.init()\n\n        poll_time = 0.0\n\n        known_files: dict[str, set[DagFileInfo]] = {}\n\n        while True:\n            loop_start_time = time.monotonic()\n\n            self.heartbeat()\n\n            self._kill_timed_out_processors()\n\n            self._queue_requested_files_for_parsing()\n\n            self._refresh_dag_bundles(known_files=known_files)\n\n            if not self._file_queue:\n                # Generate more file paths to process if we processed all the files already. Note for this to\n                # clear down, we must have cleared all files found from scanning the dags dir _and_ have\n                # cleared all files added as a result of callbacks\n                self.prepare_file_queue(known_files=known_files)\n\n            self._start_new_processes()\n\n            self._service_processor_sockets(timeout=poll_time)\n\n            self._collect_results()\n\n            for callback in self._fetch_callbacks():\n                self._add_callback_to_queue(callback)\n            self._scan_stale_dags()\n            self._cleanup_stale_bundle_versions()\n            DagWarning.purge_inactive_dag_warnings()\n\n            # Update number of loop iteration.\n            self._num_run += 1\n\n            self.print_stats(known_files=known_files)\n\n            if self.max_runs_reached():\n                self.log.info(\n                    "Exiting dag parsing loop as all files have been processed %s times", self.max_runs\n                )\n                break\n\n            loop_duration = time.monotonic() - loop_start_time\n            if loop_duration < 1:\n                poll_time = 1 - loop_duration\n            else:\n                poll_time = 0.0\n\n    def _service_processor_sockets(self, timeout: float | None = 1.0):\n        """\n        Service subprocess events by polling sockets for activity.\n\n        This runs `select` (or a platform equivalent) to look for activity on the sockets connected to the\n        parsing subprocesses, and calls the registered handler function for each socket.\n\n        All the parsing processes socket handlers are registered into a single Selector\n        """\n        events = self.selector.select(timeout=timeout)\n        for key, _ in events:\n            socket_handler, on_close = key.data\n\n            # BrokenPipeError should be caught and treated as if the handler returned false, similar\n            # to EOF case\n            try:\n                need_more = socket_handler(key.fileobj)\n            except (BrokenPipeError, ConnectionResetError):\n                need_more = False\n            if not need_more:\n                sock: socket = key.fileobj  # type: ignore[assignment]\n                on_close(sock)\n                sock.close()\n\n    def _queue_requested_files_for_parsing(self) -> None:\n        """Queue any files requested for parsing as requested by users via UI/API."""\n        files = self._get_priority_files()\n        self._add_files_to_queue(files, mode="frontprio")\n        self._force_refresh_bundles |= {file.bundle_name for file in files}\n        if self._force_refresh_bundles:\n            self.log.info("Bundles being force refreshed: %s", ", ".join(self._force_refresh_bundles))\n\n    def should_skip_refresh(\n        self,\n        *,\n        bundle: BaseDagBundle,\n        elapsed_time_since_refresh: float,\n        current_version_matches_db: bool,\n        previously_seen: bool,\n    ) -> bool:\n        """Return ``True`` when a Dag bundle refresh should be skipped."""\n        return (\n            elapsed_time_since_refresh < bundle.refresh_interval\n            and current_version_matches_db\n            and previously_seen\n            and bundle.name not in self._force_refresh_bundles\n        )\n\n    @provide_session\n    def _get_priority_files(self, session: Session = NEW_SESSION) -> list[DagFileInfo]:\n        files: list[DagFileInfo] = []\n        bundles = {b.name: b for b in self._dag_bundles}\n        requests = session.scalars(\n            select(DagPriorityParsingRequest).where(DagPriorityParsingRequest.bundle_name.in_(bundles.keys()))\n        )\n        for request in requests:\n            bundle = bundles[request.bundle_name]\n            files.append(\n                DagFileInfo(\n                    rel_path=Path(request.relative_fileloc), bundle_name=bundle.name, bundle_path=bundle.path\n                )\n            )\n            session.delete(request)\n        return files\n\n    @provide_session\n    @retry_db_transaction\n    def _fetch_callbacks(\n        self,\n        session: Session = NEW_SESSION,\n    ) -> list[CallbackRequest]:\n        """Fetch callbacks from database and add them to the internal queue for execution."""\n        self.log.debug("Fetching callbacks from the database.")\n\n        callback_queue: list[CallbackRequest] = []\n        with prohibit_commit(session) as guard:\n            bundle_names = [bundle.name for bundle in self._dag_bundles]\n            query: Select[tuple[DbCallbackRequest]] = with_row_locks(\n                select(DbCallbackRequest)\n                .where(DbCallbackRequest.bundle_name.in_(bundle_names))\n                .order_by(DbCallbackRequest.priority_weight.desc())\n                .limit(self.max_callbacks_per_loop),\n                of=DbCallbackRequest,\n                session=session,\n                skip_locked=True,\n            )\n            callbacks: Sequence[DbCallbackRequest] = [\n                cb[0] if isinstance(cb, tuple) else cb for cb in session.scalars(query)\n            ]\n            for callback in callbacks:\n                req = callback.get_callback_request()\n                try:\n                    callback_queue.append(req)\n                    session.delete(callback)\n                except Exception as e:\n                    self.log.warning("Error adding callback for execution: %s, %s", callback, e)\n            guard.commit()\n        return callback_queue\n\n    def _add_callback_to_queue(self, request: CallbackRequest):\n        self.log.debug("Queuing %s CallbackRequest: %s", type(request).__name__, request)\n        try:\n            bundle = DagBundlesManager().get_bundle(name=request.bundle_name, version=request.bundle_version)\n        except ValueError:\n            # Bundle no longer configured\n            self.log.error("Bundle %s no longer configured, skipping callback", request.bundle_name)\n            return None\n        if bundle.supports_versioning and request.bundle_version:\n            try:\n                bundle.initialize()\n            except Exception:\n                self.log.exception(\n                    "Error initializing bundle %s version %s for callback, skipping",\n                    request.bundle_name,\n                    request.bundle_version,\n                )\n                return None\n\n        file_info = DagFileInfo(\n            rel_path=Path(request.filepath),\n            bundle_path=bundle.path,\n            bundle_name=request.bundle_name,\n            bundle_version=request.bundle_version,\n        )\n        self._callback_to_execute[file_info].append(request)\n        self._add_files_to_queue([file_info], mode="front")\n        Stats.incr("dag_processing.other_callback_count")\n\n    def _refresh_dag_bundles(self, known_files: dict[str, set[DagFileInfo]]):\n        """Refresh DAG bundles, if required."""\n        now = timezone.utcnow()\n\n        # we don\'t need to check if it\'s time to refresh every loop - that is way too often\n        next_check = self._bundles_last_refreshed + self.bundle_refresh_check_interval\n        now_seconds = time.monotonic()\n        if now_seconds < next_check and not self._force_refresh_bundles:\n            self.log.debug(\n                "Not time to check if DAG Bundles need refreshed yet - skipping. Next check in %.2f seconds",\n                next_check - now_seconds,\n            )\n            return\n\n        self._bundles_last_refreshed = now_seconds\n\n        any_refreshed = False\n        for bundle in self._dag_bundles:\n            # TODO: AIP-66 handle errors in the case of incomplete cloning? And test this.\n            #  What if the cloning/refreshing took too long(longer than the dag processor timeout)\n            if not bundle.is_initialized:\n                try:\n                    bundle.initialize()\n                    any_refreshed = True\n                except AirflowException as e:\n                    self.log.exception("Error initializing bundle %s: %s", bundle.name, e)\n                    continue\n            # TODO: AIP-66 test to make sure we get a fresh record from the db and it\'s not cached\n            with create_session() as session:\n                bundle_model = session.get(DagBundleModel, bundle.name)\n                if bundle_model is None:\n                    self.log.warning("Bundle model not found for %s", bundle.name)\n                    continue\n                elapsed_time_since_refresh = (\n                    now - (bundle_model.last_refreshed or utc_epoch())\n                ).total_seconds()\n                if bundle.supports_versioning:\n                    # we will also check the version of the bundle to see if another DAG processor has seen\n                    # a new version\n                    pre_refresh_version = (\n                        self._bundle_versions.get(bundle.name) or bundle.get_current_version()\n                    )\n                    current_version_matches_db = pre_refresh_version == bundle_model.version\n                else:\n                    # With no versioning, it always "matches"\n                    current_version_matches_db = True\n\n                previously_seen = bundle.name in self._bundle_versions\n                if self.should_skip_refresh(\n                    bundle=bundle,\n                    elapsed_time_since_refresh=elapsed_time_since_refresh,\n                    current_version_matches_db=current_version_matches_db,\n                    previously_seen=previously_seen,\n                ):\n                    self.log.info("Not time to refresh bundle %s", bundle.name)\n                    continue\n\n                self.log.info("Refreshing bundle %s", bundle.name)\n\n                try:\n                    bundle.refresh()\n                    any_refreshed = True\n                except Exception:\n                    self.log.exception("Error refreshing bundle %s", bundle.name)\n                    continue\n\n                bundle_model.last_refreshed = now\n                self._force_refresh_bundles.discard(bundle.name)\n\n                if bundle.supports_versioning:\n                    # We can short-circuit the rest of this if (1) bundle was seen before by\n                    # this dag processor and (2) the version of the bundle did not change\n                    # after refreshing it\n                    version_after_refresh = bundle.get_current_version()\n                    if previously_seen and pre_refresh_version == version_after_refresh:\n                        self.log.debug(\n                            "Bundle %s version not changed after refresh: %s",\n                            bundle.name,\n                            version_after_refresh,\n                        )\n                        continue\n\n                    bundle_model.version = version_after_refresh\n\n                    self.log.info(\n                        "Version changed for %s, new version: %s", bundle.name, version_after_refresh\n                    )\n                else:\n                    version_after_refresh = None\n\n            self._bundle_versions[bundle.name] = version_after_refresh\n\n            found_files = {\n                DagFileInfo(rel_path=p, bundle_name=bundle.name, bundle_path=bundle.path)\n                for p in self._find_files_in_bundle(bundle)\n            }\n\n            known_files[bundle.name] = found_files\n\n            self.deactivate_deleted_dags(bundle_name=bundle.name, present=found_files)\n            self.clear_orphaned_import_errors(\n                bundle_name=bundle.name,\n                observed_filelocs={str(x.rel_path) for x in found_files},  # todo: make relative\n            )\n\n        if any_refreshed:\n            self.handle_removed_files(known_files=known_files)\n            self._resort_file_queue()\n            self._add_new_files_to_queue(known_files=known_files)\n\n    def _find_files_in_bundle(self, bundle: BaseDagBundle) -> list[Path]:\n        """Get relative paths for dag files from bundle dir."""\n        # Build up a list of Python files that could contain DAGs\n        self.log.info("Searching for files in %s at %s", bundle.name, bundle.path)\n        rel_paths = [Path(x).relative_to(bundle.path) for x in list_py_file_paths(bundle.path)]\n        self.log.info("Found %s files for bundle %s", len(rel_paths), bundle.name)\n\n        return rel_paths\n\n    def deactivate_deleted_dags(self, bundle_name: str, present: set[DagFileInfo]) -> None:\n        """Deactivate DAGs that come from files that are no longer present in bundle."""\n\n        def find_zipped_dags(abs_path: os.PathLike) -> Iterator[str]:\n            """\n            Find dag files in zip file located at abs_path.\n\n            We return the abs "paths" formed by joining the relative path inside the zip\n            with the path to the zip.\n\n            """\n            try:\n                with zipfile.ZipFile(abs_path) as z:\n                    for info in z.infolist():\n                        if might_contain_dag(info.filename, True, z):\n                            yield os.path.join(abs_path, info.filename)\n            except zipfile.BadZipFile:\n                self.log.exception("There was an error accessing ZIP file %s", abs_path)\n\n        rel_filelocs: list[str] = []\n        for info in present:\n            abs_path = str(info.absolute_path)\n            if abs_path.endswith(".py") or not zipfile.is_zipfile(abs_path):\n                rel_filelocs.append(str(info.rel_path))\n            else:\n                if TYPE_CHECKING:\n                    assert info.bundle_path\n                for abs_sub_path in find_zipped_dags(abs_path=info.absolute_path):\n                    rel_sub_path = Path(abs_sub_path).relative_to(info.bundle_path)\n                    rel_filelocs.append(str(rel_sub_path))\n\n        with create_session() as session:\n            any_deactivated = DagModel.deactivate_deleted_dags(\n                bundle_name=bundle_name,\n                rel_filelocs=rel_filelocs,\n                session=session,\n            )\n            # Only run cleanup if we actually deactivated any DAGs\n            # This avoids unnecessary DELETE queries in the common case where no DAGs were deleted\n            if any_deactivated:\n                remove_references_to_deleted_dags(session=session)\n\n    def print_stats(self, known_files: dict[str, set[DagFileInfo]]):\n        """Occasionally print out stats about how fast the files are getting processed."""\n        if 0 < self.print_stats_interval < time.monotonic() - self.last_stat_print_time:\n            if known_files:\n                self._log_file_processing_stats(known_files=known_files)\n            self.last_stat_print_time = time.monotonic()\n\n    @provide_session\n    def clear_orphaned_import_errors(\n        self, bundle_name: str, observed_filelocs: set[str], session: Session = NEW_SESSION\n    ):\n        """\n        Clear import errors for files that no longer exist.\n\n        :param session: session for ORM operations\n        """\n        self.log.debug("Removing old import errors")\n        try:\n            errors = session.scalars(\n                select(ParseImportError)\n                .where(ParseImportError.bundle_name == bundle_name)\n                .options(load_only(ParseImportError.filename))\n            )\n            for error in errors:\n                if error.filename not in observed_filelocs:\n                    session.delete(error)\n        except Exception:\n            self.log.exception("Error removing old import errors")\n\n    def _log_file_processing_stats(self, known_files: dict[str, set[DagFileInfo]]):\n        """\n        Print out stats about how files are getting processed.\n\n        :param known_files: a list of file paths that may contain Airflow\n            DAG definitions\n        :return: None\n        """\n        # File Path: Path to the file containing the DAG definition\n        # PID: PID associated with the process that\'s processing the file. May\n        # be empty.\n        # Runtime: If the process is currently running, how long it\'s been\n        # running for in seconds.\n        # Last Runtime: If the process ran before, how long did it take to\n        # finish in seconds\n        # Last Run: When the file finished processing in the previous run.\n        # Last # of DB Queries: The number of queries performed to the\n        # Airflow database during last parsing of the file.\n        headers = [\n            "Bundle",\n            "File Path",\n            "PID",\n            "Current Duration",\n            "# DAGs",\n            "# Errors",\n            "Last Duration",\n            "Last Run At",\n        ]\n\n        rows = []\n        utcnow = timezone.utcnow()\n        now = time.monotonic()\n\n        for files in known_files.values():\n            for file in files:\n                stat = self._file_stats[file]\n                proc = self._processors.get(file)\n                num_dags = stat.num_dags\n                num_errors = stat.import_errors\n                file_name = Path(file.rel_path).stem\n                processor_pid = proc.pid if proc else None\n                processor_start_time = proc.start_time if proc else None\n                runtime = (now - processor_start_time) if processor_start_time else None\n                last_run = stat.last_finish_time\n                if last_run:\n                    seconds_ago = (utcnow - last_run).total_seconds()\n                    Stats.gauge(f"dag_processing.last_run.seconds_ago.{file_name}", seconds_ago)\n\n                rows.append(\n                    (\n                        file.bundle_name,\n                        file.rel_path,\n                        processor_pid,\n                        runtime,\n                        num_dags,\n                        num_errors,\n                        stat.last_duration,\n                        last_run,\n                    )\n                )\n\n        # Sort by longest last runtime. (Can\'t sort None values in python3)\n        rows.sort(key=lambda x: x[6] or 0.0, reverse=True)\n\n        formatted_rows = []\n        for (\n            bundle_name,\n            relative_path,\n            pid,\n            runtime,\n            num_dags,\n            num_errors,\n            last_runtime,\n            last_run,\n        ) in rows:\n            formatted_rows.append(\n                (\n                    bundle_name,\n                    relative_path,\n                    pid,\n                    f"{runtime:.2f}s" if runtime else None,\n                    num_dags,\n                    num_errors,\n                    f"{last_runtime:.2f}s" if last_runtime else None,\n                    last_run.strftime("%Y-%m-%dT%H:%M:%S") if last_run else None,\n                )\n            )\n        log_str = (\n            "\\n"\n            + "=" * 80\n            + "\\n"\n            + "DAG File Processing Stats\\n\\n"\n            + tabulate(formatted_rows, headers=headers)\n            + "\\n"\n            + "=" * 80\n        )\n\n        self.log.info(log_str)\n\n    def handle_removed_files(self, known_files: dict[str, set[DagFileInfo]]):\n        """\n        Remove from data structures the files that are missing.\n\n        Also, terminate processes that may be running on those removed files.\n\n        :param known_files: structure containing known files per-bundle\n        :return: None\n        """\n        files_set: set[DagFileInfo] = set()\n        """Set containing all observed files.\n\n        We consolidate to one set for performance.\n        """\n\n        for v in known_files.values():\n            files_set |= v\n\n        self.purge_removed_files_from_queue(present=files_set)\n        self.terminate_orphan_processes(present=files_set)\n        self.remove_orphaned_file_stats(present=files_set)\n\n    def purge_removed_files_from_queue(self, present: set[DagFileInfo]):\n        """Remove from queue any files no longer observed locally."""\n        self._file_queue = deque(x for x in self._file_queue if x in present)\n        Stats.gauge("dag_processing.file_path_queue_size", len(self._file_queue))\n\n    def remove_orphaned_file_stats(self, present: set[DagFileInfo]):\n        """Remove the stats for any dag files that don\'t exist anymore."""\n        # todo: store stats by bundle also?\n        stats_to_remove = set(self._file_stats).difference(present)\n        for file in stats_to_remove:\n            del self._file_stats[file]\n\n    def terminate_orphan_processes(self, present: set[DagFileInfo]):\n        """Stop processors that are working on deleted files."""\n        for file in list(self._processors.keys()):\n            if file not in present:\n                processor = self._processors.pop(file, None)\n                if not processor:\n                    continue\n                file_name = str(file.rel_path)\n                self.log.warning("Stopping processor for %s", file_name)\n                Stats.decr("dag_processing.processes", tags={"file_path": file_name, "action": "stop"})\n                processor.kill(signal.SIGKILL)\n                processor.logger_filehandle.close()\n                self._file_stats.pop(file, None)\n\n    @provide_session\n    def _collect_results(self, session: Session = NEW_SESSION):\n        # TODO: Use an explicit session in this fn\n        finished = []\n        for file, proc in self._processors.items():\n            if not proc.is_ready:\n                # This processor hasn\'t finished yet, or we haven\'t read all the output from it yet\n                continue\n            finished.append(file)\n\n            # Detect if this was callback-only processing\n            # For such-cases, we don\'t serialize the dags and hence send parsing_result as None.\n            is_callback_only = proc.had_callbacks and proc.parsing_result is None\n            if is_callback_only:\n                self.log.debug("Detected callback-only processing for %s", file)\n\n            # Collect the DAGS and import errors into the DB, emit metrics etc.\n            self._file_stats[file] = process_parse_results(\n                run_duration=time.monotonic() - proc.start_time,\n                finish_time=timezone.utcnow(),\n                run_count=self._file_stats[file].run_count,\n                bundle_name=file.bundle_name,\n                bundle_version=self._bundle_versions[file.bundle_name],\n                parsing_result=proc.parsing_result,\n                session=session,\n                is_callback_only=is_callback_only,\n                relative_fileloc=str(file.rel_path),\n            )\n\n        for file in finished:\n            processor = self._processors.pop(file)\n            processor.logger_filehandle.close()\n\n    def _get_log_dir(self) -> str:\n        return os.path.join(self.base_log_dir, timezone.utcnow().strftime("%Y-%m-%d"))\n\n    def _symlink_latest_log_directory(self):\n        """\n        Create symbolic link to the current day\'s log directory.\n\n        Allows easy access to the latest parsing log files.\n        """\n        log_directory = self._get_log_dir()\n        latest_log_directory_path = os.path.join(self.base_log_dir, "latest")\n        if os.path.isdir(log_directory):\n            rel_link_target = Path(log_directory).relative_to(Path(latest_log_directory_path).parent)\n            try:\n                # if symlink exists but is stale, update it\n                if os.path.islink(latest_log_directory_path):\n                    if os.path.realpath(latest_log_directory_path) != log_directory:\n                        os.unlink(latest_log_directory_path)\n                        os.symlink(rel_link_target, latest_log_directory_path)\n                elif os.path.isdir(latest_log_directory_path) or os.path.isfile(latest_log_directory_path):\n                    self.log.warning(\n                        "%s already exists as a dir/file. Skip creating symlink.", latest_log_directory_path\n                    )\n                else:\n                    os.symlink(rel_link_target, latest_log_directory_path)\n            except OSError:\n                self.log.warning("OSError while attempting to symlink the latest log directory")\n\n    def _render_log_filename(self, dag_file: DagFileInfo) -> str:\n        """Return an absolute path of where to log for a given dagfile."""\n        if self._latest_log_symlink_date < datetime.today():\n            self._symlink_latest_log_directory()\n            self._latest_log_symlink_date = datetime.today()\n\n        bundle = next(b for b in self._dag_bundles if b.name == dag_file.bundle_name)\n        relative_path = Path(dag_file.rel_path)\n        return os.path.join(self._get_log_dir(), bundle.name, f"{relative_path}.log")\n\n    def _get_logger_for_dag_file(self, dag_file: DagFileInfo):\n        log_filename = self._render_log_filename(dag_file)\n        log_file = init_log_file(log_filename)\n        logger_filehandle = log_file.open("ab")\n        underlying_logger = structlog.BytesLogger(logger_filehandle)\n        processors = logging_processors(json_output=True)\n        return structlog.wrap_logger(\n            underlying_logger, processors=processors, logger_name="processor"\n        ).bind(), logger_filehandle\n\n    @functools.cached_property\n    def client(self) -> Client:\n        from airflow.sdk.api.client import Client\n\n        client = Client(base_url=None, token="", dry_run=True, transport=self._api_server.transport)\n        # Mypy is wrong -- the setter accepts a string on the property setter! `URLType = URL | str`\n        client.base_url = "http://in-process.invalid./"\n        return client\n\n    def _create_process(self, dag_file: DagFileInfo) -> DagFileProcessorProcess:\n        id = uuid7()\n\n        callback_to_execute_for_file = self._callback_to_execute.pop(dag_file, [])\n        logger, logger_filehandle = self._get_logger_for_dag_file(dag_file)\n\n        return DagFileProcessorProcess.start(\n            id=id,\n            path=dag_file.absolute_path,\n            bundle_path=cast("Path", dag_file.bundle_path),\n            bundle_name=dag_file.bundle_name,\n            callbacks=callback_to_execute_for_file,\n            selector=self.selector,\n            logger=logger,\n            logger_filehandle=logger_filehandle,\n            client=self.client,\n        )\n\n    def _start_new_processes(self):\n        """Start more processors if we have enough slots and files to process."""\n        while self._parallelism > len(self._processors) and self._file_queue:\n            file = self._file_queue.popleft()\n            # Stop creating duplicate processor i.e. processor with the same filepath\n            if file in self._processors:\n                continue\n\n            processor = self._create_process(file)\n            Stats.incr("dag_processing.processes", tags={"file_path": str(file.rel_path), "action": "start"})\n\n            self._processors[file] = processor\n            Stats.gauge("dag_processing.file_path_queue_size", len(self._file_queue))\n\n    def _add_new_files_to_queue(self, known_files: dict[str, set[DagFileInfo]]):\n        """\n        Add new files to the front of the queue.\n\n        A "new" file is a file that has not been processed yet and is not currently being processed.\n        """\n        new_files = []\n        for files in known_files.values():\n            for file in files:\n                # todo: store stats by bundle also?\n                if file not in self._file_stats and file not in self._processors:\n                    new_files.append(file)\n\n        if new_files:\n            self.log.info("Adding %d new files to the front of the queue", len(new_files))\n            self._add_files_to_queue(new_files, mode="front")\n\n    def _resort_file_queue(self):\n        if self._file_parsing_sort_mode == "modified_time" and self._file_queue:\n            # Separate files with pending callbacks from regular files\n            # Callbacks should stay at the front regardless of mtime\n            callback_files = []\n            regular_files = []\n            for file in self._file_queue:\n                if file in self._callback_to_execute:\n                    callback_files.append(file)\n                else:\n                    regular_files.append(file)\n\n            # Sort only the regular files by mtime\n            sorted_regular_files, _ = self._sort_by_mtime(regular_files)\n\n            # Put callback files at the front, then sorted regular files\n            self._file_queue = deque(callback_files + sorted_regular_files)\n\n    def _sort_by_mtime(self, files: Iterable[DagFileInfo]):\n        files_with_mtime: dict[DagFileInfo, float] = {}\n        changed_recently = set()\n        for file in files:\n            try:\n                modified_timestamp = os.path.getmtime(file.absolute_path)\n                modified_datetime = datetime.fromtimestamp(modified_timestamp, tz=timezone.utc)\n                files_with_mtime[file] = modified_timestamp\n                last_time = self._file_stats[file].last_finish_time\n                if not last_time:\n                    continue\n                if modified_datetime > last_time:\n                    changed_recently.add(file)\n            except FileNotFoundError:\n                self.log.warning("Skipping processing of missing file: %s", file)\n                self._file_stats.pop(file, None)\n                continue\n        file_infos = [info for info, ts in sorted(files_with_mtime.items(), key=itemgetter(1), reverse=True)]\n        return file_infos, changed_recently\n\n    def processed_recently(self, now, file):\n        last_time = self._file_stats[file].last_finish_time\n        if not last_time:\n            return False\n        elapsed_ss = (now - last_time).total_seconds()\n        if elapsed_ss < self._file_process_interval:\n            return True\n        return False\n\n    def prepare_file_queue(self, known_files: dict[str, set[DagFileInfo]]):\n        """\n        Scan dags dir to generate more file paths to process.\n\n        Note this method is only called when the file path queue is empty\n        """\n        # We only emit metrics after processing all files in the queue. If `self._parsing_start_time` is None\n        # when this method is called, no files have yet been added to the queue so we shouldn\'t emit metrics.\n        if self._parsing_start_time is not None:\n            emit_metrics(\n                parse_time=time.perf_counter() - self._parsing_start_time,\n                stats=list(self._file_stats.values()),\n            )\n            self._parsing_start_time = None\n\n        # If the file path is already being processed, or if a file was\n        # processed recently, wait until the next batch\n        in_progress = set(self._processors)\n        now = timezone.utcnow()\n\n        # Sort the file paths by the parsing order mode\n        recently_processed = set()\n        files = []\n\n        for bundle_files in known_files.values():\n            for file in bundle_files:\n                files.append(file)\n                if self.processed_recently(now, file):\n                    recently_processed.add(file)\n\n        changed_recently: set[DagFileInfo] = set()\n        if self._file_parsing_sort_mode == "modified_time":\n            files, changed_recently = self._sort_by_mtime(files=files)\n        elif self._file_parsing_sort_mode == "alphabetical":\n            files.sort(key=attrgetter("rel_path"))\n        elif self._file_parsing_sort_mode == "random_seeded_by_host":\n            # Shuffle the list seeded by hostname so multiple DAG processors can work on different\n            # set of files. Since we set the seed, the sort order will remain same per host\n            random.Random(get_hostname()).shuffle(files)\n\n        at_run_limit = [info for info, stat in self._file_stats.items() if stat.run_count == self.max_runs]\n        to_exclude = in_progress.union(at_run_limit)\n\n        # exclude recently processed unless changed recently\n        to_exclude |= recently_processed - changed_recently\n\n        # Do not convert the following list to set as set does not preserve the order\n        # and we need to maintain the order of files for `[dag_processor] file_parsing_sort_mode`\n        to_queue = [x for x in files if x not in to_exclude]\n\n        if self.log.isEnabledFor(logging.DEBUG):\n            for path, processor in self._processors.items():\n                self.log.debug(\n                    "File path %s is still being processed (started: %s)", path, processor.start_time\n                )\n\n            self.log.debug(\n                "Queuing the following files for processing:\\n\\t%s",\n                "\\n\\t".join(str(f.rel_path) for f in to_queue),\n            )\n        self._add_files_to_queue(to_queue, mode="back")\n        Stats.incr("dag_processing.file_path_queue_update_count")\n\n    def _kill_timed_out_processors(self):\n        """Kill any file processors that timeout to defend against process hangs."""\n        now = time.monotonic()\n        processors_to_remove = []\n        for file, processor in self._processors.items():\n            duration = now - processor.start_time\n            if duration > self.processor_timeout:\n                self.log.error(\n                    "Processor for %s with PID %s has been running for %.2f seconds, exceeding the timeout of %.2f seconds. Killing it!",\n                    file,\n                    processor.pid,\n                    duration,\n                    self.processor_timeout,\n                )\n                file_name = str(file.rel_path)\n                Stats.decr("dag_processing.processes", tags={"file_path": file_name, "action": "timeout"})\n                Stats.incr("dag_processing.processor_timeouts", tags={"file_path": file_name})\n                processor.kill(signal.SIGKILL)\n\n                processors_to_remove.append(file)\n\n                stat = DagFileStat(\n                    num_dags=0,\n                    import_errors=1,\n                    last_finish_time=timezone.utcnow(),\n                    last_duration=duration,\n                    run_count=self._file_stats[file].run_count + 1,\n                    last_num_of_db_queries=0,\n                )\n                self._file_stats[file] = stat\n\n        # Clean up `self._processors` after iterating over it\n        for proc in processors_to_remove:\n            processor = self._processors.pop(proc)\n            processor.logger_filehandle.close()\n\n    def _add_files_to_queue(\n        self,\n        files: list[DagFileInfo],\n        *,\n        mode: Literal["front", "back", "frontprio"],\n    ):\n        """Add stuff to the back or front of the file queue, unless it\'s already present."""\n        if mode == "frontprio":\n            for file in files:\n                # Try removing the file if already present\n                with contextlib.suppress(ValueError):\n                    self._file_queue.remove(file)\n                # enqueue file to the start of the queue.\n                self._file_queue.appendleft(file)\n        elif mode == "front":\n            new_files = list(f for f in files if f not in self._file_queue)\n            self._file_queue.extendleft(new_files)\n        elif mode == "back":\n            new_files = list(f for f in files if f not in self._file_queue)\n            self._file_queue.extend(new_files)\n        else:\n            assert_never(mode)\n\n        # If we\'ve just added files to the queue for the first time since metrics were last emitted, reset the\n        # parse time counter.\n        if self._parsing_start_time is None and self._file_queue:\n            self._parsing_start_time = time.perf_counter()\n\n        Stats.gauge("dag_processing.file_path_queue_size", len(self._file_queue))\n\n    def max_runs_reached(self):\n        """:return: whether all file paths have been processed max_runs times."""\n        if self.max_runs == -1:  # Unlimited runs.\n            return False\n        if self._num_run < self.max_runs:\n            return False\n        return all(stat.run_count >= self.max_runs for stat in self._file_stats.values())\n\n    def terminate(self):\n        """Stop all running processors."""\n        for file, processor in self._processors.items():\n            # todo: AIP-66 what to do about file_path tag? replace with bundle name and rel path?\n            Stats.decr(\n                "dag_processing.processes", tags={"file_path": str(file.rel_path), "action": "terminate"}\n            )\n            # SIGTERM, wait 5s, SIGKILL if still alive\n            processor.kill(signal.SIGTERM, escalation_delay=5.0)\n\n    def end(self):\n        """Kill all child processes on exit since we don\'t want to leave them as orphaned."""\n        pids_to_kill = [p.pid for p in self._processors.values()]\n        if pids_to_kill:\n            kill_child_processes_by_pids(pids_to_kill)\n\n\ndef emit_metrics(*, parse_time: float, stats: Sequence[DagFileStat]):\n    """\n    Emit metrics about dag parsing summary.\n\n    This is called once every time around the parsing "loop" - i.e. after\n    all files have been parsed.\n    """\n    Stats.gauge("dag_processing.total_parse_time", parse_time)\n    Stats.gauge("dagbag_size", sum(stat.num_dags for stat in stats))\n    Stats.gauge("dag_processing.import_errors", sum(stat.import_errors for stat in stats))\n\n\ndef process_parse_results(\n    run_duration: float,\n    finish_time: datetime,\n    run_count: int,\n    bundle_name: str,\n    bundle_version: str | None,\n    parsing_result: DagFileParsingResult | None,\n    session: Session,\n    *,\n    is_callback_only: bool = False,\n    relative_fileloc: str | None = None,\n) -> DagFileStat:\n    """Take the parsing result and stats about the parser process and convert it into a DagFileStat."""\n    if is_callback_only:\n        # Callback-only processing - don\'t update timestamps to avoid stale DAG detection issues\n        stat = DagFileStat(\n            last_duration=run_duration,\n            run_count=run_count,  # Don\'t increment for callback-only processing\n        )\n        Stats.incr("dag_processing.callback_only_count")\n    else:\n        # Actual DAG parsing or import error\n        stat = DagFileStat(\n            last_finish_time=finish_time,\n            last_duration=run_duration,\n            run_count=run_count + 1,\n        )\n\n    # Note: relative_fileloc has a None default. In practice it is always provided but code defensively here in case\n    if relative_fileloc is not None and stat.last_duration is not None:\n        # Normalize names to ensure they only contain valid characters for stats (alphanumeric, underscore, dot, dash)\n        file_name = normalize_name_for_stats(Path(relative_fileloc).stem)\n        # bundle_name is included to distinguish files with the same name across different bundles\n        normalized_bundle = normalize_name_for_stats(bundle_name)\n        Stats.timing(f"dag_processing.last_duration.{normalized_bundle}.{file_name}", stat.last_duration)\n        Stats.timing(\n            "dag_processing.last_duration",\n            stat.last_duration,\n            tags={"file_name": file_name, "bundle_name": normalized_bundle},\n        )\n\n    if parsing_result is None:\n        # No DAGs were parsed - this happens for callback-only processing\n        # Don\'t treat this as an import error when it\'s callback-only\n        if not is_callback_only:\n            stat.import_errors = 1\n    else:\n        # record DAGs and import errors to database\n        import_errors = {}\n        if parsing_result.import_errors:\n            import_errors = {\n                (bundle_name, rel_path): error for rel_path, error in parsing_result.import_errors.items()\n            }\n\n        # Build the set of files that were parsed. This includes the file that was parsed,\n        # even if it no longer contains DAGs, so we can clear old import errors.\n        files_parsed: set[tuple[str, str]] | None = None\n        if relative_fileloc is not None:\n            files_parsed = {(bundle_name, relative_fileloc)}\n            files_parsed.update(import_errors.keys())\n\n        if (warnings := parsing_result.warnings) and isinstance(warnings[0], dict):\n            warnings = [DagWarning(**warn) for warn in warnings]\n\n        update_dag_parsing_results_in_db(\n            bundle_name=bundle_name,\n            bundle_version=bundle_version,\n            dags=parsing_result.serialized_dags,\n            import_errors=import_errors,\n            parse_duration=run_duration,\n            warnings=set(warnings or []),\n            session=session,\n            files_parsed=files_parsed,\n        )\n        stat.num_dags = len(parsing_result.serialized_dags)\n        if parsing_result.import_errors:\n            stat.import_errors = len(parsing_result.import_errors)\n    return stat\n',
            'airflow-core/src/airflow/models/dag.py': '#\n# Licensed to the Apache Software Foundation (ASF) under one\n# or more contributor license agreements.  See the NOTICE file\n# distributed with this work for additional information\n# regarding copyright ownership.  The ASF licenses this file\n# to you under the Apache License, Version 2.0 (the\n# "License"); you may not use this file except in compliance\n# with the License.  You may obtain a copy of the License at\n#\n#   http://www.apache.org/licenses/LICENSE-2.0\n#\n# Unless required by applicable law or agreed to in writing,\n# software distributed under the License is distributed on an\n# "AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\n# KIND, either express or implied.  See the License for the\n# specific language governing permissions and limitations\n# under the License.\nfrom __future__ import annotations\n\nfrom collections import defaultdict\nfrom collections.abc import Callable, Collection\nfrom datetime import datetime, timedelta\nfrom typing import TYPE_CHECKING, Any, cast\n\nimport pendulum\nimport sqlalchemy as sa\nimport structlog\nfrom dateutil.relativedelta import relativedelta\nfrom sqlalchemy import (\n    Boolean,\n    Float,\n    ForeignKey,\n    Index,\n    Integer,\n    String,\n    Text,\n    and_,\n    case,\n    func,\n    or_,\n    select,\n)\nfrom sqlalchemy.ext.associationproxy import association_proxy\nfrom sqlalchemy.ext.hybrid import hybrid_property\nfrom sqlalchemy.orm import (\n    Mapped,\n    Session,\n    backref,\n    joinedload,\n    load_only,\n    mapped_column,\n    relationship,\n)\nfrom sqlalchemy.sql import expression\n\nfrom airflow import settings\nfrom airflow._shared.timezones import timezone\nfrom airflow.assets.evaluation import AssetEvaluator\nfrom airflow.configuration import conf as airflow_conf\nfrom airflow.exceptions import AirflowException\nfrom airflow.models.asset import AssetDagRunQueue, AssetModel\nfrom airflow.models.base import Base, StringID\nfrom airflow.models.dagbundle import DagBundleModel\nfrom airflow.models.dagrun import DagRun\nfrom airflow.models.team import Team\nfrom airflow.serialization.definitions.assets import SerializedAssetUniqueKey\nfrom airflow.serialization.encoders import DAT, encode_deadline_alert\nfrom airflow.serialization.enums import Encoding\nfrom airflow.timetables.base import DataInterval, Timetable\nfrom airflow.timetables.interval import CronDataIntervalTimetable, DeltaDataIntervalTimetable\nfrom airflow.timetables.simple import AssetTriggeredTimetable, NullTimetable, OnceTimetable\nfrom airflow.utils.session import NEW_SESSION, provide_session\nfrom airflow.utils.sqlalchemy import UtcDateTime, with_row_locks\nfrom airflow.utils.state import DagRunState\nfrom airflow.utils.types import DagRunType\n\nif TYPE_CHECKING:\n    from typing import TypeAlias\n\n    from dateutil.relativedelta import relativedelta\n\n    from airflow.sdk import Context\n    from airflow.serialization.definitions.assets import (\n        SerializedAsset,\n        SerializedAssetAlias,\n        SerializedAssetBase,\n    )\n    from airflow.serialization.definitions.dag import SerializedDAG\n    from airflow.serialization.serialized_objects import LazyDeserializedDAG\n\n    UKey: TypeAlias = SerializedAssetUniqueKey\n    DagStateChangeCallback = Callable[[Context], None]\n    ScheduleInterval = None | str | timedelta | relativedelta\n\n    ScheduleArg = (\n        ScheduleInterval\n        | Timetable\n        | "SerializedAssetBase"\n        | Collection["SerializedAsset" | "SerializedAssetAlias"]\n    )\n\nlog = structlog.getLogger(__name__)\n\nTAG_MAX_LEN = 100\n\n\ndef infer_automated_data_interval(timetable: Timetable, logical_date: datetime) -> DataInterval:\n    """\n    Infer a data interval for a run against this DAG.\n\n    This method is used to bridge runs created prior to AIP-39\n    implementation, which do not have an explicit data interval. Therefore,\n    this method only considers ``schedule_interval`` values valid prior to\n    Airflow 2.2.\n\n    DO NOT call this method if there is a known data interval.\n\n    :meta private:\n    """\n    timetable_type = type(timetable)\n    if issubclass(timetable_type, (NullTimetable, OnceTimetable, AssetTriggeredTimetable)):\n        return DataInterval.exact(timezone.coerce_datetime(logical_date))\n    start = timezone.coerce_datetime(logical_date)\n    if issubclass(timetable_type, CronDataIntervalTimetable):\n        end = cast("CronDataIntervalTimetable", timetable)._get_next(start)\n    elif issubclass(timetable_type, DeltaDataIntervalTimetable):\n        end = cast("DeltaDataIntervalTimetable", timetable)._get_next(start)\n    # Contributors: When the exception below is raised, you might want to\n    # add an \'elif\' block here to handle custom timetables. Stop! The bug\n    # you\'re looking for is instead at when the DAG run (represented by\n    # logical_date) was created. See GH-31969 for an example:\n    # * Wrong fix: GH-32074 (modifies this function).\n    # * Correct fix: GH-32118 (modifies the DAG run creation code).\n    else:\n        raise ValueError(f"Not a valid timetable: {timetable!r}")\n    return DataInterval(start, end)\n\n\ndef get_run_data_interval(timetable: Timetable, run: DagRun | None) -> DataInterval | None:\n    """\n    Get the data interval of this run.\n\n    For compatibility, this method infers the data interval from the DAG\'s\n    schedule if the run does not have an explicit one set, which is possible for\n    runs created prior to AIP-39.\n\n    This function is private to Airflow core and should not be depended on as a\n    part of the Python API.\n\n    :meta private:\n    """\n    if not run:\n        return run\n\n    if run.partition_key is not None:\n        return None\n\n    if (\n        data_interval := _get_model_data_interval(run, "data_interval_start", "data_interval_end")\n    ) is not None:\n        return data_interval\n\n    if (\n        data_interval := timetable.infer_manual_data_interval(run_after=pendulum.instance(run.run_after))\n    ) is not None:\n        return data_interval\n\n    # Compatibility: runs created before AIP-39 implementation don\'t have an\n    # explicit data interval. Try to infer from the logical date.\n    if TYPE_CHECKING:\n        assert run.logical_date is not None\n    return infer_automated_data_interval(timetable, run.logical_date)\n\n\ndef get_next_data_interval(timetable: Timetable, dag_model: DagModel) -> DataInterval | None:\n    """\n    Get the data interval of the next scheduled run.\n\n    For compatibility, this method infers the data interval from the DAG\'s\n    schedule if the run does not have an explicit one set, which is possible\n    for runs created prior to AIP-39.\n\n    This function is private to Airflow core and should not be depended on as a\n    part of the Python API.\n\n    :meta private:\n    """\n    if dag_model.next_dagrun is None:  # Next run not scheduled.\n        return None\n    data_interval = dag_model.next_dagrun_data_interval\n    if data_interval is not None:\n        return data_interval\n\n    # Compatibility: A run was scheduled without an explicit data interval.\n    # This means the run was scheduled before AIP-39 implementation. Try to\n    # infer from the logical date.\n    return infer_automated_data_interval(timetable, dag_model.next_dagrun)\n\n\nclass InconsistentDataInterval(AirflowException):\n    """\n    Exception raised when a model populates data interval fields incorrectly.\n\n    The data interval fields should either both be None (for runs scheduled\n    prior to AIP-39), or both be datetime (for runs scheduled after AIP-39 is\n    implemented). This is raised if exactly one of the fields is None.\n    """\n\n    _template = (\n        "Inconsistent {cls}: {start[0]}={start[1]!r}, {end[0]}={end[1]!r}, "\n        "they must be either both None or both datetime"\n    )\n\n    def __init__(self, instance: Any, start_field_name: str, end_field_name: str) -> None:\n        self._class_name = type(instance).__name__\n        self._start_field = (start_field_name, getattr(instance, start_field_name))\n        self._end_field = (end_field_name, getattr(instance, end_field_name))\n\n    def __str__(self) -> str:\n        return self._template.format(cls=self._class_name, start=self._start_field, end=self._end_field)\n\n\ndef _get_model_data_interval(\n    instance: Any,\n    start_field_name: str,\n    end_field_name: str,\n) -> DataInterval | None:\n    start = timezone.coerce_datetime(getattr(instance, start_field_name))\n    end = timezone.coerce_datetime(getattr(instance, end_field_name))\n    if start is None:\n        if end is not None:\n            raise InconsistentDataInterval(instance, start_field_name, end_field_name)\n        return None\n    if end is None:\n        raise InconsistentDataInterval(instance, start_field_name, end_field_name)\n    return DataInterval(start, end)\n\n\ndef get_last_dagrun(dag_id: str, session: Session, include_manually_triggered: bool = False) -> DagRun | None:\n    """\n    Return the last dag run for a dag, None if there was none.\n\n    Last dag run can be any type of run e.g. scheduled or backfilled.\n    Overridden DagRuns are ignored.\n    """\n    DR = DagRun\n    query = select(DR).where(DR.dag_id == dag_id, DR.logical_date.is_not(None))\n    if not include_manually_triggered:\n        query = query.where(DR.run_type != DagRunType.MANUAL)\n    query = query.order_by(DR.logical_date.desc())\n    return session.scalar(query.limit(1))\n\n\ndef get_asset_triggered_next_run_info(\n    dag_ids: list[str], *, session: Session\n) -> dict[str, dict[str, int | str]]:\n    """\n    Get next run info for a list of dag_ids.\n\n    Given a list of dag_ids, get string representing how close any that are asset triggered are\n    their next run, e.g. "1 of 2 assets updated".\n    """\n    from airflow.models.asset import AssetDagRunQueue as ADRQ, DagScheduleAssetReference\n\n    return {\n        x.dag_id: {\n            "uri": x.uri,\n            "ready": x.ready,\n            "total": x.total,\n        }\n        for x in session.execute(\n            select(\n                DagScheduleAssetReference.dag_id,\n                # This is a dirty hack to workaround group by requiring an aggregate,\n                # since grouping by asset is not what we want to do here...but it works\n                case((func.count() == 1, func.max(AssetModel.uri)), else_="").label("uri"),\n                func.count().label("total"),\n                func.sum(case((ADRQ.target_dag_id.is_not(None), 1), else_=0)).label("ready"),\n            )\n            .join(\n                ADRQ,\n                and_(\n                    ADRQ.asset_id == DagScheduleAssetReference.asset_id,\n                    ADRQ.target_dag_id == DagScheduleAssetReference.dag_id,\n                ),\n                isouter=True,\n            )\n            .join(AssetModel, AssetModel.id == DagScheduleAssetReference.asset_id)\n            .group_by(DagScheduleAssetReference.dag_id)\n            .where(DagScheduleAssetReference.dag_id.in_(dag_ids))\n        ).all()\n    }\n\n\nclass DagTag(Base):\n    """A tag name per dag, to allow quick filtering in the DAG view."""\n\n    __tablename__ = "dag_tag"\n    name: Mapped[str] = mapped_column(String(TAG_MAX_LEN), primary_key=True)\n    dag_id: Mapped[str] = mapped_column(\n        StringID(),\n        ForeignKey("dag.dag_id", name="dag_tag_dag_id_fkey", ondelete="CASCADE"),\n        primary_key=True,\n    )\n\n    __table_args__ = (Index("idx_dag_tag_dag_id", dag_id),)\n\n    def __repr__(self):\n        return self.name\n\n\nclass DagOwnerAttributes(Base):\n    """\n    Table defining different owner attributes.\n\n    For example, a link for an owner that will be passed as a hyperlink to the "DAGs" view.\n    """\n\n    __tablename__ = "dag_owner_attributes"\n    dag_id: Mapped[str] = mapped_column(\n        StringID(),\n        ForeignKey("dag.dag_id", name="dag.dag_id", ondelete="CASCADE"),\n        nullable=False,\n        primary_key=True,\n    )\n    owner: Mapped[str] = mapped_column(String(500), primary_key=True, nullable=False)\n    link: Mapped[str] = mapped_column(String(500), nullable=False)\n\n    def __repr__(self):\n        return f"<DagOwnerAttributes: dag_id={self.dag_id}, owner={self.owner}, link={self.link}>"\n\n    @classmethod\n    def get_all(cls, session: Session) -> dict[str, dict[str, str]]:\n        dag_links: dict = defaultdict(dict)\n        for obj in session.scalars(select(cls)):\n            dag_links[obj.dag_id].update({obj.owner: obj.link})\n        return dag_links\n\n\nclass DagModel(Base):\n    """Table containing DAG properties."""\n\n    __tablename__ = "dag"\n    """\n    These items are stored in the database for state related information.\n    """\n    dag_id: Mapped[str] = mapped_column(StringID(), primary_key=True)\n    # A DAG can be paused from the UI / DB\n    # Set this default value of is_paused based on a configuration value!\n    is_paused_at_creation = airflow_conf.getboolean("core", "dags_are_paused_at_creation")\n    is_paused: Mapped[bool] = mapped_column(Boolean, default=is_paused_at_creation)\n    # Whether that DAG was seen on the last DagBag load\n    is_stale: Mapped[bool] = mapped_column(Boolean, nullable=False, default=True)\n    exceeds_max_non_backfill: Mapped[bool] = mapped_column(\n        Boolean, nullable=False, default=False, server_default="0"\n    )\n    # Last time the scheduler started\n    last_parsed_time: Mapped[datetime | None] = mapped_column(UtcDateTime, nullable=True)\n    # How long it took to parse this file\n    last_parse_duration: Mapped[float | None] = mapped_column(Float, nullable=True)\n    # Time when the DAG last received a refresh signal\n    # (e.g. the DAG\'s "refresh" button was clicked in the web UI)\n    last_expired: Mapped[datetime | None] = mapped_column(UtcDateTime, nullable=True)\n    # The location of the file containing the DAG object\n    # Note: Do not depend on fileloc pointing to a file; in the case of a\n    # packaged DAG, it will point to the subpath of the DAG within the\n    # associated zip.\n    fileloc: Mapped[str | None] = mapped_column(String(2000), nullable=True)\n    relative_fileloc: Mapped[str | None] = mapped_column(String(2000), nullable=True)\n    bundle_name: Mapped[str] = mapped_column(StringID(), ForeignKey("dag_bundle.name"), nullable=False)\n    # The version of the bundle the last time the DAG was processed\n    bundle_version: Mapped[str | None] = mapped_column(String(200), nullable=True)\n    # String representing the owners\n    owners: Mapped[str | None] = mapped_column(String(2000), nullable=True)\n    # Display name of the dag\n    _dag_display_property_value: Mapped[str | None] = mapped_column(\n        "dag_display_name", String(2000), nullable=True\n    )\n    # Description of the dag\n    description: Mapped[str | None] = mapped_column(Text, nullable=True)\n    # Timetable Type\n    timetable_type: Mapped[str] = mapped_column(String(255), nullable=False, default="")\n    # Timetable summary\n    timetable_summary: Mapped[str | None] = mapped_column(Text, nullable=True)\n    # Timetable description\n    timetable_description: Mapped[str | None] = mapped_column(String(1000), nullable=True)\n    # Whether the timetable do partitioning.\n    timetable_partitioned: Mapped[bool] = mapped_column(Boolean, nullable=False, server_default="0")\n    # Asset expression based on asset triggers\n    asset_expression: Mapped[dict[str, Any] | None] = mapped_column(sa.JSON(), nullable=True)\n    # DAG deadline information\n    _deadline: Mapped[dict[str, Any] | None] = mapped_column("deadline", sa.JSON(), nullable=True)\n    # Tags for view filter\n    tags = relationship("DagTag", cascade="all, delete, delete-orphan", backref=backref("dag"))\n    # Dag owner links for DAGs view\n    dag_owner_links = relationship(\n        "DagOwnerAttributes", cascade="all, delete, delete-orphan", backref=backref("dag")\n    )\n\n    max_active_tasks: Mapped[int] = mapped_column(Integer, nullable=False)\n    max_active_runs: Mapped[int | None] = mapped_column(\n        Integer, nullable=True\n    )  # todo: should not be nullable if we have a default\n    max_consecutive_failed_dag_runs: Mapped[int] = mapped_column(Integer, nullable=False)\n\n    has_task_concurrency_limits: Mapped[bool] = mapped_column(Boolean, nullable=False)\n    has_import_errors: Mapped[bool | None] = mapped_column(Boolean(), default=False, server_default="0")\n    fail_fast: Mapped[bool] = mapped_column(Boolean, nullable=False, default=False, server_default="0")\n    allowed_run_types: Mapped[list[str] | None] = mapped_column(sa.JSON(), nullable=True)\n\n    # The logical date of the next dag run.\n    next_dagrun: Mapped[datetime | None] = mapped_column(UtcDateTime, nullable=True)\n\n    # Must be either both NULL or both datetime.\n    next_dagrun_data_interval_start: Mapped[datetime | None] = mapped_column(UtcDateTime, nullable=True)\n    next_dagrun_data_interval_end: Mapped[datetime | None] = mapped_column(UtcDateTime, nullable=True)\n\n    next_dagrun_partition_key: Mapped[str | None] = mapped_column(String(255))\n    next_dagrun_partition_date: Mapped[datetime | None] = mapped_column(UtcDateTime, nullable=True)\n\n    # Earliest time at which this ``next_dagrun`` can be created.\n    next_dagrun_create_after: Mapped[datetime | None] = mapped_column(UtcDateTime, nullable=True)\n\n    __table_args__ = (Index("idx_next_dagrun_create_after", next_dagrun_create_after, unique=False),)\n\n    schedule_asset_references = relationship(\n        "DagScheduleAssetReference",\n        back_populates="dag",\n        cascade="all, delete, delete-orphan",\n    )\n    schedule_asset_alias_references = relationship(\n        "DagScheduleAssetAliasReference",\n        back_populates="dag",\n        cascade="all, delete, delete-orphan",\n    )\n    schedule_asset_name_references = relationship(\n        "DagScheduleAssetNameReference",\n        back_populates="dag",\n        cascade="all, delete, delete-orphan",\n    )\n    schedule_asset_uri_references = relationship(\n        "DagScheduleAssetUriReference",\n        back_populates="dag",\n        cascade="all, delete, delete-orphan",\n    )\n    schedule_assets = association_proxy("schedule_asset_references", "asset")\n    task_inlet_asset_references = relationship(\n        "TaskInletAssetReference",\n        cascade="all, delete, delete-orphan",\n    )\n    task_outlet_asset_references = relationship(\n        "TaskOutletAssetReference",\n        cascade="all, delete, delete-orphan",\n    )\n    NUM_DAGS_PER_DAGRUN_QUERY = airflow_conf.getint(\n        "scheduler", "max_dagruns_to_create_per_loop", fallback=10\n    )\n    dag_versions = relationship(\n        "DagVersion", back_populates="dag_model", cascade="all, delete, delete-orphan"\n    )\n\n    def __init__(self, **kwargs):\n        super().__init__(**kwargs)\n        if self.max_active_tasks is None:\n            self.max_active_tasks = airflow_conf.getint("core", "max_active_tasks_per_dag")\n\n        if self.max_active_runs is None:\n            self.max_active_runs = airflow_conf.getint("core", "max_active_runs_per_dag")\n\n        if self.max_consecutive_failed_dag_runs is None:\n            self.max_consecutive_failed_dag_runs = airflow_conf.getint(\n                "core", "max_consecutive_failed_dag_runs_per_dag"\n            )\n\n        if self.has_task_concurrency_limits is None:\n            # Be safe -- this will be updated later once the DAG is parsed\n            self.has_task_concurrency_limits = True\n\n    def __repr__(self):\n        return f"<DAG: {self.dag_id}>"\n\n    @property\n    def next_dagrun_data_interval(self) -> DataInterval | None:\n        return _get_model_data_interval(\n            self,\n            "next_dagrun_data_interval_start",\n            "next_dagrun_data_interval_end",\n        )\n\n    @next_dagrun_data_interval.setter\n    def next_dagrun_data_interval(self, value: tuple[datetime, datetime] | None) -> None:\n        if value is None:\n            self.next_dagrun_data_interval_start = self.next_dagrun_data_interval_end = None\n        else:\n            self.next_dagrun_data_interval_start, self.next_dagrun_data_interval_end = value\n\n    @property\n    def deadline(self):\n        """Get deadline alert UUID references."""\n        return self._deadline\n\n    @deadline.setter\n    def deadline(self, value):\n        """Set and serialize the deadline alert."""\n        if value is None:\n            self._deadline = None\n        elif isinstance(value, list):\n            self._deadline = [\n                item\n                if isinstance(item, dict)\n                else {Encoding.TYPE: DAT.DEADLINE_ALERT, Encoding.VAR: encode_deadline_alert(item)}\n                for item in value\n            ]\n        elif isinstance(value, dict):\n            self._deadline = value\n        else:\n            self._deadline = {Encoding.TYPE: DAT.DEADLINE_ALERT, Encoding.VAR: encode_deadline_alert(value)}\n\n    @property\n    def timezone(self):\n        return settings.TIMEZONE\n\n    @staticmethod\n    @provide_session\n    def get_dagmodel(dag_id: str, session: Session = NEW_SESSION) -> DagModel | None:\n        return session.get(\n            DagModel,\n            dag_id,\n        )\n\n    @classmethod\n    @provide_session\n    def get_current(cls, dag_id: str, session: Session = NEW_SESSION) -> DagModel | None:\n        return session.scalar(select(cls).where(cls.dag_id == dag_id))\n\n    @provide_session\n    def get_last_dagrun(\n        self, session: Session = NEW_SESSION, include_manually_triggered: bool = False\n    ) -> DagRun | None:\n        return get_last_dagrun(\n            self.dag_id, session=session, include_manually_triggered=include_manually_triggered\n        )\n\n    def get_is_active(self, *, session: Session | None = None) -> bool:\n        """Provide interface compatibility to \'DAG\'."""\n        return not self.is_stale\n\n    @staticmethod\n    @provide_session\n    def get_paused_dag_ids(dag_ids: list[str], session: Session = NEW_SESSION) -> set[str]:\n        """\n        Given a list of dag_ids, get a set of Paused Dag Ids.\n\n        :param dag_ids: List of Dag ids\n        :param session: ORM Session\n        :return: Paused Dag_ids\n        """\n        paused_dag_ids = session.scalars(\n            select(DagModel.dag_id)\n            .where(DagModel.is_paused == expression.true())\n            .where(DagModel.dag_id.in_(dag_ids))\n        )\n\n        return set(paused_dag_ids)\n\n    @property\n    def safe_dag_id(self):\n        return self.dag_id.replace(".", "__dot__")\n\n    @hybrid_property\n    def dag_display_name(self) -> str:\n        return self._dag_display_property_value or self.dag_id\n\n    @dag_display_name.expression  # type: ignore[no-redef]\n    def dag_display_name(self) -> str:\n        """\n        Expression part of the ``dag_display`` name hybrid property.\n\n        :meta private:\n        """\n        return case(\n            (self._dag_display_property_value.is_not(None), self._dag_display_property_value),\n            else_=self.dag_id,\n        )\n\n    @classmethod\n    @provide_session\n    def deactivate_deleted_dags(\n        cls,\n        bundle_name: str,\n        rel_filelocs: list[str],\n        session: Session = NEW_SESSION,\n    ) -> bool:\n        """\n        Set ``is_active=False`` on the DAGs for which the DAG files have been removed.\n\n        :param bundle_name: bundle for filelocs\n        :param rel_filelocs: relative filelocs for bundle\n        :param session: ORM Session\n        :return: True if any DAGs were marked as stale, False otherwise\n        """\n        log.debug("Deactivating DAGs (for which DAG files are deleted) from %s table ", cls.__tablename__)\n        dag_models = session.scalars(\n            select(cls)\n            .where(\n                cls.bundle_name == bundle_name,\n            )\n            .options(\n                load_only(\n                    cls.relative_fileloc,\n                    cls.is_stale,\n                ),\n            )\n        )\n\n        any_deactivated = False\n        for dm in dag_models:\n            if dm.relative_fileloc not in rel_filelocs:\n                dm.is_stale = True\n                any_deactivated = True\n\n        return any_deactivated\n\n    @classmethod\n    def dags_needing_dagruns(cls, session: Session) -> tuple[Any, dict[str, datetime]]:\n        """\n        Return (and lock) a list of Dag objects that are due to create a new DagRun.\n\n        This will return a resultset of rows that is row-level-locked with a "SELECT ... FOR UPDATE" query,\n        you should ensure that any scheduling decisions are made in a single transaction -- as soon as the\n        transaction is committed it will be unlocked.\n\n        :meta private:\n        """\n        from airflow.models.serialized_dag import SerializedDagModel\n\n        evaluator = AssetEvaluator(session)\n\n        def dag_ready(dag_id: str, cond: SerializedAssetBase, statuses: dict[UKey, bool]) -> bool:\n            try:\n                return evaluator.run(cond, statuses)\n            except AttributeError:\n                # if dag was serialized before 2.9 and we *just* upgraded,\n                # we may be dealing with old version.  In that case,\n                # just wait for the dag to be reserialized.\n                log.warning("Dag \'%s\' has old serialization; skipping run creation.", dag_id)\n                return False\n            except Exception:\n                log.exception("Dag \'%s\' failed to be evaluated; assuming not ready", dag_id)\n                return False\n\n        # this loads all the ADRQ records.... may need to limit num dags\n        adrq_by_dag: dict[str, list[AssetDagRunQueue]] = defaultdict(list)\n        for adrq in session.scalars(\n            select(AssetDagRunQueue).options(\n                joinedload(AssetDagRunQueue.dag_model),\n                joinedload(AssetDagRunQueue.asset),\n            )\n        ):\n            if adrq.dag_model.asset_expression is None:\n                # The dag referenced does not actually depend on an asset! This\n                # could happen if the dag DID depend on an asset at some point,\n                # but no longer does. Delete the stale adrq.\n                session.delete(adrq)\n            else:\n                adrq_by_dag[adrq.target_dag_id].append(adrq)\n\n        if adrq_by_dag:\n            log.info(\n                "Asset-triggered Dags with queued events: %s",\n                {dag_id: len(adrqs) for dag_id, adrqs in adrq_by_dag.items()},\n            )\n\n        dag_statuses: dict[str, dict[UKey, bool]] = {\n            dag_id: {SerializedAssetUniqueKey.from_asset(adrq.asset): True for adrq in adrqs}\n            for dag_id, adrqs in adrq_by_dag.items()\n        }\n        ser_dags = SerializedDagModel.get_latest_serialized_dags(dag_ids=list(dag_statuses), session=session)\n        for ser_dag in ser_dags:\n            dag_id = ser_dag.dag_id\n            statuses = dag_statuses[dag_id]\n            ready = dag_ready(dag_id, cond=ser_dag.dag.timetable.asset_condition, statuses=statuses)\n            if not ready:\n                log.debug("Asset condition not met for dag \'%s\'", dag_id)\n                del adrq_by_dag[dag_id]\n                del dag_statuses[dag_id]\n        del dag_statuses\n\n        # triggered dates for asset triggered dags\n        triggered_date_by_dag: dict[str, datetime] = {\n            dag_id: max(adrq.created_at for adrq in adrqs) for dag_id, adrqs in adrq_by_dag.items()\n        }\n        del adrq_by_dag\n\n        asset_triggered_dag_ids = set(triggered_date_by_dag.keys())\n        if asset_triggered_dag_ids:\n            # exclude as max active runs has been reached\n            exclusion_list = set(\n                session.scalars(\n                    select(DagModel.dag_id)\n                    .join(DagRun.dag_model)\n                    .where(DagRun.state.in_((DagRunState.QUEUED, DagRunState.RUNNING)))\n                    .where(DagModel.dag_id.in_(asset_triggered_dag_ids))\n                    .group_by(DagModel.dag_id)\n                    .having(func.count() >= func.max(DagModel.max_active_runs))\n                )\n            )\n            if exclusion_list:\n                log.info(\n                    "Asset-triggered Dags at max_active_runs, deferring: %s",\n                    exclusion_list,\n                )\n                asset_triggered_dag_ids -= exclusion_list\n                triggered_date_by_dag = {\n                    k: v for k, v in triggered_date_by_dag.items() if k not in exclusion_list\n                }\n\n        # We limit so that _one_ scheduler doesn\'t try to do all the creation of dag runs\n        query = (\n            select(cls)\n            .where(\n                cls.is_paused == expression.false(),\n                cls.is_stale == expression.false(),\n                cls.has_import_errors == expression.false(),\n                cls.exceeds_max_non_backfill == expression.false(),\n                or_(\n                    cls.next_dagrun_create_after <= func.now(),\n                    cls.dag_id.in_(asset_triggered_dag_ids),\n                ),\n            )\n            .order_by(cls.next_dagrun_create_after)\n            .limit(cls.NUM_DAGS_PER_DAGRUN_QUERY)\n        )\n\n        return (\n            session.scalars(with_row_locks(query, of=cls, session=session, skip_locked=True)),\n            triggered_date_by_dag,\n        )\n\n    def calculate_dagrun_date_fields(\n        self,\n        dag: SerializedDAG | LazyDeserializedDAG,\n        *,\n        last_automated_run: DagRun | None,\n    ) -> None:\n        """\n        Calculate ``next_dagrun`` and `next_dagrun_create_after``.\n\n        :param dag: The DAG object\n        :param last_automated_run: DagRun of most recent run of this dag, or none\n            if not yet scheduled.\n            TODO: AIP-76 This is not always latest run! See https://github.com/apache/airflow/issues/59618.\n        """\n        # TODO: AIP-76 perhaps we need to add validation for manual runs ensure consistency between\n        #   partition_key / partition_date and run_after\n\n        if isinstance(last_automated_run, datetime):\n            raise ValueError(\n                "Passing a datetime to `DagModel.calculate_dagrun_date_fields` is not supported. "\n                "Provide a data interval instead."\n            )\n\n        last_run_info = None\n        if last_automated_run:\n            last_run_info = dag.timetable.run_info_from_dag_run(dag_run=last_automated_run)\n        next_dagrun_info = dag.next_dagrun_info(last_automated_run_info=last_run_info)\n        if next_dagrun_info is None:\n            # there is no next dag run after the last dag run; set everything to None\n            self.next_dagrun_data_interval = self.next_dagrun = self.next_dagrun_create_after = None\n            self.next_dagrun_partition_key = self.next_dagrun_partition_date = None\n        else:\n            self.next_dagrun = next_dagrun_info.logical_date\n            self.next_dagrun_data_interval = next_dagrun_info.data_interval\n            self.next_dagrun_partition_key = next_dagrun_info.partition_key\n            self.next_dagrun_partition_date = next_dagrun_info.partition_date\n            self.next_dagrun_create_after = next_dagrun_info.run_after\n        log.info(\n            "setting next dagrun info",\n            next_dagrun=str(self.next_dagrun),\n            next_dagrun_create_after=str(self.next_dagrun_create_after),\n            next_dagrun_data_interval_start=str(self.next_dagrun_data_interval_start),\n            next_dagrun_data_interval_end=str(self.next_dagrun_data_interval_end),\n            next_dagrun_partition_key=self.next_dagrun_partition_key,\n            next_dagrun_partition_date=str(self.next_dagrun_partition_date),\n        )\n\n    @provide_session\n    def get_asset_triggered_next_run_info(\n        self, *, session: Session = NEW_SESSION\n    ) -> dict[str, int | str] | None:\n        if self.asset_expression is None:\n            return None\n\n        # When an asset alias does not resolve into assets, get_asset_triggered_next_run_info returns\n        # an empty dict as there\'s no asset info to get. This method should thus return None.\n        return get_asset_triggered_next_run_info([self.dag_id], session=session).get(self.dag_id, None)\n\n    @staticmethod\n    @provide_session\n    def get_team_name(dag_id: str, session: Session = NEW_SESSION) -> str | None:\n        """Return the team name associated to a Dag or None if it is not owned by a specific team."""\n        stmt = (\n            select(Team.name)\n            .join(DagBundleModel.teams)\n            .join(DagModel, DagModel.bundle_name == DagBundleModel.name)\n            .where(DagModel.dag_id == dag_id)\n        )\n        return session.scalar(stmt)\n\n    @staticmethod\n    @provide_session\n    def get_dag_id_to_team_name_mapping(\n        dag_ids: list[str], session: Session = NEW_SESSION\n    ) -> dict[str, str | None]:\n        stmt = (\n            select(DagModel.dag_id, Team.name)\n            .join(DagBundleModel.teams)\n            .join(DagModel, DagModel.bundle_name == DagBundleModel.name)\n            .where(DagModel.dag_id.in_(dag_ids))\n        )\n        return {dag_id: team_name for dag_id, team_name in session.execute(stmt)}\n\n\nSTATICA_HACK = True\nglobals()["kcah_acitats"[::-1].upper()] = False\nif STATICA_HACK:  # pragma: no cover\n    from airflow.models.serialized_dag import SerializedDagModel\n\n    DagModel.serialized_dag = relationship(SerializedDagModel)\n    """:sphinx-autoapi-skip:"""\n\n\ndef __getattr__(name: str):\n    # Add DAG and dag for compatibility. We can\'t do this in\n    # airflow/models/__init__.py since this module contains other things.\n    if name not in ("DAG", "dag"):\n        raise AttributeError(f"module {__name__!r} has no attribute {name!r}")\n\n    import warnings\n\n    from airflow.utils.deprecation_tools import DeprecatedImportWarning\n\n    warnings.warn(\n        f"Import {name!r} directly from the airflow module is deprecated and "\n        f"will be removed in the future. Please import it from \'airflow.sdk\'.",\n        DeprecatedImportWarning,\n        stacklevel=2,\n    )\n\n    import airflow.sdk\n\n    return getattr(airflow.sdk, name)\n',
            'airflow-core/tests/unit/dag_processing/test_manager.py': '#\n# Licensed to the Apache Software Foundation (ASF) under one\n# or more contributor license agreements.  See the NOTICE file\n# distributed with this work for additional information\n# regarding copyright ownership.  The ASF licenses this file\n# to you under the Apache License, Version 2.0 (the\n# "License"); you may not use this file except in compliance\n# with the License.  You may obtain a copy of the License at\n#\n#   http://www.apache.org/licenses/LICENSE-2.0\n#\n# Unless required by applicable law or agreed to in writing,\n# software distributed under the License is distributed on an\n# "AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\n# KIND, either express or implied.  See the License for the\n# specific language governing permissions and limitations\n# under the License.\nfrom __future__ import annotations\n\nimport json\nimport logging\nimport os\nimport random\nimport re\nimport shutil\nimport signal\nimport textwrap\nimport time\nfrom collections import defaultdict, deque\nfrom datetime import datetime, timedelta\nfrom pathlib import Path\nfrom socket import socket, socketpair\nfrom unittest import mock\nfrom unittest.mock import MagicMock\n\nimport msgspec\nimport pytest\nimport time_machine\nfrom sqlalchemy import func, select\nfrom uuid6 import uuid7\n\nfrom airflow._shared.timezones import timezone\nfrom airflow.callbacks.callback_requests import DagCallbackRequest\nfrom airflow.dag_processing.bundles.manager import DagBundlesManager\nfrom airflow.dag_processing.dagbag import DagBag\nfrom airflow.dag_processing.manager import (\n    DagFileInfo,\n    DagFileProcessorManager,\n    DagFileStat,\n)\nfrom airflow.dag_processing.processor import DagFileProcessorProcess\nfrom airflow.models import DagModel, DbCallbackRequest\nfrom airflow.models.asset import TaskOutletAssetReference\nfrom airflow.models.dag_version import DagVersion\nfrom airflow.models.dagbundle import DagBundleModel\nfrom airflow.models.dagcode import DagCode\nfrom airflow.models.serialized_dag import SerializedDagModel\nfrom airflow.models.team import Team\nfrom airflow.utils.net import get_hostname\nfrom airflow.utils.session import create_session\n\nfrom tests_common.test_utils.compat import ParseImportError\nfrom tests_common.test_utils.config import conf_vars\nfrom tests_common.test_utils.dag import sync_dag_to_db\nfrom tests_common.test_utils.db import (\n    clear_db_assets,\n    clear_db_callbacks,\n    clear_db_dag_bundles,\n    clear_db_dags,\n    clear_db_import_errors,\n    clear_db_runs,\n    clear_db_serialized_dags,\n    clear_db_teams,\n)\nfrom unit.models import TEST_DAGS_FOLDER\n\npytestmark = pytest.mark.db_test\n\nlogger = logging.getLogger(__name__)\nTEST_DAG_FOLDER = Path(__file__).parents[1].resolve() / "dags"\nDEFAULT_DATE = timezone.datetime(2016, 1, 1)\n\n\ndef _get_file_infos(files: list[str | Path]) -> list[DagFileInfo]:\n    return [DagFileInfo(bundle_name="testing", bundle_path=TEST_DAGS_FOLDER, rel_path=Path(f)) for f in files]\n\n\ndef mock_get_mtime(file: Path):\n    f = str(file)\n    m = re.match(pattern=r".*ss=(.+?)\\.\\w+", string=f)\n    if not m:\n        raise ValueError(f"unexpected: {file}")\n    match = m.group(1)\n    if match == "<class \'FileNotFoundError\'>":\n        raise FileNotFoundError()\n    try:\n        return int(match)\n    except Exception:\n        raise ValueError(f"could not convert value {match} to int")\n\n\ndef encode_mtime_in_filename(val):\n    from pathlib import PurePath\n\n    out = []\n    for fname, mtime in val:\n        f = PurePath(PurePath(fname).name)\n        addition = f"ss={str(mtime)}"\n        out.append(f"{f.stem}-{addition}{f.suffix}")\n    return out\n\n\nclass TestDagFileProcessorManager:\n    @pytest.fixture(autouse=True)\n    def _disable_examples(self):\n        with conf_vars({("core", "load_examples"): "False"}):\n            yield\n\n    def setup_method(self):\n        clear_db_teams()\n        clear_db_assets()\n        clear_db_runs()\n        clear_db_serialized_dags()\n        clear_db_dags()\n        clear_db_callbacks()\n        clear_db_import_errors()\n        clear_db_dag_bundles()\n\n    def teardown_class(self):\n        clear_db_teams()\n        clear_db_assets()\n        clear_db_runs()\n        clear_db_serialized_dags()\n        clear_db_dags()\n        clear_db_callbacks()\n        clear_db_import_errors()\n        clear_db_dag_bundles()\n\n    def mock_processor(self, start_time: float | None = None) -> tuple[DagFileProcessorProcess, socket]:\n        proc = MagicMock()\n        logger_filehandle = MagicMock()\n        proc.create_time.return_value = time.time()\n        proc.wait.return_value = 0\n        read_end, write_end = socketpair()\n        ret = DagFileProcessorProcess(\n            process_log=MagicMock(),\n            id=uuid7(),\n            pid=1234,\n            process=proc,\n            stdin=write_end,\n            logger_filehandle=logger_filehandle,\n            client=MagicMock(),\n        )\n        if start_time:\n            ret.start_time = start_time\n        ret._open_sockets.clear()\n        return ret, read_end\n\n    @pytest.fixture\n    def clear_parse_import_errors(self):\n        clear_db_import_errors()\n\n    @pytest.mark.usefixtures("clear_parse_import_errors")\n    @conf_vars({("core", "load_examples"): "False"})\n    def test_remove_file_clears_import_error(self, tmp_path, configure_testing_dag_bundle):\n        path_to_parse = tmp_path / "temp_dag.py"\n\n        # Generate original import error\n        path_to_parse.write_text("an invalid airflow DAG")\n\n        with configure_testing_dag_bundle(path_to_parse):\n            manager = DagFileProcessorManager(\n                max_runs=1,\n                processor_timeout=365 * 86_400,\n            )\n\n            manager.run()\n\n            with create_session() as session:\n                import_errors = session.scalars(select(ParseImportError)).all()\n                assert len(import_errors) == 1\n\n                path_to_parse.unlink()\n\n            # Rerun the parser once the dag file has been removed\n            manager.run()\n\n            with create_session() as session:\n                import_errors = session.scalars(select(ParseImportError)).all()\n\n                assert len(import_errors) == 0\n                session.rollback()\n\n    @conf_vars({("core", "load_examples"): "False"})\n    def test_max_runs_when_no_files(self, tmp_path):\n        with conf_vars({("core", "dags_folder"): str(tmp_path)}):\n            manager = DagFileProcessorManager(max_runs=1)\n            manager.run()\n\n        # TODO: AIP-66 no asserts?\n\n    def test_start_new_processes_with_same_filepath(self, configure_testing_dag_bundle):\n        """\n        Test that when a processor already exist with a filepath, a new processor won\'t be created\n        with that filepath. The filepath will just be removed from the list.\n        """\n        with configure_testing_dag_bundle("/tmp"):\n            manager = DagFileProcessorManager(max_runs=1)\n            manager._dag_bundles = list(DagBundlesManager().get_all_dag_bundles())\n\n        file_1 = DagFileInfo(bundle_name="testing", rel_path=Path("file_1.py"), bundle_path=TEST_DAGS_FOLDER)\n        file_2 = DagFileInfo(bundle_name="testing", rel_path=Path("file_2.py"), bundle_path=TEST_DAGS_FOLDER)\n        file_3 = DagFileInfo(bundle_name="testing", rel_path=Path("file_3.py"), bundle_path=TEST_DAGS_FOLDER)\n        manager._file_queue = deque([file_1, file_2, file_3])\n\n        # Mock that only one processor exists. This processor runs with \'file_1\'\n        manager._processors[file_1] = MagicMock()\n        # Start New Processes\n        with mock.patch.object(DagFileProcessorManager, "_create_process"):\n            manager._start_new_processes()\n\n        # Because of the config: \'[dag_processor] parsing_processes = 2\'\n        # verify that only one extra process is created\n        # and since a processor with \'file_1\' already exists,\n        # even though it is first in \'_file_path_queue\'\n        # a new processor is created with \'file_2\' and not \'file_1\'.\n\n        assert file_1 in manager._processors.keys()\n        assert file_2 in manager._processors.keys()\n        assert deque([file_3]) == manager._file_queue\n\n    def test_handle_removed_files_when_processor_file_path_not_in_new_file_paths(self):\n        """Ensure processors and file stats are removed when the file path is not in the new file paths"""\n        manager = DagFileProcessorManager(max_runs=1)\n        bundle_name = "testing"\n        file = DagFileInfo(\n            bundle_name=bundle_name, rel_path=Path("missing_file.txt"), bundle_path=TEST_DAGS_FOLDER\n        )\n\n        manager._processors[file] = MagicMock()\n        manager._file_stats[file] = DagFileStat()\n\n        manager.handle_removed_files({bundle_name: set()})\n        assert manager._processors == {}\n        assert file not in manager._file_stats\n\n    def test_handle_removed_files_when_processor_file_path_is_present(self):\n        """handle_removed_files should not purge files that are still present."""\n        manager = DagFileProcessorManager(max_runs=1)\n        bundle_name = "testing"\n        file = DagFileInfo(bundle_name=bundle_name, rel_path=Path("abc.txt"), bundle_path=TEST_DAGS_FOLDER)\n        mock_processor = MagicMock()\n\n        manager._processors[file] = mock_processor\n\n        manager.handle_removed_files(known_files={bundle_name: {file}})\n        assert manager._processors == {file: mock_processor}\n\n    @conf_vars({("dag_processor", "file_parsing_sort_mode"): "alphabetical"})\n    def test_files_in_queue_sorted_alphabetically(self):\n        """Test dag files are sorted alphabetically"""\n        file_names = ["file_3.py", "file_2.py", "file_4.py", "file_1.py"]\n        dag_files = _get_file_infos(file_names)\n        ordered_dag_files = _get_file_infos(sorted(file_names))\n\n        manager = DagFileProcessorManager(max_runs=1)\n        known_files = {"some-bundle": set(dag_files)}\n        assert manager._file_queue == deque()\n        manager.prepare_file_queue(known_files=known_files)\n        assert manager._file_queue == deque(ordered_dag_files)\n\n    @conf_vars({("dag_processor", "file_parsing_sort_mode"): "random_seeded_by_host"})\n    def test_files_sorted_random_seeded_by_host(self):\n        """Test files are randomly sorted and seeded by host name"""\n        f_infos = _get_file_infos(["file_3.py", "file_2.py", "file_4.py", "file_1.py"])\n        known_files = {"anything": f_infos}\n        manager = DagFileProcessorManager(max_runs=1)\n\n        assert manager._file_queue == deque()\n        manager.prepare_file_queue(known_files=known_files)  # using list over test for reproducibility\n        random.Random(get_hostname()).shuffle(f_infos)\n        expected = deque(f_infos)\n        assert manager._file_queue == expected\n\n        # Verify running it again produces same order\n        manager._files = []\n        manager.prepare_file_queue(known_files=known_files)\n        assert manager._file_queue == expected\n\n    @conf_vars({("dag_processor", "file_parsing_sort_mode"): "modified_time"})\n    @mock.patch("airflow.utils.file.os.path.getmtime", new=mock_get_mtime)\n    def test_files_sorted_by_modified_time(self):\n        """Test files are sorted by modified time"""\n        paths_with_mtime = [\n            ("file_3.py", 3.0),\n            ("file_2.py", 2.0),\n            ("file_4.py", 5.0),\n            ("file_1.py", 4.0),\n        ]\n        filenames = encode_mtime_in_filename(paths_with_mtime)\n        dag_files = _get_file_infos(filenames)\n\n        manager = DagFileProcessorManager(max_runs=1)\n\n        assert manager._file_queue == deque()\n        manager.prepare_file_queue(known_files={"any": set(dag_files)})\n        ordered_files = _get_file_infos(\n            [\n                "file_4-ss=5.0.py",\n                "file_1-ss=4.0.py",\n                "file_3-ss=3.0.py",\n                "file_2-ss=2.0.py",\n            ]\n        )\n        assert manager._file_queue == deque(ordered_files)\n\n    @conf_vars({("dag_processor", "file_parsing_sort_mode"): "modified_time"})\n    @mock.patch("airflow.utils.file.os.path.getmtime", new=mock_get_mtime)\n    def test_queued_files_exclude_missing_file(self):\n        """Check that a file is not enqueued for processing if it has been deleted"""\n        file_and_mtime = [("file_3.py", 2.0), ("file_2.py", 3.0), ("file_4.py", FileNotFoundError)]\n        filenames = encode_mtime_in_filename(file_and_mtime)\n        file_infos = _get_file_infos(filenames)\n        manager = DagFileProcessorManager(max_runs=1)\n        manager.prepare_file_queue(known_files={"any": set(file_infos)})\n        ordered_files = _get_file_infos(["file_2-ss=3.0.py", "file_3-ss=2.0.py"])\n        assert manager._file_queue == deque(ordered_files)\n\n    @conf_vars({("dag_processor", "file_parsing_sort_mode"): "modified_time"})\n    @mock.patch("airflow.utils.file.os.path.getmtime", new=mock_get_mtime)\n    def test_add_new_file_to_parsing_queue(self):\n        """Check that new file is added to parsing queue"""\n        dag_files = _get_file_infos(["file_1-ss=2.0.py", "file_2-ss=3.0.py", "file_3-ss=4.0.py"])\n        from random import Random\n\n        Random("file_2.py").random()\n        manager = DagFileProcessorManager(max_runs=1)\n\n        manager.prepare_file_queue(known_files={"any": set(dag_files)})\n        assert set(manager._file_queue) == set(dag_files)\n\n        manager.prepare_file_queue(\n            known_files={"any": set((*dag_files, *_get_file_infos(["file_4-ss=1.0.py"])))}\n        )\n        # manager._add_new_files_to_queue()\n        ordered_files = _get_file_infos(\n            [\n                "file_3-ss=4.0.py",\n                "file_2-ss=3.0.py",\n                "file_1-ss=2.0.py",\n                "file_4-ss=1.0.py",\n            ]\n        )\n        assert manager._file_queue == deque(ordered_files)\n\n    def test_add_new_files_to_queue_behavior(self):\n        """\n        Check that _add_new_files_to_queue:\n        1. Adds new files to the front of the queue.\n        2. Skips files that are currently being processed.\n        3. Skips files that have already been processed (in _file_stats).\n        4. Does not re-add files already in the queue.\n        """\n        manager = DagFileProcessorManager(max_runs=1)\n        file_1 = DagFileInfo(bundle_name="testing", rel_path=Path("file_1.py"), bundle_path=TEST_DAGS_FOLDER)\n        file_2 = DagFileInfo(bundle_name="testing", rel_path=Path("file_2.py"), bundle_path=TEST_DAGS_FOLDER)\n        file_3 = DagFileInfo(bundle_name="testing", rel_path=Path("file_3.py"), bundle_path=TEST_DAGS_FOLDER)\n        file_4 = DagFileInfo(bundle_name="testing", rel_path=Path("file_4.py"), bundle_path=TEST_DAGS_FOLDER)\n\n        # Setup:\n        # file_1 is already in the queue\n        manager._file_queue = deque([file_1])\n\n        # file_3 is currently being processed\n        manager._processors[file_3] = MagicMock()\n\n        # file_4 has already been processed\n        manager._file_stats[file_4] = DagFileStat(num_dags=1)\n\n        # known_files contains all four\n        known_files = {"testing": {file_1, file_2, file_3, file_4}}\n\n        manager._add_new_files_to_queue(known_files)\n\n        # file_4 should be ignored (in file_stats)\n        # file_3 should be ignored (processing)\n        # file_2 should be at the front (new)\n        # file_1 should remain (already in queue)\n        assert list(manager._file_queue) == [file_2, file_1]\n\n    @conf_vars({("dag_processor", "file_parsing_sort_mode"): "modified_time"})\n    @mock.patch("airflow.utils.file.os.path.getmtime", new=mock_get_mtime)\n    def test_resort_file_queue_by_mtime(self):\n        """\n        Check that existing files in the queue are re-sorted by mtime when calling _resort_file_queue,\n        if sort mode is modified_time.\n        """\n        # Prepare some files with mtimes\n        files_with_mtime = [\n            ("file_1.py", 100.0),\n            ("file_2.py", 200.0),\n        ]\n        filenames = encode_mtime_in_filename(files_with_mtime)\n        dag_files = _get_file_infos(filenames)\n        # dag_files[0] -> file_1 (mtime 100)\n        # dag_files[1] -> file_2 (mtime 200)\n\n        manager = DagFileProcessorManager(max_runs=1)\n\n        # Populate queue with unsorted files\n        # Queue: [file_1 (100), file_2 (200)]\n        manager._file_queue = deque([dag_files[0], dag_files[1]])\n\n        manager._resort_file_queue()\n\n        # Verify resort happened: [file_2 (200), file_1 (100)]\n        assert list(manager._file_queue) == [dag_files[1], dag_files[0]]\n\n    @conf_vars({("dag_processor", "file_parsing_sort_mode"): "alphabetical"})\n    def test_resort_file_queue_does_nothing_when_alphabetical(self):\n        """\n        Check that _resort_file_queue does NOT change the order if sort mode is alphabetical.\n        """\n        file_a = DagFileInfo(bundle_name="testing", rel_path=Path("a.py"), bundle_path=TEST_DAGS_FOLDER)\n        file_b = DagFileInfo(bundle_name="testing", rel_path=Path("b.py"), bundle_path=TEST_DAGS_FOLDER)\n\n        manager = DagFileProcessorManager(max_runs=1)\n\n        # Populate queue in non-alphabetical order\n        manager._file_queue = deque([file_b, file_a])\n\n        manager._resort_file_queue()\n\n        # Order should remain unchanged\n        assert list(manager._file_queue) == [file_b, file_a]\n\n    @conf_vars({("dag_processor", "file_parsing_sort_mode"): "modified_time"})\n    @mock.patch("airflow.utils.file.os.path.getmtime", new=mock_get_mtime)\n    def test_resort_file_queue_keeps_callbacks_at_front(self):\n        """\n        Check that files with pending callbacks stay at the front of the queue\n        regardless of their modification time, and preserve their relative order.\n        """\n        files_with_mtime = [\n            ("callback_1.py", 50.0),  # has callback, oldest mtime\n            ("callback_2.py", 300.0),  # has callback, newest mtime\n            ("regular_1.py", 100.0),  # no callback\n            ("regular_2.py", 200.0),  # no callback\n        ]\n        filenames = encode_mtime_in_filename(files_with_mtime)\n        dag_files = _get_file_infos(filenames)\n        # dag_files[0] -> callback_1 (mtime 50)\n        # dag_files[1] -> callback_2 (mtime 300)\n        # dag_files[2] -> regular_1 (mtime 100)\n        # dag_files[3] -> regular_2 (mtime 200)\n\n        manager = DagFileProcessorManager(max_runs=1)\n\n        # Queue order: callback_1, callback_2, regular_1, regular_2\n        manager._file_queue = deque([dag_files[0], dag_files[1], dag_files[2], dag_files[3]])\n\n        # Both callback files have pending callbacks\n        manager._callback_to_execute[dag_files[0]] = [MagicMock()]\n        manager._callback_to_execute[dag_files[1]] = [MagicMock()]\n\n        manager._resort_file_queue()\n\n        # Callback files should stay at front in original order (callback_1, callback_2)\n        # despite callback_1 having the oldest mtime and callback_2 having the newest\n        # Regular files should be sorted by mtime (newest first): regular_2 (200), regular_1 (100)\n        assert list(manager._file_queue) == [dag_files[0], dag_files[1], dag_files[3], dag_files[2]]\n\n    @conf_vars({("dag_processor", "file_parsing_sort_mode"): "modified_time"})\n    @mock.patch("airflow.utils.file.os.path.getmtime")\n    def test_recently_modified_file_is_parsed_with_mtime_mode(self, mock_getmtime):\n        """\n        Test recently updated files are processed even if min_file_process_interval is not reached\n        """\n        freezed_base_time = timezone.datetime(2020, 1, 5, 0, 0, 0)\n        initial_file_1_mtime = (freezed_base_time - timedelta(minutes=5)).timestamp()\n        dag_file = DagFileInfo(\n            bundle_name="testing", rel_path=Path("file_1.py"), bundle_path=TEST_DAGS_FOLDER\n        )\n        known_files = {"does-not-matter": {dag_file}}\n        mock_getmtime.side_effect = [initial_file_1_mtime]\n\n        manager = DagFileProcessorManager(max_runs=3)\n\n        # let\'s say the DAG was just parsed 10 seconds before the Freezed time\n        last_finish_time = freezed_base_time - timedelta(seconds=10)\n        manager._file_stats = {\n            dag_file: DagFileStat(1, 0, last_finish_time, 1.0, 1, 1),\n        }\n        with time_machine.travel(freezed_base_time):\n            assert manager._file_queue == deque()\n            # File Path Queue will be empty as the "modified time" < "last finish time"\n            manager.prepare_file_queue(known_files=known_files)\n            assert manager._file_queue == deque()\n\n        # Simulate the DAG modification by using modified_time which is greater\n        # than the last_parse_time but still less than now - min_file_process_interval\n        file_1_new_mtime = freezed_base_time - timedelta(seconds=5)\n        file_1_new_mtime_ts = file_1_new_mtime.timestamp()\n        with time_machine.travel(freezed_base_time):\n            assert manager._file_queue == deque()\n            # File Path Queue will be empty as the "modified time" < "last finish time"\n            mock_getmtime.side_effect = [file_1_new_mtime_ts]\n            manager.prepare_file_queue(known_files=known_files)\n            # Check that file is added to the queue even though file was just recently passed\n            assert manager._file_queue == deque([dag_file])\n            assert last_finish_time < file_1_new_mtime\n            assert (\n                manager._file_process_interval\n                > (freezed_base_time - manager._file_stats[dag_file].last_finish_time).total_seconds()\n            )\n\n    def test_file_paths_in_queue_sorted_by_priority(self):\n        from airflow.models.dagbag import DagPriorityParsingRequest\n\n        parsing_request = DagPriorityParsingRequest(relative_fileloc="file_1.py", bundle_name="dags-folder")\n        with create_session() as session:\n            session.add(parsing_request)\n            session.commit()\n\n        file1 = DagFileInfo(\n            bundle_name="dags-folder", rel_path=Path("file_1.py"), bundle_path=TEST_DAGS_FOLDER\n        )\n        file2 = DagFileInfo(\n            bundle_name="dags-folder", rel_path=Path("file_2.py"), bundle_path=TEST_DAGS_FOLDER\n        )\n\n        manager = DagFileProcessorManager(max_runs=1)\n        manager._dag_bundles = list(DagBundlesManager().get_all_dag_bundles())\n        manager._file_queue = deque([file2, file1])\n        manager._queue_requested_files_for_parsing()\n        assert manager._file_queue == deque([file1, file2])\n        assert manager._force_refresh_bundles == {"dags-folder"}\n        with create_session() as session2:\n            parsing_request_after = session2.get(DagPriorityParsingRequest, parsing_request.id)\n        assert parsing_request_after is None\n\n    def test_parsing_requests_only_bundles_being_parsed(self, testing_dag_bundle):\n        """Ensure the manager only handles parsing requests for bundles being parsed in this manager"""\n        from airflow.models.dagbag import DagPriorityParsingRequest\n\n        with create_session() as session:\n            session.add(DagPriorityParsingRequest(relative_fileloc="file_1.py", bundle_name="dags-folder"))\n            session.add(DagPriorityParsingRequest(relative_fileloc="file_x.py", bundle_name="testing"))\n            session.commit()\n\n        file1 = DagFileInfo(\n            bundle_name="dags-folder", rel_path=Path("file_1.py"), bundle_path=TEST_DAGS_FOLDER\n        )\n\n        manager = DagFileProcessorManager(max_runs=1)\n        manager._dag_bundles = list(DagBundlesManager().get_all_dag_bundles())\n        manager._queue_requested_files_for_parsing()\n        assert manager._file_queue == deque([file1])\n        with create_session() as session2:\n            parsing_request_after = session2.scalars(select(DagPriorityParsingRequest)).all()\n        assert len(parsing_request_after) == 1\n        assert parsing_request_after[0].relative_fileloc == "file_x.py"\n\n    @pytest.mark.usefixtures("testing_dag_bundle")\n    def test_scan_stale_dags(self, session):\n        """\n        Ensure that DAGs are marked inactive when the file is parsed but the\n        DagModel.last_parsed_time is not updated.\n        """\n        manager = DagFileProcessorManager(\n            max_runs=1,\n            processor_timeout=10 * 60,\n        )\n        bundle = MagicMock()\n        bundle.name = "testing"\n        manager._dag_bundles = [bundle]\n\n        test_dag_path = DagFileInfo(\n            bundle_name="testing",\n            rel_path=Path("test_example_bash_operator.py"),\n            bundle_path=TEST_DAGS_FOLDER,\n        )\n        dagbag = DagBag(\n            test_dag_path.absolute_path,\n            include_examples=False,\n            bundle_path=test_dag_path.bundle_path,\n        )\n\n        # Add stale DAG to the DB\n        dag = dagbag.get_dag("test_example_bash_operator")\n        sync_dag_to_db(dag, session=session)\n\n        # Add DAG to the file_parsing_stats\n        stat = DagFileStat(\n            num_dags=1,\n            import_errors=0,\n            last_finish_time=timezone.utcnow() + timedelta(hours=1),\n            last_duration=1,\n            run_count=1,\n            last_num_of_db_queries=1,\n        )\n        manager._files = [test_dag_path]\n        manager._file_stats[test_dag_path] = stat\n\n        active_dag_count = session.scalar(\n            select(func.count(DagModel.dag_id)).where(\n                ~DagModel.is_stale,\n                DagModel.relative_fileloc == str(test_dag_path.rel_path),\n                DagModel.bundle_name == test_dag_path.bundle_name,\n            )\n        )\n        assert active_dag_count == 1\n\n        manager._scan_stale_dags()\n\n        active_dag_count = session.scalar(\n            select(func.count(DagModel.dag_id)).where(\n                ~DagModel.is_stale,\n                DagModel.relative_fileloc == str(test_dag_path.rel_path),\n                DagModel.bundle_name == test_dag_path.bundle_name,\n            )\n        )\n        assert active_dag_count == 0\n\n        serialized_dag_count = session.scalar(\n            select(func.count(SerializedDagModel.dag_id)).where(SerializedDagModel.dag_id == dag.dag_id)\n        )\n        # Deactivating the DagModel should not delete the SerializedDagModel\n        # SerializedDagModel gives history about Dags\n        assert serialized_dag_count == 1\n\n    @mock.patch("airflow.dag_processing.manager.BundleUsageTrackingManager")\n    def test_cleanup_stale_bundle_versions_interval(self, mock_bundle_manager):\n        manager = DagFileProcessorManager(max_runs=1)\n        manager.stale_bundle_cleanup_interval = 10\n\n        manager._last_stale_bundle_cleanup_time = time.monotonic() - 20\n        manager._cleanup_stale_bundle_versions()\n        mock_bundle_manager.return_value.remove_stale_bundle_versions.assert_called_once()\n\n        mock_bundle_manager.return_value.remove_stale_bundle_versions.reset_mock()\n        manager._last_stale_bundle_cleanup_time = time.monotonic()\n        manager._cleanup_stale_bundle_versions()\n        mock_bundle_manager.return_value.remove_stale_bundle_versions.assert_not_called()\n\n    @mock.patch("airflow.dag_processing.manager.BundleUsageTrackingManager")\n    def test_cleanup_stale_bundle_versions(self, mock_bundle_manager):\n        manager = DagFileProcessorManager(max_runs=1)\n        manager.cleanup_stale_bundle_versions()\n        mock_bundle_manager.return_value.remove_stale_bundle_versions.assert_called_once_with()\n\n    def test_kill_timed_out_processors_kill(self):\n        manager = DagFileProcessorManager(max_runs=1, processor_timeout=5)\n        # Set start_time to ensure timeout occurs: start_time = current_time - (timeout + 1) = always (timeout + 1) seconds\n        start_time = time.monotonic() - manager.processor_timeout - 1\n        processor, _ = self.mock_processor(start_time=start_time)\n        manager._processors = {\n            DagFileInfo(\n                bundle_name="testing", rel_path=Path("abc.txt"), bundle_path=TEST_DAGS_FOLDER\n            ): processor\n        }\n        with mock.patch.object(type(processor), "kill") as mock_kill:\n            manager._kill_timed_out_processors()\n        mock_kill.assert_called_once_with(signal.SIGKILL)\n        assert len(manager._processors) == 0\n        processor.logger_filehandle.close.assert_called()\n\n    def test_kill_timed_out_processors_no_kill(self):\n        manager = DagFileProcessorManager(\n            max_runs=1,\n            processor_timeout=5,\n        )\n\n        processor, _ = self.mock_processor()\n        processor._process.create_time.return_value = timezone.make_aware(datetime.max).timestamp()\n        manager._processors = {\n            DagFileInfo(\n                bundle_name="testing", rel_path=Path("abc.txt"), bundle_path=TEST_DAGS_FOLDER\n            ): processor\n        }\n        with mock.patch.object(type(processor), "kill") as mock_kill:\n            manager._kill_timed_out_processors()\n        mock_kill.assert_not_called()\n\n    @pytest.mark.usefixtures("testing_dag_bundle")\n    @pytest.mark.parametrize(\n        ("callbacks", "path", "expected_body"),\n        [\n            pytest.param(\n                [],\n                "/opt/airflow/dags/test_dag.py",\n                {\n                    "file": "/opt/airflow/dags/test_dag.py",\n                    "bundle_path": "/opt/airflow/dags",\n                    "bundle_name": "testing",\n                    "callback_requests": [],\n                    "type": "DagFileParseRequest",\n                },\n            ),\n            pytest.param(\n                [\n                    DagCallbackRequest(\n                        filepath="dag_callback_dag.py",\n                        dag_id="dag_id",\n                        run_id="run_id",\n                        bundle_name="testing",\n                        bundle_version=None,\n                        context_from_server=None,\n                        is_failure_callback=False,\n                    )\n                ],\n                "/opt/airflow/dags/dag_callback_dag.py",\n                {\n                    "file": "/opt/airflow/dags/dag_callback_dag.py",\n                    "bundle_path": "/opt/airflow/dags",\n                    "bundle_name": "testing",\n                    "callback_requests": [\n                        {\n                            "filepath": "dag_callback_dag.py",\n                            "bundle_name": "testing",\n                            "bundle_version": None,\n                            "msg": None,\n                            "dag_id": "dag_id",\n                            "run_id": "run_id",\n                            "context_from_server": None,\n                            "is_failure_callback": False,\n                            "type": "DagCallbackRequest",\n                        }\n                    ],\n                    "type": "DagFileParseRequest",\n                },\n            ),\n        ],\n    )\n    def test_serialize_callback_requests(self, callbacks, path, expected_body):\n        from airflow.sdk.execution_time.comms import _ResponseFrame\n\n        processor, read_socket = self.mock_processor()\n        processor._on_child_started(\n            callbacks, path, bundle_path=Path("/opt/airflow/dags"), bundle_name="testing"\n        )\n\n        read_socket.settimeout(0.1)\n        # Read response from the read end of the socket\n        frame_len = int.from_bytes(read_socket.recv(4), "big")\n        bytes = read_socket.recv(frame_len)\n        frame = msgspec.msgpack.Decoder(_ResponseFrame).decode(bytes)\n\n        assert frame.body == expected_body\n\n    @conf_vars({("core", "load_examples"): "False"})\n    @pytest.mark.execution_timeout(10)\n    def test_dag_with_system_exit(self, configure_testing_dag_bundle):\n        """\n        Test to check that a DAG with a system.exit() doesn\'t break the scheduler.\n        """\n        dag_id = "exit_test_dag"\n        dag_directory = TEST_DAG_FOLDER.parent / "dags_with_system_exit"\n\n        # Delete the one valid DAG/SerializedDAG, and check that it gets re-created\n        clear_db_dags()\n        clear_db_serialized_dags()\n\n        with configure_testing_dag_bundle(dag_directory):\n            manager = DagFileProcessorManager(max_runs=1)\n            manager.run()\n\n        # Three files in folder should be processed\n        assert sum(stat.run_count for stat in manager._file_stats.values()) == 3\n\n        with create_session() as session:\n            assert session.get(DagModel, dag_id) is not None\n\n    @conf_vars({("core", "load_examples"): "False"})\n    @mock.patch("airflow.dag_processing.manager.Stats.timing")\n    def test_send_file_processing_statsd_timing(\n        self, statsd_timing_mock, tmp_path, configure_testing_dag_bundle\n    ):\n        dag_filename = "temp_dag.py"\n        path_to_parse = tmp_path / dag_filename\n        dag_code = textwrap.dedent(\n            """\n            from airflow import DAG\n            dag = DAG(dag_id=\'temp_dag\')\n            """\n        )\n        path_to_parse.write_text(dag_code)\n\n        with configure_testing_dag_bundle(tmp_path):\n            manager = DagFileProcessorManager(max_runs=1)\n            manager.run()\n\n        bundle_name = "testing"\n        file_info = DagFileInfo(\n            bundle_name=bundle_name,\n            rel_path=Path(dag_filename),\n            bundle_path=tmp_path,\n        )\n        last_runtime = manager._file_stats[file_info].last_duration\n        statsd_timing_mock.assert_has_calls(\n            [\n                mock.call("dag_processing.last_duration.testing.temp_dag", last_runtime),\n                mock.call(\n                    "dag_processing.last_duration",\n                    last_runtime,\n                    tags={"file_name": dag_filename[:-3], "bundle_name": bundle_name},\n                ),\n            ],\n            any_order=True,\n        )\n\n    @pytest.mark.usefixtures("testing_dag_bundle")\n    def test_refresh_dags_dir_doesnt_delete_zipped_dags(\n        self, tmp_path, session, configure_testing_dag_bundle, test_zip_path\n    ):\n        """Test DagFileProcessorManager._refresh_dag_dir method"""\n        dagbag = DagBag(dag_folder=tmp_path, include_examples=False)\n        dagbag.process_file(test_zip_path)\n        dag = dagbag.get_dag("test_zip_dag")\n        sync_dag_to_db(dag)\n\n        with configure_testing_dag_bundle(test_zip_path):\n            manager = DagFileProcessorManager(max_runs=1)\n            manager.run()\n\n        # Assert dag not deleted in SDM\n        assert SerializedDagModel.has_dag("test_zip_dag")\n        # assert code not deleted\n        assert DagCode.has_dag(dag.dag_id)\n        # assert dag still active\n        assert session.get(DagModel, dag.dag_id).is_stale is False\n\n    @pytest.mark.usefixtures("testing_dag_bundle")\n    def test_refresh_dags_dir_deactivates_deleted_zipped_dags(\n        self, session, tmp_path, configure_testing_dag_bundle, test_zip_path\n    ):\n        """Test DagFileProcessorManager._refresh_dag_dir method"""\n        dag_id = "test_zip_dag"\n        filename = "test_zip.zip"\n        source_location = test_zip_path\n        bundle_path = Path(tmp_path, "test_refresh_dags_dir_deactivates_deleted_zipped_dags")\n        bundle_path.mkdir(exist_ok=True)\n        zip_dag_path = bundle_path / filename\n        shutil.copy(source_location, zip_dag_path)\n\n        with configure_testing_dag_bundle(bundle_path):\n            session.commit()\n            manager = DagFileProcessorManager(max_runs=1)\n            manager.run()\n\n            assert SerializedDagModel.has_dag(dag_id)\n            assert DagCode.has_dag(dag_id)\n            assert DagVersion.get_latest_version(dag_id)\n            dag = session.scalar(select(DagModel).where(DagModel.dag_id == dag_id))\n            assert dag.is_stale is False\n\n            os.remove(zip_dag_path)\n\n            manager.run()\n\n            assert SerializedDagModel.has_dag(dag_id)\n            assert DagCode.has_dag(dag_id)\n            assert DagVersion.get_latest_version(dag_id)\n            dag = session.scalar(select(DagModel).where(DagModel.dag_id == dag_id))\n            assert dag.is_stale is True\n\n    def test_deactivate_deleted_dags(self, dag_maker, session):\n        with dag_maker("test_dag1") as dag1:\n            dag1.relative_fileloc = "test_dag1.py"\n        with dag_maker("test_dag2") as dag2:\n            dag2.relative_fileloc = "test_dag2.py"\n        dag_maker.sync_dagbag_to_db()\n\n        active_files = [\n            DagFileInfo(\n                bundle_name="dag_maker",\n                rel_path=Path("test_dag1.py"),\n                bundle_path=TEST_DAGS_FOLDER,\n            ),\n            # Mimic that the test_dag2.py file is deleted\n        ]\n\n        manager = DagFileProcessorManager(max_runs=1)\n        manager.deactivate_deleted_dags("dag_maker", active_files)\n\n        # The DAG from test_dag1.py is still active\n        assert session.get(DagModel, "test_dag1").is_stale is False\n        # and the DAG from test_dag2.py is deactivated\n        assert session.get(DagModel, "test_dag2").is_stale is True\n\n    @pytest.mark.parametrize(\n        ("rel_filelocs", "expected_return", "expected_dag1_stale", "expected_dag2_stale"),\n        [\n            pytest.param(\n                ["test_dag1.py"],  # Only dag1 present, dag2 deleted\n                True,  # Should return True\n                False,  # dag1 should not be stale\n                True,  # dag2 should be stale\n                id="dags_deactivated",\n            ),\n            pytest.param(\n                ["test_dag1.py", "test_dag2.py"],  # Both files present\n                False,  # Should return False\n                False,  # dag1 should not be stale\n                False,  # dag2 should not be stale\n                id="no_dags_deactivated",\n            ),\n        ],\n    )\n    def test_deactivate_deleted_dags_return_value(\n        self, dag_maker, session, rel_filelocs, expected_return, expected_dag1_stale, expected_dag2_stale\n    ):\n        """Test that DagModel.deactivate_deleted_dags returns correct boolean value."""\n        with dag_maker("test_dag1") as dag1:\n            dag1.relative_fileloc = "test_dag1.py"\n        with dag_maker("test_dag2") as dag2:\n            dag2.relative_fileloc = "test_dag2.py"\n        dag_maker.sync_dagbag_to_db()\n\n        any_deactivated = DagModel.deactivate_deleted_dags(\n            bundle_name="dag_maker",\n            rel_filelocs=rel_filelocs,\n            session=session,\n        )\n\n        assert any_deactivated is expected_return\n        assert session.get(DagModel, "test_dag1").is_stale is expected_dag1_stale\n        assert session.get(DagModel, "test_dag2").is_stale is expected_dag2_stale\n\n    @pytest.mark.parametrize(\n        ("active_files", "should_call_cleanup"),\n        [\n            pytest.param(\n                [\n                    DagFileInfo(\n                        bundle_name="dag_maker",\n                        rel_path=Path("test_dag1.py"),\n                        bundle_path=TEST_DAGS_FOLDER,\n                    ),\n                    # test_dag2.py is deleted\n                ],\n                True,  # Should call cleanup\n                id="dags_deactivated",\n            ),\n            pytest.param(\n                [\n                    DagFileInfo(\n                        bundle_name="dag_maker",\n                        rel_path=Path("test_dag1.py"),\n                        bundle_path=TEST_DAGS_FOLDER,\n                    ),\n                    DagFileInfo(\n                        bundle_name="dag_maker",\n                        rel_path=Path("test_dag2.py"),\n                        bundle_path=TEST_DAGS_FOLDER,\n                    ),\n                ],\n                False,  # Should NOT call cleanup\n                id="no_dags_deactivated",\n            ),\n        ],\n    )\n    @mock.patch("airflow.dag_processing.manager.remove_references_to_deleted_dags")\n    def test_manager_deactivate_deleted_dags_cleanup_behavior(\n        self, mock_remove_references, dag_maker, session, active_files, should_call_cleanup\n    ):\n        """Test that manager conditionally calls remove_references_to_deleted_dags based on whether DAGs were deactivated."""\n        with dag_maker("test_dag1") as dag1:\n            dag1.relative_fileloc = "test_dag1.py"\n        with dag_maker("test_dag2") as dag2:\n            dag2.relative_fileloc = "test_dag2.py"\n        dag_maker.sync_dagbag_to_db()\n\n        manager = DagFileProcessorManager(max_runs=1)\n        manager.deactivate_deleted_dags("dag_maker", active_files)\n\n        if should_call_cleanup:\n            mock_remove_references.assert_called_once()\n        else:\n            mock_remove_references.assert_not_called()\n\n    @conf_vars({("core", "load_examples"): "False"})\n    def test_fetch_callbacks_from_database(self, configure_testing_dag_bundle):\n        """Test _fetch_callbacks returns callbacks ordered by priority_weight desc."""\n\n        dag_filepath = TEST_DAG_FOLDER / "test_on_failure_callback_dag.py"\n\n        callback1 = DagCallbackRequest(\n            dag_id="test_start_date_scheduling",\n            bundle_name="testing",\n            bundle_version=None,\n            filepath="test_on_failure_callback_dag.py",\n            is_failure_callback=True,\n            run_id="123",\n        )\n        callback2 = DagCallbackRequest(\n            dag_id="test_start_date_scheduling",\n            bundle_name="testing",\n            bundle_version=None,\n            filepath="test_on_failure_callback_dag.py",\n            is_failure_callback=True,\n            run_id="456",\n        )\n\n        with create_session() as session:\n            session.add(DbCallbackRequest(callback=callback1, priority_weight=11))\n            session.add(DbCallbackRequest(callback=callback2, priority_weight=10))\n\n        with configure_testing_dag_bundle(dag_filepath):\n            manager = DagFileProcessorManager(max_runs=1)\n            manager._dag_bundles = list(DagBundlesManager().get_all_dag_bundles())\n\n            with create_session() as session:\n                callbacks = manager._fetch_callbacks(session=session)\n\n                # Should return callbacks ordered by priority_weight desc (highest first)\n                assert callbacks[0].run_id == "123"\n                assert callbacks[1].run_id == "456"\n\n                assert len(session.scalars(select(DbCallbackRequest)).all()) == 0\n\n    @conf_vars(\n        {\n            ("dag_processor", "max_callbacks_per_loop"): "2",\n            ("core", "load_examples"): "False",\n        }\n    )\n    def test_fetch_callbacks_from_database_max_per_loop(self, tmp_path, configure_testing_dag_bundle):\n        """Test DagFileProcessorManager._fetch_callbacks method"""\n        dag_filepath = TEST_DAG_FOLDER / "test_on_failure_callback_dag.py"\n\n        with create_session() as session:\n            for i in range(5):\n                callback = DagCallbackRequest(\n                    dag_id="test_start_date_scheduling",\n                    bundle_name="testing",\n                    bundle_version=None,\n                    filepath="test_on_failure_callback_dag.py",\n                    is_failure_callback=True,\n                    run_id=str(i),\n                )\n                session.add(DbCallbackRequest(callback=callback, priority_weight=i))\n\n        with configure_testing_dag_bundle(dag_filepath):\n            manager = DagFileProcessorManager(max_runs=1)\n\n            with create_session() as session:\n                manager.run()\n                assert len(session.scalars(select(DbCallbackRequest)).all()) == 3\n\n            with create_session() as session:\n                manager.run()\n                assert len(session.scalars(select(DbCallbackRequest)).all()) == 1\n\n    @conf_vars({("core", "load_examples"): "False"})\n    def test_fetch_callbacks_ignores_other_bundles(self, configure_testing_dag_bundle):\n        """Ensure callbacks for bundles not owned by current dag processor manager are ignored and not deleted."""\n\n        dag_filepath = TEST_DAG_FOLDER / "test_on_failure_callback_dag.py"\n\n        # Create two callbacks: one for the active \'testing\' bundle and one for a different bundle\n        matching = DagCallbackRequest(\n            dag_id="test_start_date_scheduling",\n            bundle_name="testing",\n            bundle_version=None,\n            filepath="test_on_failure_callback_dag.py",\n            is_failure_callback=True,\n            run_id="match",\n        )\n        non_matching = DagCallbackRequest(\n            dag_id="test_start_date_scheduling",\n            bundle_name="other-bundle",\n            bundle_version=None,\n            filepath="test_on_failure_callback_dag.py",\n            is_failure_callback=True,\n            run_id="no-match",\n        )\n\n        with create_session() as session:\n            session.add(DbCallbackRequest(callback=matching, priority_weight=100))\n            session.add(DbCallbackRequest(callback=non_matching, priority_weight=200))\n\n        with configure_testing_dag_bundle(dag_filepath):\n            manager = DagFileProcessorManager(max_runs=1)\n            manager._dag_bundles = list(DagBundlesManager().get_all_dag_bundles())\n\n            with create_session() as session:\n                callbacks = manager._fetch_callbacks(session=session)\n\n                # Only the matching callback should be returned\n                assert [c.run_id for c in callbacks] == ["match"]\n\n                # The non-matching callback should remain in the DB\n                remaining = session.scalars(select(DbCallbackRequest)).all()\n                assert len(remaining) == 1\n                # Decode remaining request and verify it\'s for the other bundle\n                remaining_req = remaining[0].get_callback_request()\n                assert remaining_req.bundle_name == "other-bundle"\n\n    @conf_vars(\n        {\n            ("dag_processor", "max_callbacks_per_loop"): "2",\n            ("core", "load_examples"): "False",\n        }\n    )\n    def test_fetch_callbacks_filters_by_bundle_before_limit(self, configure_testing_dag_bundle):\n        dag_filepath = TEST_DAG_FOLDER / "test_on_failure_callback_dag.py"\n\n        matching = DagCallbackRequest(\n            dag_id="test_start_date_scheduling",\n            bundle_name="testing",\n            bundle_version=None,\n            filepath="test_on_failure_callback_dag.py",\n            is_failure_callback=True,\n            run_id="match",\n        )\n        non_matching_1 = DagCallbackRequest(\n            dag_id="test_start_date_scheduling",\n            bundle_name="other-bundle-a",\n            bundle_version=None,\n            filepath="test_on_failure_callback_dag.py",\n            is_failure_callback=True,\n            run_id="no-match-1",\n        )\n        non_matching_2 = DagCallbackRequest(\n            dag_id="test_start_date_scheduling",\n            bundle_name="other-bundle-b",\n            bundle_version=None,\n            filepath="test_on_failure_callback_dag.py",\n            is_failure_callback=True,\n            run_id="no-match-2",\n        )\n\n        with create_session() as session:\n            session.add(DbCallbackRequest(callback=non_matching_1, priority_weight=300))\n            session.add(DbCallbackRequest(callback=non_matching_2, priority_weight=200))\n            session.add(DbCallbackRequest(callback=matching, priority_weight=100))\n\n        with configure_testing_dag_bundle(dag_filepath):\n            manager = DagFileProcessorManager(max_runs=1)\n            manager._dag_bundles = list(DagBundlesManager().get_all_dag_bundles())\n\n            with create_session() as session:\n                callbacks = manager._fetch_callbacks(session=session)\n\n                assert [c.run_id for c in callbacks] == ["match"]\n\n                remaining = session.scalars(select(DbCallbackRequest)).all()\n                assert len(remaining) == 2\n                assert {callback.bundle_name for callback in remaining} == {\n                    "other-bundle-a",\n                    "other-bundle-b",\n                }\n\n    @mock.patch.object(DagFileProcessorManager, "_get_logger_for_dag_file")\n    def test_callback_queue(self, mock_get_logger, configure_testing_dag_bundle):\n        mock_logger = MagicMock()\n        mock_filehandle = MagicMock()\n        mock_get_logger.return_value = [mock_logger, mock_filehandle]\n\n        tmp_path = "/green_eggs/ham"\n        with configure_testing_dag_bundle(tmp_path):\n            # given\n            manager = DagFileProcessorManager(\n                max_runs=1,\n                processor_timeout=365 * 86_400,\n            )\n            manager._dag_bundles = list(DagBundlesManager().get_all_dag_bundles())\n\n            dag1_path = DagFileInfo(\n                bundle_name="testing", rel_path=Path("file1.py"), bundle_path=Path(tmp_path)\n            )\n            dag1_req1 = DagCallbackRequest(\n                filepath="file1.py",\n                dag_id="dag1",\n                run_id="run1",\n                is_failure_callback=False,\n                bundle_name="testing",\n                bundle_version=None,\n                msg=None,\n            )\n            dag1_req2 = DagCallbackRequest(\n                filepath="file1.py",\n                dag_id="dag1",\n                run_id="run1",\n                is_failure_callback=False,\n                bundle_name="testing",\n                bundle_version=None,\n                msg=None,\n            )\n\n            dag2_path = DagFileInfo(\n                bundle_name="testing", rel_path=Path("file2.py"), bundle_path=Path(tmp_path)\n            )\n            dag2_req1 = DagCallbackRequest(\n                filepath="file2.py",\n                dag_id="dag2",\n                run_id="run1",\n                bundle_name=dag2_path.bundle_name,\n                bundle_version=None,\n                is_failure_callback=False,\n                msg=None,\n            )\n\n            # when\n            manager._add_callback_to_queue(dag1_req1)\n            manager._add_callback_to_queue(dag2_req1)\n\n            # then - requests should be in manager\'s queue, with dag2 ahead of dag1 (because it was added last)\n            assert manager._file_queue == deque([dag2_path, dag1_path])\n            assert set(manager._callback_to_execute.keys()) == {\n                dag1_path,\n                dag2_path,\n            }\n            assert manager._callback_to_execute[dag2_path] == [dag2_req1]\n\n            # update the queue, although the callback is registered\n            assert manager._file_queue == deque([dag2_path, dag1_path])\n\n            # when\n            manager._add_callback_to_queue(dag1_req2)\n            # Since dag1_req2 is same as dag1_req1, we now have 2 items in file_path_queue\n            assert manager._file_queue == deque([dag2_path, dag1_path])\n            assert manager._callback_to_execute[dag1_path] == [\n                dag1_req1,\n                dag1_req2,\n            ]\n\n            with mock.patch.object(\n                DagFileProcessorProcess, "start", side_effect=lambda *args, **kwargs: self.mock_processor()\n            ) as start:\n                manager._start_new_processes()\n            # Callbacks passed to processor\n            assert start.call_args_list == [\n                mock.call(\n                    id=mock.ANY,\n                    path=Path(dag2_path.bundle_path, dag2_path.rel_path),\n                    bundle_path=dag2_path.bundle_path,\n                    bundle_name="testing",\n                    callbacks=[dag2_req1],\n                    selector=mock.ANY,\n                    logger=mock_logger,\n                    logger_filehandle=mock_filehandle,\n                    client=mock.ANY,\n                ),\n                mock.call(\n                    id=mock.ANY,\n                    path=Path(dag1_path.bundle_path, dag1_path.rel_path),\n                    bundle_path=dag1_path.bundle_path,\n                    bundle_name="testing",\n                    callbacks=[dag1_req1, dag1_req2],\n                    selector=mock.ANY,\n                    logger=mock_logger,\n                    logger_filehandle=mock_filehandle,\n                    client=mock.ANY,\n                ),\n            ]\n            # And removed from the queue\n            assert dag1_path not in manager._callback_to_execute\n            assert dag2_path not in manager._callback_to_execute\n\n    @mock.patch("airflow.dag_processing.manager.DagBundlesManager")\n    def test_add_callback_initializes_versioned_bundle(self, mock_bundle_manager):\n        manager = DagFileProcessorManager(max_runs=1)\n        bundle = MagicMock()\n        bundle.supports_versioning = True\n        bundle.path = Path("/tmp/bundle")\n        mock_bundle_manager.return_value.get_bundle.return_value = bundle\n\n        request = DagCallbackRequest(\n            filepath="file1.py",\n            dag_id="dag1",\n            run_id="run1",\n            is_failure_callback=False,\n            bundle_name="testing",\n            bundle_version="some_commit_hash",\n            msg=None,\n        )\n\n        manager._add_callback_to_queue(request)\n\n        bundle.initialize.assert_called_once()\n\n    @mock.patch("airflow.dag_processing.manager.DagBundlesManager")\n    def test_add_callback_skips_when_bundle_init_fails(self, mock_bundle_manager):\n        manager = DagFileProcessorManager(max_runs=1)\n        bundle = MagicMock()\n        bundle.supports_versioning = True\n        bundle.initialize.side_effect = Exception("clone failed")\n        mock_bundle_manager.return_value.get_bundle.return_value = bundle\n\n        request = DagCallbackRequest(\n            filepath="file1.py",\n            dag_id="dag1",\n            run_id="run1",\n            is_failure_callback=False,\n            bundle_name="testing",\n            bundle_version="some_commit_hash",\n            msg=None,\n        )\n\n        manager._add_callback_to_queue(request)\n\n        bundle.initialize.assert_called_once()\n        assert len(manager._callback_to_execute) == 0\n\n    def test_dag_with_assets(self, session, configure_testing_dag_bundle):\n        """\'Integration\' test to ensure that the assets get parsed and stored correctly for parsed dags."""\n        test_dag_path = str(TEST_DAG_FOLDER / "test_assets.py")\n\n        with configure_testing_dag_bundle(test_dag_path):\n            manager = DagFileProcessorManager(\n                max_runs=1,\n                processor_timeout=365 * 86_400,\n            )\n            manager.run()\n\n        dag_model = session.get(DagModel, ("dag_with_skip_task"))\n        assert dag_model.task_outlet_asset_references == [\n            TaskOutletAssetReference(asset_id=mock.ANY, dag_id="dag_with_skip_task", task_id="skip_task")\n        ]\n\n    def test_bundles_are_refreshed(self):\n        """\n        Ensure bundles are refreshed by the manager, when necessary.\n\n        - always refresh all bundles when starting the manager\n        - refresh if the bundle hasn\'t been refreshed in the refresh_interval\n        - when the latest_version in the db doesn\'t match the version this manager knows about\n        """\n        config = [\n            {\n                "name": "bundleone",\n                "classpath": "airflow.dag_processing.bundles.local.LocalDagBundle",\n                "kwargs": {"path": "/dev/null", "refresh_interval": 0},\n            },\n            {\n                "name": "bundletwo",\n                "classpath": "airflow.dag_processing.bundles.local.LocalDagBundle",\n                "kwargs": {"path": "/dev/null", "refresh_interval": 300},\n            },\n        ]\n\n        bundleone = MagicMock()\n        bundleone.name = "bundleone"\n        bundleone.path = "/dev/null"\n        bundleone.refresh_interval = 0\n        bundleone.get_current_version.return_value = None\n        bundletwo = MagicMock()\n        bundletwo.name = "bundletwo"\n        bundletwo.path = "/dev/null"\n        bundletwo.refresh_interval = 300\n        bundletwo.get_current_version.return_value = None\n\n        with conf_vars({("dag_processor", "dag_bundle_config_list"): json.dumps(config)}):\n            DagBundlesManager().sync_bundles_to_db()\n            with mock.patch("airflow.dag_processing.manager.DagBundlesManager") as mock_bundle_manager:\n                mock_bundle_manager.return_value._bundle_config = {"bundleone": None, "bundletwo": None}\n                mock_bundle_manager.return_value.get_all_dag_bundles.return_value = [bundleone, bundletwo]\n\n                # We should refresh bundleone twice, but bundletwo only once - it has a long refresh_interval\n                manager = DagFileProcessorManager(max_runs=2)\n                manager.run()\n                assert bundleone.refresh.call_count == 2\n                bundletwo.refresh.assert_called_once()\n\n                # Now, we should refresh both bundles, regardless of the refresh_interval\n                # as we are starting up a fresh manager\n                bundleone.reset_mock()\n                bundletwo.reset_mock()\n                manager = DagFileProcessorManager(max_runs=2)\n                manager.run()\n                assert bundleone.refresh.call_count == 2\n                bundletwo.refresh.assert_called_once()\n\n                # however, if the version doesn\'t match, we should still refresh\n                bundletwo.reset_mock()\n\n                def _update_bundletwo_version():\n                    # We will update the bundle version in the db, so the next manager loop\n                    # will believe another processor had seen a new version\n                    with create_session() as session:\n                        bundletwo_model = session.get(DagBundleModel, "bundletwo")\n                        bundletwo_model.version = "123"\n\n                bundletwo.refresh.side_effect = _update_bundletwo_version\n                manager = DagFileProcessorManager(max_runs=2)\n                manager.run()\n                assert bundletwo.refresh.call_count == 2\n\n    def test_bundle_refresh_check_interval(self):\n        """Ensure dag processor doesn\'t refresh bundles every loop."""\n        config = [\n            {\n                "name": "bundleone",\n                "classpath": "airflow.dag_processing.bundles.local.LocalDagBundle",\n                "kwargs": {"path": "/dev/null", "refresh_interval": 0},\n            },\n        ]\n\n        bundleone = MagicMock()\n        bundleone.name = "bundleone"\n        bundleone.path = "/dev/null"\n        bundleone.refresh_interval = 0\n        bundleone.get_current_version.return_value = None\n\n        with conf_vars(\n            {\n                ("dag_processor", "dag_bundle_config_list"): json.dumps(config),\n                ("dag_processor", "bundle_refresh_check_interval"): "10",\n            }\n        ):\n            DagBundlesManager().sync_bundles_to_db()\n            manager = DagFileProcessorManager(max_runs=2)\n            manager._dag_bundles = [bundleone]\n            manager._refresh_dag_bundles({})\n            assert bundleone.refresh.call_count == 1\n            manager._refresh_dag_bundles({})\n            assert bundleone.refresh.call_count == 1  # didn\'t fresh the second time\n\n    @pytest.mark.parametrize(\n        (\n            "elapsed_time_since_refresh",\n            "current_version_matches_db",\n            "previously_seen",\n            "force_refresh",\n            "expected",\n        ),\n        [\n            (10, True, True, False, True),\n            (400, True, True, False, False),\n            (10, False, True, False, False),\n            (10, True, False, False, False),\n            (10, True, True, True, False),\n        ],\n    )\n    def test_should_skip_bundle_refresh(\n        self,\n        elapsed_time_since_refresh,\n        current_version_matches_db,\n        previously_seen,\n        force_refresh,\n        expected,\n    ):\n        manager = DagFileProcessorManager(max_runs=1)\n        bundle = MagicMock()\n        bundle.name = "bundleone"\n        bundle.refresh_interval = 300\n\n        if force_refresh:\n            manager._force_refresh_bundles = {"bundleone"}\n\n        should_skip_refresh = manager.should_skip_refresh(\n            bundle=bundle,\n            elapsed_time_since_refresh=elapsed_time_since_refresh,\n            current_version_matches_db=current_version_matches_db,\n            previously_seen=previously_seen,\n        )\n\n        assert should_skip_refresh is expected\n\n    def test_bundle_force_refresh(self):\n        """Ensure the dag processor honors force refreshing a bundle."""\n        config = [\n            {\n                "name": "bundleone",\n                "classpath": "airflow.dag_processing.bundles.local.LocalDagBundle",\n                "kwargs": {"path": "/dev/null", "refresh_interval": 0},\n            },\n        ]\n\n        bundleone = MagicMock()\n        bundleone.name = "bundleone"\n        bundleone.path = "/dev/null"\n        bundleone.refresh_interval = 0\n        bundleone.get_current_version.return_value = None\n\n        with conf_vars(\n            {\n                ("dag_processor", "dag_bundle_config_list"): json.dumps(config),\n                ("dag_processor", "bundle_refresh_check_interval"): "10",\n            }\n        ):\n            DagBundlesManager().sync_bundles_to_db()\n            manager = DagFileProcessorManager(max_runs=2)\n            manager._dag_bundles = [bundleone]\n            manager._refresh_dag_bundles({})\n            assert bundleone.refresh.call_count == 1\n            manager._force_refresh_bundles = {"bundleone"}\n            manager._refresh_dag_bundles({})\n            assert bundleone.refresh.call_count == 2  # forced refresh\n\n    def test_bundles_versions_are_stored(self, session):\n        config = [\n            {\n                "name": "bundleone",\n                "classpath": "airflow.dag_processing.bundles.local.LocalDagBundle",\n                "kwargs": {"path": "/dev/null", "refresh_interval": 0},\n            },\n        ]\n\n        mybundle = MagicMock()\n        mybundle.name = "bundleone"\n        mybundle.path = "/dev/null"\n        mybundle.refresh_interval = 0\n        mybundle.supports_versioning = True\n        mybundle.get_current_version.return_value = "123"\n\n        with conf_vars({("dag_processor", "dag_bundle_config_list"): json.dumps(config)}):\n            DagBundlesManager().sync_bundles_to_db()\n            with mock.patch("airflow.dag_processing.manager.DagBundlesManager") as mock_bundle_manager:\n                mock_bundle_manager.return_value._bundle_config = {"bundleone": None}\n                mock_bundle_manager.return_value.get_all_dag_bundles.return_value = [mybundle]\n                manager = DagFileProcessorManager(max_runs=1)\n                manager.run()\n\n        with create_session() as session:\n            model = session.get(DagBundleModel, "bundleone")\n            assert model.version == "123"\n\n    def test_non_versioned_bundle_get_version_not_called(self):\n        config = [\n            {\n                "name": "bundleone",\n                "classpath": "airflow.dag_processing.bundles.local.LocalDagBundle",\n                "kwargs": {"path": "/dev/null", "refresh_interval": 0},\n            },\n        ]\n\n        bundleone = MagicMock()\n        bundleone.name = "bundleone"\n        bundleone.refresh_interval = 0\n        bundleone.supports_versioning = False\n        bundleone.path = Path("/dev/null")\n\n        with conf_vars({("dag_processor", "dag_bundle_config_list"): json.dumps(config)}):\n            DagBundlesManager().sync_bundles_to_db()\n            with mock.patch("airflow.dag_processing.manager.DagBundlesManager") as mock_bundle_manager:\n                mock_bundle_manager.return_value._bundle_config = {"bundleone": None}\n                mock_bundle_manager.return_value.get_all_dag_bundles.return_value = [bundleone]\n                manager = DagFileProcessorManager(max_runs=1)\n                manager.run()\n\n        bundleone.refresh.assert_called_once()\n        bundleone.get_current_version.assert_not_called()\n\n    def test_versioned_bundle_get_version_called_once(self):\n        """Make sure in a normal "warm" loop, get_current_version is called just once after refresha"""\n        config = [\n            {\n                "name": "bundleone",\n                "classpath": "airflow.dag_processing.bundles.local.LocalDagBundle",\n                "kwargs": {"path": "/dev/null", "refresh_interval": 0},\n            },\n        ]\n\n        bundleone = MagicMock()\n        bundleone.name = "bundleone"\n        bundleone.refresh_interval = 0\n        bundleone.supports_versioning = True\n        bundleone.get_current_version.return_value = "123"\n        bundleone.path = Path("/dev/null")\n\n        with conf_vars({("dag_processor", "dag_bundle_config_list"): json.dumps(config)}):\n            DagBundlesManager().sync_bundles_to_db()\n            with mock.patch("airflow.dag_processing.manager.DagBundlesManager") as mock_bundle_manager:\n                mock_bundle_manager.return_value._bundle_config = {"bundleone": None}\n                mock_bundle_manager.return_value.get_all_dag_bundles.return_value = [bundleone]\n                manager = DagFileProcessorManager(max_runs=1)\n                manager.run()  # run it once to warm up\n\n                # now run it again so we can check we only call get_current_version once\n                bundleone.refresh.reset_mock()\n                bundleone.get_current_version.reset_mock()\n                manager.run()\n                bundleone.refresh.assert_called_once()\n                bundleone.get_current_version.assert_called_once()\n\n    @pytest.mark.parametrize(\n        ("bundle_names", "expected"),\n        [\n            (None, {"bundle1", "bundle2", "bundle3"}),\n            (["bundle1"], {"bundle1"}),\n            (["bundle1", "bundle2"], {"bundle1", "bundle2"}),\n        ],\n    )\n    def test_bundle_names_to_parse(self, bundle_names, expected, configure_dag_bundles):\n        config = {f"bundle{i}": os.devnull for i in range(1, 4)}\n        with configure_dag_bundles(config):\n            manager = DagFileProcessorManager(max_runs=1, bundle_names_to_parse=bundle_names)\n            manager._run_parsing_loop = MagicMock()\n            manager.run()\n\n        bundle_names_being_parsed = {b.name for b in manager._dag_bundles}\n        assert bundle_names_being_parsed == expected\n\n    @conf_vars({("core", "multi_team"): "true"})\n    def test_bundles_with_team(self, session):\n        team1_name = "test_team1"\n        team2_name = "test_team2"\n\n        # Create two teams\n        session.add(Team(name=team1_name))\n        session.add(Team(name=team2_name))\n        session.commit()\n\n        # Associate a dag bundle to a team\n        config = [\n            {\n                "name": "bundle_team",\n                "classpath": "airflow.dag_processing.bundles.local.LocalDagBundle",\n                "kwargs": {},\n                "team_name": team1_name,\n            },\n        ]\n\n        with conf_vars({("dag_processor", "dag_bundle_config_list"): json.dumps(config)}):\n            DagBundlesManager().sync_bundles_to_db()\n\n        team = session.scalars(select(Team).where(Team.name == team1_name)).one()\n        assert len(team.dag_bundles) == 1\n        assert team.dag_bundles[0].name == "bundle_team"\n\n        # Change the team ownership\n        config = [\n            {\n                "name": "bundle_team",\n                "classpath": "airflow.dag_processing.bundles.local.LocalDagBundle",\n                "kwargs": {},\n                "team_name": team2_name,\n            },\n        ]\n\n        with conf_vars({("dag_processor", "dag_bundle_config_list"): json.dumps(config)}):\n            DagBundlesManager().sync_bundles_to_db()\n\n        team1 = session.scalars(select(Team).where(Team.name == team1_name)).one()\n        assert len(team1.dag_bundles) == 0\n        team2 = session.scalars(select(Team).where(Team.name == team2_name)).one()\n        assert len(team2.dag_bundles) == 1\n        assert team2.dag_bundles[0].name == "bundle_team"\n\n        # Delete the team ownership\n        config = [\n            {\n                "name": "bundle_team",\n                "classpath": "airflow.dag_processing.bundles.local.LocalDagBundle",\n                "kwargs": {},\n            },\n        ]\n\n        with conf_vars({("dag_processor", "dag_bundle_config_list"): json.dumps(config)}):\n            DagBundlesManager().sync_bundles_to_db()\n\n        team1 = session.scalars(select(Team).where(Team.name == team1_name)).one()\n        assert len(team1.dag_bundles) == 0\n        team2 = session.scalars(select(Team).where(Team.name == team2_name)).one()\n        assert len(team2.dag_bundles) == 0\n\n    @mock.patch.object(DagFileProcessorProcess, "start")\n    def test_create_process_passes_bundle_name_to_process_start(\n        self, mock_process_start, configure_testing_dag_bundle\n    ):\n        """Test that DagFileProcessorManager._create_process() passes bundle_name to DagFileProcessorProcess.start()"""\n        with configure_testing_dag_bundle("/tmp"):\n            manager = DagFileProcessorManager(max_runs=1)\n            manager._dag_bundles = list(DagBundlesManager().get_all_dag_bundles())\n\n        # Setup test data\n        file_info = DagFileInfo(\n            bundle_name="testing", rel_path=Path("test_dag.py"), bundle_path=TEST_DAGS_FOLDER\n        )\n\n        # Mock the process creation\n        mock_process_start.return_value = self.mock_processor()[0]\n\n        # Call _create_process (only takes one parameter: dag_file)\n        manager._create_process(file_info)\n\n        # Verify DagFileProcessorProcess.start was called with correct bundle_name\n        mock_process_start.assert_called_once()\n        call_kwargs = mock_process_start.call_args.kwargs\n        assert call_kwargs["bundle_name"] == "testing"\n\n    @mock.patch("airflow.dag_processing.manager.Stats.initialize")\n    def test_stats_initialize_called_on_run(self, stats_init_mock, tmp_path, configure_testing_dag_bundle):\n        """Test that Stats.initialize() is called when DagFileProcessorManager.run() is executed."""\n        with configure_testing_dag_bundle(tmp_path):\n            manager = DagFileProcessorManager(max_runs=1)\n            manager.run()\n\n        # Verify Stats.initialize was called with the expected configuration parameters\n        stats_init_mock.assert_called_once()\n        call_kwargs = stats_init_mock.call_args.kwargs\n        assert "factory" in call_kwargs\n\n    @mock.patch("airflow.dag_processing.manager.Stats.gauge")\n    def test_stats_total_parse_time(self, statsd_gauge_mock, tmp_path, configure_testing_dag_bundle):\n        key = "dag_processing.total_parse_time"\n        gauge_values = defaultdict(list)\n        statsd_gauge_mock.side_effect = lambda name, value: gauge_values[name].append(value)\n\n        dag_path = tmp_path / "temp_dag.py"\n        dag_code = textwrap.dedent(\n            """\n            from airflow import DAG\n            dag = DAG(dag_id=\'temp_dag\')\n            """\n        )\n        dag_path.write_text(dag_code)\n\n        with configure_testing_dag_bundle(tmp_path):\n            manager = DagFileProcessorManager(max_runs=0)\n\n            for _ in range(3):\n                manager.max_runs += 1\n                manager.run()\n\n                assert key in gauge_values\n                assert len(gauge_values[key]) == 1\n                assert gauge_values[key][0] >= 1e-4\n\n                dag_path.touch()  # make the loop run faster\n                gauge_values.clear()\n',
            'airflow-core/tests/unit/models/test_dag.py': '#\n# Licensed to the Apache Software Foundation (ASF) under one\n# or more contributor license agreements.  See the NOTICE file\n# distributed with this work for additional information\n# regarding copyright ownership.  The ASF licenses this file\n# to you under the Apache License, Version 2.0 (the\n# "License"); you may not use this file except in compliance\n# with the License.  You may obtain a copy of the License at\n#\n#   http://www.apache.org/licenses/LICENSE-2.0\n#\n# Unless required by applicable law or agreed to in writing,\n# software distributed under the License is distributed on an\n# "AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\n# KIND, either express or implied.  See the License for the\n# specific language governing permissions and limitations\n# under the License.\nfrom __future__ import annotations\n\nimport datetime\nimport logging\nimport os\nimport pickle\nimport re\nfrom contextlib import nullcontext\nfrom datetime import timedelta\nfrom pathlib import Path\nfrom typing import TYPE_CHECKING\nfrom unittest import mock\nfrom unittest.mock import ANY, patch\n\nimport jinja2\nimport pendulum\nimport pytest\nimport time_machine\nfrom sqlalchemy import delete, inspect, select, update\n\nfrom airflow import settings\nfrom airflow._shared.module_loading import qualname\nfrom airflow._shared.timezones import timezone\nfrom airflow._shared.timezones.timezone import datetime as datetime_tz\nfrom airflow.configuration import conf\nfrom airflow.dag_processing.dagbag import BundleDagBag, DagBag\nfrom airflow.exceptions import AirflowException\nfrom airflow.models.asset import (\n    AssetAliasModel,\n    AssetDagRunQueue,\n    AssetEvent,\n    AssetModel,\n    TaskOutletAssetReference,\n)\nfrom airflow.models.dag import (\n    DagModel,\n    DagOwnerAttributes,\n    DagTag,\n    get_asset_triggered_next_run_info,\n    get_next_data_interval,\n    get_run_data_interval,\n)\nfrom airflow.models.dagbag import DBDagBag\nfrom airflow.models.dagbundle import DagBundleModel\nfrom airflow.models.dagrun import DagRun\nfrom airflow.models.deadline_alert import DeadlineAlert as DeadlineAlertModel\nfrom airflow.models.serialized_dag import SerializedDagModel\nfrom airflow.models.taskinstance import TaskInstance as TI\nfrom airflow.providers.standard.operators.bash import BashOperator\nfrom airflow.providers.standard.operators.empty import EmptyOperator\nfrom airflow.providers.standard.operators.python import PythonOperator\nfrom airflow.sdk import (\n    DAG,\n    BaseOperator,\n    CronPartitionTimetable,\n    TaskGroup,\n    setup,\n    task as task_decorator,\n    teardown,\n)\nfrom airflow.sdk.definitions._internal.contextmanager import TaskGroupContext\nfrom airflow.sdk.definitions._internal.templater import NativeEnvironment, SandboxedEnvironment\nfrom airflow.sdk.definitions.asset import Asset, AssetAlias, AssetAll, AssetAny\nfrom airflow.sdk.definitions.callback import AsyncCallback\nfrom airflow.sdk.definitions.deadline import DeadlineAlert, DeadlineReference\nfrom airflow.sdk.definitions.param import Param\nfrom airflow.serialization.definitions.dag import SerializedDAG\nfrom airflow.serialization.encoders import coerce_to_core_timetable\nfrom airflow.serialization.serialized_objects import LazyDeserializedDAG\nfrom airflow.task.trigger_rule import TriggerRule\nfrom airflow.timetables.base import DagRunInfo, DataInterval, TimeRestriction, Timetable\nfrom airflow.timetables.simple import (\n    AssetTriggeredTimetable,\n    NullTimetable,\n    OnceTimetable,\n)\nfrom airflow.utils.file import list_py_file_paths\nfrom airflow.utils.session import create_session\nfrom airflow.utils.state import DagRunState, State, TaskInstanceState\nfrom airflow.utils.types import DagRunTriggeredByType, DagRunType\n\nfrom tests_common.test_utils.asserts import assert_queries_count\nfrom tests_common.test_utils.config import conf_vars\nfrom tests_common.test_utils.dag import create_scheduler_dag, sync_dag_to_db\nfrom tests_common.test_utils.db import (\n    clear_db_assets,\n    clear_db_dag_bundles,\n    clear_db_dags,\n    clear_db_runs,\n    clear_db_serialized_dags,\n    clear_db_teams,\n)\nfrom tests_common.test_utils.mapping import expand_mapped_task\nfrom tests_common.test_utils.mock_plugins import mock_plugin_manager\nfrom tests_common.test_utils.taskinstance import run_task_instance\nfrom tests_common.test_utils.timetables import cron_timetable, delta_timetable\nfrom unit.models import DEFAULT_DATE\nfrom unit.plugins.priority_weight_strategy import (\n    FactorPriorityWeightStrategy,\n    StaticTestPriorityWeightStrategy,\n    TestPriorityWeightStrategyPlugin,\n)\n\nif TYPE_CHECKING:\n    from sqlalchemy.engine import ScalarResult\n    from sqlalchemy.orm import Session\n\npytestmark = pytest.mark.db_test\n\nTEST_DATE = datetime_tz(2015, 1, 2, 0, 0)\n\nrepo_root = Path(__file__).parents[2]\n\n\nasync def empty_callback_for_deadline():\n    """Used in a number of tests to confirm that Deadlines and DeadlineAlerts function correctly."""\n    pass\n\n\n@pytest.fixture\ndef clear_dags():\n    clear_db_dags()\n    clear_db_serialized_dags()\n    clear_db_dag_bundles()\n    yield\n    clear_db_dags()\n    clear_db_serialized_dags()\n    clear_db_dag_bundles()\n\n\n@pytest.fixture\ndef clear_assets():\n    clear_db_assets()\n    yield\n    clear_db_assets()\n\n\nTEST_DAGS_FOLDER = Path(__file__).parents[1] / "dags"\n\n\n@pytest.fixture\ndef test_dags_bundle(configure_testing_dag_bundle):\n    with configure_testing_dag_bundle(TEST_DAGS_FOLDER):\n        yield\n\n\ndef _create_dagrun(\n    dag: DAG,\n    *,\n    logical_date: datetime.datetime,\n    data_interval: tuple[datetime.datetime, datetime.datetime],\n    run_type: DagRunType,\n    state: DagRunState = DagRunState.RUNNING,\n    start_date: datetime.datetime | None = None,\n    **kwargs,\n) -> DagRun:\n    logical_date = timezone.coerce_datetime(logical_date)\n    if not isinstance(data_interval, DataInterval):\n        data_interval = DataInterval(*map(timezone.coerce_datetime, data_interval))\n    scheduler_dag = sync_dag_to_db(dag)\n    run_id = scheduler_dag.timetable.generate_run_id(\n        run_type=run_type,\n        run_after=logical_date or data_interval.end,\n        data_interval=data_interval,\n    )\n    return scheduler_dag.create_dagrun(\n        run_id=run_id,\n        logical_date=logical_date,\n        data_interval=data_interval,\n        run_after=data_interval.end,\n        run_type=run_type,\n        state=state,\n        start_date=start_date,\n        triggered_by=DagRunTriggeredByType.TEST,\n        **kwargs,\n    )\n\n\nclass TestDag:\n    def setup_method(self) -> None:\n        clear_db_runs()\n        clear_db_dags()\n        clear_db_assets()\n\n    @conf_vars({("core", "load_examples"): "false"})\n    def test_dag_test_auto_parses_when_not_serialized(self, test_dags_bundle, session):\n        """\n        DAG.test() should auto-parse and sync the DAG if it\'s not serialized yet.\n        """\n\n        dag_id = "test_example_bash_operator"\n\n        dagbag = DagBag(dag_folder=os.fspath(TEST_DAGS_FOLDER), include_examples=False)\n        dag = dagbag.dags.get(dag_id)\n\n        # Ensure not serialized yet\n        assert DBDagBag().get_latest_version_of_dag(dag_id, session=session) is None\n        assert session.scalar(select(DagRun).where(DagRun.dag_id == dag_id)) is None\n\n        dr = dag.test()\n        assert dr is not None\n\n        # Serialized DAG should now exist and DagRun would be created\n        ser = DBDagBag().get_latest_version_of_dag(dag_id, session=session)\n        assert ser is not None\n        assert session.scalar(select(DagRun).where(DagRun.dag_id == dag_id)) is not None\n\n    def teardown_method(self) -> None:\n        clear_db_runs()\n        clear_db_dags()\n        clear_db_assets()\n\n    @staticmethod\n    def _occur_before(a, b, list_):\n        """\n        Assert that a occurs before b in the list.\n        """\n        a_index = -1\n        b_index = -1\n        for i, e in enumerate(list_):\n            if e.task_id == a:\n                a_index = i\n            if e.task_id == b:\n                b_index = i\n        return 0 <= a_index < b_index\n\n    def test_dag_naive_default_args_start_date(self):\n        dag = DAG("DAG", schedule=None, default_args={"start_date": datetime.datetime(2018, 1, 1)})\n        assert dag.timezone == settings.TIMEZONE\n        dag = DAG("DAG", schedule=None, start_date=datetime.datetime(2018, 1, 1))\n        assert dag.timezone == settings.TIMEZONE\n\n    def test_dag_none_default_args_start_date(self):\n        """\n        Tests if a start_date of None in default_args\n        works.\n        """\n        dag = DAG("DAG", schedule=None, default_args={"start_date": None})\n        assert dag.timezone == settings.TIMEZONE\n\n    @pytest.mark.parametrize(\n        ("cls", "expected"),\n        [\n            (StaticTestPriorityWeightStrategy, 99),\n            (FactorPriorityWeightStrategy, 3),\n        ],\n    )\n    def test_dag_task_custom_weight_strategy(self, cls, expected):\n        with (\n            mock_plugin_manager(plugins=[TestPriorityWeightStrategyPlugin]),\n            DAG("dag", schedule=None, start_date=DEFAULT_DATE, default_args={"owner": "owner1"}) as dag,\n        ):\n            task = EmptyOperator(\n                task_id="empty_task",\n                weight_rule=cls(),\n            )\n        dr = _create_dagrun(\n            dag,\n            logical_date=DEFAULT_DATE,\n            data_interval=(DEFAULT_DATE, DEFAULT_DATE),\n            run_type=DagRunType.MANUAL,\n        )\n        ti = dr.get_task_instance(task.task_id)\n        assert ti.priority_weight == expected\n\n    def test_user_defined_filters_macros(self):\n        def jinja_udf(name):\n            return f"Hello {name}"\n\n        dag = DAG(\n            "test-dag",\n            schedule=None,\n            start_date=DEFAULT_DATE,\n            user_defined_filters={"hello": jinja_udf},\n            user_defined_macros={"foo": "bar"},\n        )\n        jinja_env = dag.get_template_env()\n\n        assert "hello" in jinja_env.filters\n        assert jinja_env.filters["hello"] == jinja_udf\n        assert jinja_env.globals["foo"] == "bar"\n\n    def test_set_jinja_env_additional_option(self):\n        dag = DAG(\n            dag_id="test-dag",\n            schedule=None,\n            jinja_environment_kwargs={"keep_trailing_newline": True, "cache_size": 50},\n        )\n        jinja_env = dag.get_template_env()\n        assert jinja_env.keep_trailing_newline is True\n        assert jinja_env.cache.capacity == 50\n\n        assert jinja_env.undefined is jinja2.StrictUndefined\n\n    def test_template_undefined(self):\n        dag = DAG("test-dag", schedule=None, template_undefined=jinja2.Undefined)\n        jinja_env = dag.get_template_env()\n        assert jinja_env.undefined is jinja2.Undefined\n\n    @pytest.mark.parametrize(\n        ("use_native_obj", "force_sandboxed", "expected_env"),\n        [\n            (False, True, SandboxedEnvironment),\n            (False, False, SandboxedEnvironment),\n            (True, False, NativeEnvironment),\n            (True, True, SandboxedEnvironment),\n        ],\n    )\n    def test_template_env(self, use_native_obj, force_sandboxed, expected_env):\n        dag = DAG("test-dag", schedule=None, render_template_as_native_obj=use_native_obj)\n        jinja_env = dag.get_template_env(force_sandboxed=force_sandboxed)\n        assert isinstance(jinja_env, expected_env)\n\n    def test_resolve_template_files_value(self, tmp_path):\n        path = tmp_path / "testfile.template"\n        path.write_text("{{ ds }}")\n\n        with DAG(\n            dag_id="test-dag",\n            schedule=None,\n            start_date=DEFAULT_DATE,\n            template_searchpath=os.fspath(path.parent),\n        ):\n            task = EmptyOperator(task_id="op1")\n\n        task.test_field = path.name\n        task.template_fields = ("test_field",)\n        task.template_ext = (".template",)\n        task.resolve_template_files()\n\n        assert task.test_field == "{{ ds }}"\n\n    def test_resolve_template_files_list(self, tmp_path):\n        path = tmp_path / "testfile.template"\n        path.write_text("{{ ds }}")\n\n        with DAG(\n            dag_id="test-dag",\n            schedule=None,\n            start_date=DEFAULT_DATE,\n            template_searchpath=os.fspath(path.parent),\n        ):\n            task = EmptyOperator(task_id="op1")\n\n        task.test_field = [path.name, "some_string"]\n        task.template_fields = ("test_field",)\n        task.template_ext = (".template",)\n        task.resolve_template_files()\n\n        assert task.test_field == ["{{ ds }}", "some_string"]\n\n    def test_create_dagrun_when_schedule_is_none_and_empty_start_date(self, testing_dag_bundle):\n        # Check that we don\'t get an AttributeError \'start_date\' for self.start_date when schedule is none\n        dag = DAG("dag_with_none_schedule_and_empty_start_date", schedule=None)\n        dag.add_task(BaseOperator(task_id="task_without_start_date"))\n        scheduler_dag = sync_dag_to_db(dag)\n        dagrun = scheduler_dag.create_dagrun(\n            run_id="test",\n            state=State.RUNNING,\n            run_type=DagRunType.MANUAL,\n            logical_date=DEFAULT_DATE,\n            data_interval=(DEFAULT_DATE, DEFAULT_DATE),\n            run_after=DEFAULT_DATE,\n            triggered_by=DagRunTriggeredByType.TEST,\n        )\n        assert dagrun is not None\n\n    def test_dagtag_repr(self, testing_dag_bundle):\n        clear_db_dags()\n        dag = DAG("dag-test-dagtag", schedule=None, start_date=DEFAULT_DATE, tags=["tag-1", "tag-2"])\n        session = settings.Session()\n        orm_dag = DagModel(\n            dag_id=dag.dag_id,\n            bundle_name="testing",\n            is_stale=False,\n        )\n        session.add(orm_dag)\n        session.flush()\n\n        sync_dag_to_db(dag)\n        with create_session() as session:\n            assert {"tag-1", "tag-2"} == {\n                repr(t)\n                for t in session.scalars(select(DagTag).where(DagTag.dag_id == "dag-test-dagtag")).all()\n            }\n\n    def test_bulk_write_to_db(self, testing_dag_bundle):\n        clear_db_dags()\n        dags = [\n            create_scheduler_dag(\n                DAG(f"dag-bulk-sync-{i}", schedule=None, start_date=DEFAULT_DATE, tags=["test-dag"])\n            )\n            for i in range(4)\n        ]\n\n        with assert_queries_count(6):\n            SerializedDAG.bulk_write_to_db("testing", None, dags)\n        with create_session() as session:\n            assert {"dag-bulk-sync-0", "dag-bulk-sync-1", "dag-bulk-sync-2", "dag-bulk-sync-3"} == {\n                row[0] for row in session.execute(select(DagModel.dag_id)).all()\n            }\n            assert {\n                ("dag-bulk-sync-0", "test-dag"),\n                ("dag-bulk-sync-1", "test-dag"),\n                ("dag-bulk-sync-2", "test-dag"),\n                ("dag-bulk-sync-3", "test-dag"),\n            } == set(session.execute(select(DagTag.dag_id, DagTag.name)).all())\n\n            for row in session.execute(select(DagModel.last_parsed_time)).all():\n                assert row[0] is not None\n\n        # Re-sync should do fewer queries\n        with assert_queries_count(9):\n            SerializedDAG.bulk_write_to_db("testing", None, dags)\n        with assert_queries_count(9):\n            SerializedDAG.bulk_write_to_db("testing", None, dags)\n        # Adding tags\n        for dag in dags:\n            dag.tags.add("test-dag2")\n        with assert_queries_count(10):\n            SerializedDAG.bulk_write_to_db("testing", None, dags)\n        with create_session() as session:\n            assert {"dag-bulk-sync-0", "dag-bulk-sync-1", "dag-bulk-sync-2", "dag-bulk-sync-3"} == {\n                row[0] for row in session.execute(select(DagModel.dag_id)).all()\n            }\n            assert {\n                ("dag-bulk-sync-0", "test-dag"),\n                ("dag-bulk-sync-0", "test-dag2"),\n                ("dag-bulk-sync-1", "test-dag"),\n                ("dag-bulk-sync-1", "test-dag2"),\n                ("dag-bulk-sync-2", "test-dag"),\n                ("dag-bulk-sync-2", "test-dag2"),\n                ("dag-bulk-sync-3", "test-dag"),\n                ("dag-bulk-sync-3", "test-dag2"),\n            } == set(session.execute(select(DagTag.dag_id, DagTag.name)).all())\n        # Removing tags\n        for dag in dags:\n            dag.tags.remove("test-dag")\n        with assert_queries_count(10):\n            SerializedDAG.bulk_write_to_db("testing", None, dags)\n        with create_session() as session:\n            assert {"dag-bulk-sync-0", "dag-bulk-sync-1", "dag-bulk-sync-2", "dag-bulk-sync-3"} == {\n                row[0] for row in session.execute(select(DagModel.dag_id)).all()\n            }\n            assert {\n                ("dag-bulk-sync-0", "test-dag2"),\n                ("dag-bulk-sync-1", "test-dag2"),\n                ("dag-bulk-sync-2", "test-dag2"),\n                ("dag-bulk-sync-3", "test-dag2"),\n            } == set(session.execute(select(DagTag.dag_id, DagTag.name)).all())\n\n            for row in session.execute(select(DagModel.last_parsed_time)).all():\n                assert row[0] is not None\n\n        # Removing all tags\n        for dag in dags:\n            dag.tags = set()\n        with assert_queries_count(10):\n            SerializedDAG.bulk_write_to_db("testing", None, dags)\n        with create_session() as session:\n            assert {"dag-bulk-sync-0", "dag-bulk-sync-1", "dag-bulk-sync-2", "dag-bulk-sync-3"} == {\n                row[0] for row in session.execute(select(DagModel.dag_id)).all()\n            }\n            assert not set(session.execute(select(DagTag.dag_id, DagTag.name)).all())\n\n            for row in session.execute(select(DagModel.last_parsed_time)).all():\n                assert row[0] is not None\n\n    def test_bulk_write_to_db_single_dag(self, testing_dag_bundle):\n        """\n        Test bulk_write_to_db for a single dag using the index optimized query\n        """\n        clear_db_dags()\n        dags = [\n            create_scheduler_dag(\n                DAG(f"dag-bulk-sync-{i}", schedule=None, start_date=DEFAULT_DATE, tags=["test-dag"])\n            )\n            for i in range(1)\n        ]\n\n        with assert_queries_count(6):\n            SerializedDAG.bulk_write_to_db("testing", None, dags)\n        with create_session() as session:\n            assert {"dag-bulk-sync-0"} == {row[0] for row in session.execute(select(DagModel.dag_id)).all()}\n            assert {\n                ("dag-bulk-sync-0", "test-dag"),\n            } == set(session.execute(select(DagTag.dag_id, DagTag.name)).all())\n\n            for row in session.execute(select(DagModel.last_parsed_time)).all():\n                assert row[0] is not None\n\n        # Re-sync should do fewer queries\n        with assert_queries_count(8):\n            SerializedDAG.bulk_write_to_db("testing", None, dags)\n        with assert_queries_count(8):\n            SerializedDAG.bulk_write_to_db("testing", None, dags)\n\n    def test_bulk_write_to_db_multiple_dags(self, testing_dag_bundle):\n        """\n        Test bulk_write_to_db for multiple dags which does not use the index optimized query\n        """\n        clear_db_dags()\n        dags = [\n            create_scheduler_dag(\n                DAG(f"dag-bulk-sync-{i}", schedule=None, start_date=DEFAULT_DATE, tags=["test-dag"])\n            )\n            for i in range(4)\n        ]\n\n        with assert_queries_count(6):\n            SerializedDAG.bulk_write_to_db("testing", None, dags)\n        with create_session() as session:\n            assert {"dag-bulk-sync-0", "dag-bulk-sync-1", "dag-bulk-sync-2", "dag-bulk-sync-3"} == {\n                row[0] for row in session.execute(select(DagModel.dag_id)).all()\n            }\n            assert {\n                ("dag-bulk-sync-0", "test-dag"),\n                ("dag-bulk-sync-1", "test-dag"),\n                ("dag-bulk-sync-2", "test-dag"),\n                ("dag-bulk-sync-3", "test-dag"),\n            } == set(session.execute(select(DagTag.dag_id, DagTag.name)).all())\n\n            for row in session.execute(select(DagModel.last_parsed_time)).all():\n                assert row[0] is not None\n\n        # Re-sync should do fewer queries\n        with assert_queries_count(9):\n            SerializedDAG.bulk_write_to_db("testing", None, dags)\n        with assert_queries_count(9):\n            SerializedDAG.bulk_write_to_db("testing", None, dags)\n\n    @pytest.mark.parametrize("interval", [None, "@daily"])\n    def test_bulk_write_to_db_interval_save_runtime(self, testing_dag_bundle, interval):\n        mock_active_runs_of_dags = mock.MagicMock(side_effect=DagRun.active_runs_of_dags)\n        with mock.patch.object(DagRun, "active_runs_of_dags", mock_active_runs_of_dags):\n            dags_null_timetable = [\n                create_scheduler_dag(DAG("dag-interval-None", schedule=None, start_date=TEST_DATE)),\n                create_scheduler_dag(DAG("dag-interval-test", schedule=interval, start_date=TEST_DATE)),\n            ]\n            SerializedDAG.bulk_write_to_db("testing", None, dags_null_timetable)\n            if interval:\n                mock_active_runs_of_dags.assert_called_once()\n            else:\n                mock_active_runs_of_dags.assert_not_called()\n\n    @pytest.mark.parametrize(\n        ("state", "catchup", "expected_next_dagrun"),\n        [\n            # With catchup=True, next_dagrun is the start date\n            (DagRunState.RUNNING, True, DEFAULT_DATE),\n            (DagRunState.QUEUED, True, DEFAULT_DATE),\n            # With catchup=False, next_dagrun is based on the current date\n            (DagRunState.RUNNING, False, None),  # None means we\'ll use current date\n            (DagRunState.QUEUED, False, None),\n        ],\n    )\n    def test_bulk_write_to_db_max_active_runs(self, testing_dag_bundle, state, catchup, expected_next_dagrun):\n        """\n        Test that DagModel.next_dagrun_create_after is set to NULL when the dag cannot be created due to max\n        active runs being hit. Tests both catchup=True and catchup=False scenarios.\n        """\n        dag = DAG(\n            dag_id="test_scheduler_verify_max_active_runs",\n            schedule=timedelta(days=1),\n            start_date=DEFAULT_DATE,\n            catchup=catchup,\n        )\n        dag.max_active_runs = 1\n        EmptyOperator(task_id="dummy", dag=dag, owner="airflow")\n\n        scheduler_dag = sync_dag_to_db(dag)\n        scheduler_dag.clear()\n\n        session = settings.Session()\n        model = session.get(DagModel, dag.dag_id)\n        current_time = timezone.utcnow()\n\n        if expected_next_dagrun is None:\n            # For catchup=False, next_dagrun will be around the current date (not DEFAULT_DATE)\n            # Instead of comparing exact dates, verify it\'s relatively recent and not the old start date\n\n            # Verify it\'s not using the old DEFAULT_DATE from 2016 and is after\n            # that since we are picking up present date.\n            assert model.next_dagrun.year >= DEFAULT_DATE.year\n            assert model.next_dagrun.month >= DEFAULT_DATE.month\n\n            # Verify the date is within a reasonable range of the current date\n            # (allowing for timezone differences and scheduling details)\n            assert abs((model.next_dagrun - current_time).days) <= 31  # Within the current month\n\n            # Most importantly, verify it\'s not the default date\n            assert model.next_dagrun != DEFAULT_DATE\n\n            # Verify next_dagrun_create_after is scheduled after next_dagrun\n            assert model.next_dagrun_create_after > model.next_dagrun\n        else:\n            # For catchup=True, next_dagrun is the start date\n            assert model.next_dagrun == expected_next_dagrun\n            assert model.next_dagrun_create_after == expected_next_dagrun + timedelta(days=1)\n\n        assert model.exceeds_max_non_backfill is False\n\n        dr = scheduler_dag.create_dagrun(\n            run_id="test",\n            state=state,\n            logical_date=model.next_dagrun,\n            run_type=DagRunType.SCHEDULED,\n            session=session,\n            data_interval=(model.next_dagrun, model.next_dagrun),\n            run_after=model.next_dagrun_create_after,\n            triggered_by=DagRunTriggeredByType.TEST,\n        )\n        assert dr is not None\n        SerializedDAG.bulk_write_to_db("testing", None, [dag])\n        model = session.get(DagModel, dag.dag_id)\n        # Check that exceeds_max_non_backfill is set correctly\n        assert model.exceeds_max_non_backfill is True\n        # Check that running bulk_write_to_db again doesn\'t change exceeds_max_non_backfill\n        SerializedDAG.bulk_write_to_db("testing", None, [dag])\n        model = session.get(DagModel, dag.dag_id)\n        assert model.exceeds_max_non_backfill is True\n\n        if catchup is True:\n            assert model.next_dagrun_create_after == DEFAULT_DATE + timedelta(days=1)\n        else:\n            assert model.next_dagrun_create_after > current_time + timedelta(days=-2)  # allow for fuzz\n\n    def test_bulk_write_to_db_has_import_error(self, testing_dag_bundle):\n        """\n        Test that DagModel.has_import_error is set to false if no import errors.\n        """\n        dag = DAG(dag_id="test_has_import_error", schedule=None, start_date=DEFAULT_DATE)\n        EmptyOperator(task_id="dummy", dag=dag, owner="airflow")\n\n        session = settings.Session()\n        scheduler_dag = sync_dag_to_db(dag, session=session)\n        scheduler_dag.clear()\n\n        model = session.get(DagModel, dag.dag_id)\n\n        assert not model.has_import_errors\n\n        # Simulate Dagfileprocessor setting the import error to true\n        model.has_import_errors = True\n        session.merge(model)\n        session.flush()\n        model = session.get(DagModel, dag.dag_id)\n        # assert\n        assert model.has_import_errors\n        # parse\n        SerializedDAG.bulk_write_to_db("testing", None, [dag])\n\n        model = session.get(DagModel, dag.dag_id)\n        # assert that has_import_error is now false\n        assert not model.has_import_errors\n        session.close()\n\n    def test_bulk_write_to_db_assets(self, testing_dag_bundle):\n        """\n        Ensure that assets referenced in a dag are correctly loaded into the database.\n        """\n        dag_id1 = "test_asset_dag1"\n        dag_id2 = "test_asset_dag2"\n\n        task_id = "test_asset_task"\n\n        uri1 = "s3://asset/1"\n        a1 = Asset(uri=uri1, name="test_asset_1", extra={"not": "used"}, group="test-group")\n        a2 = Asset(uri="s3://asset/2", name="test_asset_2", group="test-group")\n        a3 = Asset(uri="s3://asset/3", name="test_asset-3", group="test-group")\n\n        dag1 = DAG(dag_id=dag_id1, start_date=DEFAULT_DATE, schedule=[a1])\n        EmptyOperator(task_id=task_id, dag=dag1, outlets=[a2, a3])\n\n        dag2 = DAG(dag_id=dag_id2, start_date=DEFAULT_DATE, schedule=None)\n        EmptyOperator(\n            task_id=task_id,\n            dag=dag2,\n            outlets=[Asset(uri=uri1, name="test_asset_1", extra={"should": "be used"}, group="test-group")],\n        )\n\n        session = settings.Session()\n        create_scheduler_dag(dag1).clear()\n        SerializedDAG.bulk_write_to_db("testing", None, [dag1, dag2], session=session)\n        session.commit()\n        stored_assets = {x.uri: x for x in session.scalars(select(AssetModel)).all()}\n        asset1_orm = stored_assets[a1.uri]\n        asset2_orm = stored_assets[a2.uri]\n        asset3_orm = stored_assets[a3.uri]\n        assert stored_assets[uri1].extra == {"should": "be used"}\n        assert [x.dag_id for x in asset1_orm.scheduled_dags] == [dag_id1]\n        assert [(x.task_id, x.dag_id) for x in asset1_orm.producing_tasks] == [(task_id, dag_id2)]\n        assert set(\n            session.execute(\n                select(\n                    TaskOutletAssetReference.task_id,\n                    TaskOutletAssetReference.dag_id,\n                    TaskOutletAssetReference.asset_id,\n                ).where(TaskOutletAssetReference.dag_id.in_((dag_id1, dag_id2)))\n            ).all()\n        ) == {\n            (task_id, dag_id1, asset2_orm.id),\n            (task_id, dag_id1, asset3_orm.id),\n            (task_id, dag_id2, asset1_orm.id),\n        }\n\n        # now that we have verified that a new dag has its asset references recorded properly,\n        # we need to verify that *changes* are recorded properly.\n        # so if any references are *removed*, they should also be deleted from the DB\n        # so let\'s remove some references and see what happens\n        dag1 = DAG(dag_id=dag_id1, start_date=DEFAULT_DATE, schedule=None)\n        EmptyOperator(task_id=task_id, dag=dag1, outlets=[a2])\n        dag2 = DAG(dag_id=dag_id2, start_date=DEFAULT_DATE, schedule=None)\n        EmptyOperator(task_id=task_id, dag=dag2)\n\n        SerializedDAG.bulk_write_to_db("testing", None, [dag1, dag2], session=session)\n        session.commit()\n        session.expunge_all()\n        stored_assets = {x.uri: x for x in session.scalars(select(AssetModel)).all()}\n        asset1_orm = stored_assets[a1.uri]\n        asset2_orm = stored_assets[a2.uri]\n        assert [x.dag_id for x in asset1_orm.scheduled_dags] == []\n        assert set(\n            session.execute(\n                select(\n                    TaskOutletAssetReference.task_id,\n                    TaskOutletAssetReference.dag_id,\n                    TaskOutletAssetReference.asset_id,\n                ).where(TaskOutletAssetReference.dag_id.in_((dag_id1, dag_id2)))\n            ).all()\n        ) == {(task_id, dag_id1, asset2_orm.id)}\n\n    def test_bulk_write_to_db_asset_aliases(self, testing_dag_bundle):\n        """\n        Ensure that asset aliases referenced in a dag are correctly loaded into the database.\n        """\n        dag_id1 = "test_asset_alias_dag1"\n        dag_id2 = "test_asset_alias_dag2"\n        task_id = "test_asset_task"\n        asset_alias_1 = AssetAlias(name="asset_alias_1")\n        asset_alias_2 = AssetAlias(name="asset_alias_2")\n        asset_alias_2_2 = AssetAlias(name="asset_alias_2")\n        asset_alias_3 = AssetAlias(name="asset_alias_3")\n        dag1 = DAG(dag_id=dag_id1, start_date=DEFAULT_DATE, schedule=None)\n        EmptyOperator(task_id=task_id, dag=dag1, outlets=[asset_alias_1, asset_alias_2, asset_alias_3])\n        dag2 = DAG(dag_id=dag_id2, start_date=DEFAULT_DATE, schedule=None)\n        EmptyOperator(task_id=task_id, dag=dag2, outlets=[asset_alias_2_2, asset_alias_3])\n\n        session = settings.Session()\n        SerializedDAG.bulk_write_to_db("testing", None, [dag1, dag2], session=session)\n        session.commit()\n\n        stored_asset_alias_models = {x.name: x for x in session.scalars(select(AssetAliasModel)).all()}\n        asset_alias_1_orm = stored_asset_alias_models[asset_alias_1.name]\n        asset_alias_2_orm = stored_asset_alias_models[asset_alias_2.name]\n        asset_alias_3_orm = stored_asset_alias_models[asset_alias_3.name]\n        assert asset_alias_1_orm.name == "asset_alias_1"\n        assert asset_alias_2_orm.name == "asset_alias_2"\n        assert asset_alias_3_orm.name == "asset_alias_3"\n        assert len(stored_asset_alias_models) == 3\n\n    @mock.patch.dict(\n        os.environ,\n        {\n            "AIRFLOW__CORE__MAX_CONSECUTIVE_FAILED_DAG_RUNS_PER_DAG": "4",\n        },\n    )\n    def test_existing_dag_is_paused_config(self):\n        # config should be set properly\n        assert conf.getint("core", "max_consecutive_failed_dag_runs_per_dag") == 4\n        # checking the default value is coming from config\n        dag = DAG("test_dag", schedule=None)\n        assert dag.max_consecutive_failed_dag_runs == 4\n        # but we can override the value using params\n        dag = DAG("test_dag2", schedule=None, max_consecutive_failed_dag_runs=2)\n        assert dag.max_consecutive_failed_dag_runs == 2\n\n    def test_existing_dag_is_paused_after_limit(self, testing_dag_bundle):\n        def add_failed_dag_run(dag, id, logical_date):\n            dr = dag.create_dagrun(\n                run_type=DagRunType.MANUAL,\n                run_id="run_id_" + id,\n                logical_date=logical_date,\n                state=State.FAILED,\n                data_interval=(logical_date, logical_date),\n                run_after=logical_date,\n                triggered_by=DagRunTriggeredByType.TEST,\n                session=session,\n            )\n            ti_op1 = dr.get_task_instance(task_id=op1.task_id, session=session)\n            ti_op1.set_state(state=TaskInstanceState.FAILED, session=session)\n            dr.update_state(session=session)\n\n        dag_id = "dag_paused_after_limit"\n        dag = DAG(dag_id, schedule=None, is_paused_upon_creation=False, max_consecutive_failed_dag_runs=2)\n        op1 = BashOperator(task_id="task", bash_command="exit 1;")\n        dag.add_task(op1)\n        session = settings.Session()\n        orm_dag = DagModel(\n            dag_id=dag.dag_id,\n            bundle_name="testing",\n            is_stale=False,\n        )\n        session.add(orm_dag)\n        session.flush()\n\n        scheduler_dag = sync_dag_to_db(dag, session=session)\n        assert not session.get(DagModel, dag.dag_id).is_paused\n\n        # dag should be paused after 2 failed dag_runs\n        add_failed_dag_run(scheduler_dag, "1", TEST_DATE)\n        add_failed_dag_run(scheduler_dag, "2", TEST_DATE + timedelta(days=1))\n        assert session.get(DagModel, dag.dag_id).is_paused\n\n    def test_dag_is_deactivated_upon_dagfile_deletion(self, dag_maker):\n        dag_id = "old_existing_dag"\n        with dag_maker(dag_id, schedule=None, is_paused_upon_creation=True) as dag:\n            ...\n        session = settings.Session()\n        sync_dag_to_db(dag, session=session)\n\n        orm_dag = session.scalar(select(DagModel).where(DagModel.dag_id == dag_id))\n\n        assert not orm_dag.is_stale\n\n        DagModel.deactivate_deleted_dags(\n            bundle_name=orm_dag.bundle_name,\n            rel_filelocs=list_py_file_paths(settings.DAGS_FOLDER),\n        )\n\n        orm_dag = session.scalar(select(DagModel).where(DagModel.dag_id == dag_id))\n        assert orm_dag.is_stale\n\n        session.execute(delete(DagModel).where(DagModel.dag_id == dag_id))\n        session.close()\n\n    def test_dag_naive_default_args_start_date_with_timezone(self):\n        local_tz = pendulum.timezone("Europe/Zurich")\n        default_args = {"start_date": datetime.datetime(2018, 1, 1, tzinfo=local_tz)}\n\n        dag = DAG("DAG", schedule=None, default_args=default_args)\n        assert dag.timezone.name == local_tz.name\n\n        dag = DAG("DAG", schedule=None, default_args=default_args)\n        assert dag.timezone.name == local_tz.name\n\n    def test_schedule_dag_no_previous_runs(self, testing_dag_bundle):\n        """\n        Tests scheduling a dag with no previous runs\n        """\n        dag_id = "test_schedule_dag_no_previous_runs"\n        dag = DAG(dag_id=dag_id, schedule=None)\n        dag.add_task(BaseOperator(task_id="faketastic", owner="Also fake", start_date=TEST_DATE))\n\n        scheduler_dag = sync_dag_to_db(dag)\n        dag_run = scheduler_dag.create_dagrun(\n            run_id="test",\n            run_type=DagRunType.SCHEDULED,\n            logical_date=TEST_DATE,\n            state=State.RUNNING,\n            data_interval=(TEST_DATE, TEST_DATE),\n            run_after=TEST_DATE,\n            triggered_by=DagRunTriggeredByType.TEST,\n        )\n        assert dag_run is not None\n        assert dag.dag_id == dag_run.dag_id\n        assert dag_run.run_id is not None\n        assert dag_run.run_id != ""\n        assert dag_run.logical_date == TEST_DATE, (\n            f"dag_run.logical_date did not match expectation: {dag_run.logical_date}"\n        )\n        assert dag_run.state == State.RUNNING\n        assert dag_run.run_type != DagRunType.MANUAL\n\n    @patch("airflow.models.dagrun.Stats")\n    def test_dag_handle_callback_crash(self, mock_stats, testing_dag_bundle):\n        """\n        Tests avoid crashes from calling dag callbacks exceptions\n        """\n        dag_id = "test_dag_callback_crash"\n        mock_callback_with_exception = mock.MagicMock()\n        mock_callback_with_exception.side_effect = Exception\n        dag = DAG(\n            dag_id=dag_id,\n            schedule=None,\n            # callback with invalid signature should not cause crashes\n            on_success_callback=lambda: 1,\n            on_failure_callback=mock_callback_with_exception,\n        )\n        when = TEST_DATE\n        dag.add_task(BaseOperator(task_id="faketastic", owner="Also fake", start_date=when))\n\n        scheduler_dag = sync_dag_to_db(dag)\n\n        with create_session() as session:\n            dag_run = scheduler_dag.create_dagrun(\n                run_id="test",\n                state=State.RUNNING,\n                logical_date=when,\n                run_type=DagRunType.MANUAL,\n                session=session,\n                data_interval=(when, when),\n                run_after=when,\n                triggered_by=DagRunTriggeredByType.TEST,\n            )\n\n            # should not raise any exception\n        dag_run.execute_dag_callbacks(dag=dag, success=False)\n        dag_run.execute_dag_callbacks(dag=dag, success=True)\n\n        mock_stats.incr.assert_called_with(\n            "dag.callback_exceptions",\n            tags={"dag_id": "test_dag_callback_crash"},\n        )\n\n    def test_dag_handle_callback_with_removed_task(self, dag_maker, session, testing_dag_bundle):\n        """\n        Tests avoid crashes when a removed task is the last one in the list of task instance\n        """\n        dag_id = "test_dag_callback_with_removed_task"\n        mock_callback = mock.MagicMock()\n        with DAG(\n            dag_id=dag_id,\n            schedule=None,\n            on_success_callback=mock_callback,\n            on_failure_callback=mock_callback,\n        ) as dag:\n            EmptyOperator(task_id="faketastic")\n            task_removed = EmptyOperator(task_id="removed_task")\n\n        scheduler_dag = sync_dag_to_db(dag)\n        with create_session() as session:\n            dag_run = scheduler_dag.create_dagrun(\n                run_id="test",\n                state=State.RUNNING,\n                logical_date=TEST_DATE,\n                run_type=DagRunType.MANUAL,\n                session=session,\n                data_interval=(TEST_DATE, TEST_DATE),\n                run_after=TEST_DATE,\n                triggered_by=DagRunTriggeredByType.TEST,\n            )\n            dag._remove_task(task_removed.task_id)\n            tis = dag_run.get_task_instances(session=session)\n            tis[-1].state = TaskInstanceState.REMOVED\n            assert dag_run.get_task_instance(task_removed.task_id).state == TaskInstanceState.REMOVED\n\n            # should not raise any exception\n            dag_run.execute_dag_callbacks(dag=dag, success=False)\n            dag_run.execute_dag_callbacks(dag=dag, success=True)\n\n    @time_machine.travel(timezone.datetime(2025, 11, 11))\n    @pytest.mark.parametrize(("catchup", "expected_next_dagrun"), [(True, DEFAULT_DATE), (False, None)])\n    def test_next_dagrun_after_fake_scheduled_previous(\n        self, catchup, expected_next_dagrun, testing_dag_bundle\n    ):\n        """\n        Test scheduling a dag where there is a prior DagRun\n        which has the same run_id as the next run should have.\n        Tests with both catchup=True and catchup=False to verify different behaviors.\n        """\n        delta = datetime.timedelta(hours=1)\n        dag_id = f"test_schedule_dag_fake_scheduled_previous_{catchup}"\n        dag = DAG(dag_id=dag_id, schedule=delta, start_date=DEFAULT_DATE, catchup=catchup)\n        dag.add_task(BaseOperator(task_id="faketastic", owner="Also fake", start_date=DEFAULT_DATE))\n\n        session = settings.Session()\n        orm_dag = DagModel(\n            dag_id=dag.dag_id,\n            bundle_name="testing",\n            is_stale=False,\n        )\n        session.add(orm_dag)\n        session.flush()\n\n        _create_dagrun(\n            dag,\n            run_type=DagRunType.SCHEDULED,\n            logical_date=DEFAULT_DATE,\n            state=State.SUCCESS,\n            data_interval=(DEFAULT_DATE, DEFAULT_DATE),\n        )\n        sync_dag_to_db(dag)\n        with create_session() as session:\n            model = session.get(DagModel, dag.dag_id)\n\n        if expected_next_dagrun is None:\n            # Verify it\'s not using the old default date\n            assert model.next_dagrun.year == 2025\n            assert model.next_dagrun.month == 11\n            # Verify next_dagrun_create_after is scheduled after next_dagrun\n            assert model.next_dagrun_create_after > model.next_dagrun\n        else:\n            # For catchup=True, even though there is a run for this date already,\n            # it is marked as manual/external, so we should create a scheduled one anyway!\n            assert model.next_dagrun == expected_next_dagrun\n            assert model.next_dagrun_create_after == expected_next_dagrun + delta\n\n    def test_schedule_dag_once(self, testing_dag_bundle):\n        """\n        Tests scheduling a dag scheduled for @once - should be scheduled the first time\n        it is called, and not scheduled the second.\n        """\n        dag_id = "test_schedule_dag_once"\n        with DAG(dag_id=dag_id, schedule="@once", start_date=TEST_DATE) as dag:\n            BaseOperator(task_id="faketastic", owner="Also fake", start_date=TEST_DATE)\n        assert qualname(dag.timetable) == "airflow.sdk.definitions.timetables.simple.OnceTimetable"\n\n        _create_dagrun(\n            dag,\n            run_type=DagRunType.SCHEDULED,\n            logical_date=TEST_DATE,\n            state=State.SUCCESS,\n            data_interval=(TEST_DATE, TEST_DATE),\n        )\n\n        # Then sync again after creating the dag run -- this should update next_dagrun\n        SerializedDAG.bulk_write_to_db("testing", None, [dag])\n        with create_session() as session:\n            model = session.get(DagModel, dag.dag_id)\n\n        assert model.next_dagrun is None\n        assert model.next_dagrun_create_after is None\n\n    def test_fractional_seconds(self):\n        """\n        Tests if fractional seconds are stored in the database\n        """\n        dag_id = "test_fractional_seconds"\n        dag = DAG(dag_id=dag_id, schedule="@once", start_date=TEST_DATE)\n        dag.add_task(BaseOperator(task_id="faketastic", owner="Also fake", start_date=TEST_DATE))\n\n        start_date = timezone.utcnow()\n\n        run = _create_dagrun(\n            dag,\n            run_type=DagRunType.MANUAL,\n            logical_date=start_date,\n            start_date=start_date,\n            state=State.RUNNING,\n            data_interval=(start_date, start_date),\n        )\n\n        run.refresh_from_db()\n\n        assert start_date == run.logical_date, "dag run logical_date loses precision"\n        assert start_date == run.start_date, "dag run start_date loses precision "\n\n    def test_rich_comparison_ops(self):\n        test_dag_id = "test_rich_comparison_ops"\n\n        class DAGsubclass(DAG):\n            pass\n\n        args = {"owner": "airflow", "start_date": DEFAULT_DATE}\n        dag = DAG(test_dag_id, schedule=None, default_args=args)\n\n        dag_eq = DAG(test_dag_id, schedule=None, default_args=args)\n\n        dag_diff_name = DAG(test_dag_id + "_neq", schedule=None, default_args=args)\n\n        dag_subclass = DAGsubclass(test_dag_id, schedule=None, default_args=args)\n        dag_subclass_diff_name = DAGsubclass(test_dag_id + "2", schedule=None, default_args=args)\n\n        # test identity equality\n        assert dag == dag\n\n        # test dag (in)equality based on _comps\n        assert dag_eq == dag\n        assert dag_diff_name != dag\n\n        # test dag inequality based on type even if _comps happen to match\n        assert dag_subclass != dag\n\n        # a dag should equal an unpickled version of itself\n        dump = pickle.dumps(dag)\n        assert pickle.loads(dump) == dag\n\n        # dags are ordered based on dag_id no matter what the type is\n        assert dag < dag_diff_name\n        assert dag < dag_subclass_diff_name\n\n        # greater than should have been created automatically by functools\n        assert dag_diff_name > dag\n\n        # hashes are non-random and match equality\n        assert hash(dag) == hash(dag)\n        assert hash(dag_eq) == hash(dag)\n        assert hash(dag_diff_name) != hash(dag)\n        assert hash(dag_subclass) != hash(dag)\n\n    def test_get_paused_dag_ids(self, testing_dag_bundle):\n        dag_id = "test_get_paused_dag_ids"\n        dag = DAG(dag_id, schedule=None, is_paused_upon_creation=True)\n        session = settings.Session()\n        orm_dag = DagModel(\n            dag_id=dag.dag_id,\n            bundle_name="testing",\n            is_stale=False,\n            is_paused=True,  # Set is_paused to match DAG\'s is_paused_upon_creation\n        )\n        session.add(orm_dag)\n        session.flush()\n        sync_dag_to_db(dag)\n        assert DagModel.get_dagmodel(dag_id) is not None\n\n        paused_dag_ids = DagModel.get_paused_dag_ids([dag_id])\n        assert paused_dag_ids == {dag_id}\n\n        with create_session() as session:\n            session.execute(delete(DagModel).where(DagModel.dag_id == dag_id))\n\n    @pytest.mark.parametrize(\n        ("schedule_arg", "expected_timetable", "interval_description"),\n        [\n            (None, NullTimetable(), "Never, external triggers only"),\n            ("@daily", cron_timetable("0 0 * * *"), "At 00:00"),\n            ("@weekly", cron_timetable("0 0 * * 0"), "At 00:00, only on Sunday"),\n            ("@monthly", cron_timetable("0 0 1 * *"), "At 00:00, on day 1 of the month"),\n            ("@quarterly", cron_timetable("0 0 1 */3 *"), "At 00:00, on day 1 of the month, every 3 months"),\n            ("@yearly", cron_timetable("0 0 1 1 *"), "At 00:00, on day 1 of the month, only in January"),\n            ("5 0 * 8 *", cron_timetable("5 0 * 8 *"), "At 00:05, only in August"),\n            ("@once", OnceTimetable(), "Once, as soon as possible"),\n            (datetime.timedelta(days=1), delta_timetable(datetime.timedelta(days=1)), ""),\n            ("30 21 * * 5 1", cron_timetable("30 21 * * 5 1"), ""),\n        ],\n    )\n    def test_timetable_and_description_from_schedule_arg(\n        self, schedule_arg, expected_timetable, interval_description\n    ):\n        dag = DAG("test_schedule_arg", schedule=schedule_arg, start_date=TEST_DATE)\n        assert dag.timetable == expected_timetable\n        assert coerce_to_core_timetable(dag.timetable).description == interval_description\n\n    def test_timetable_and_description_from_asset(self):\n        uri = "test://asset"\n        dag = DAG(\n            "test_schedule_interval_arg", schedule=[Asset(uri=uri, group="test-group")], start_date=TEST_DATE\n        )\n        assert dag.timetable == AssetTriggeredTimetable(Asset(uri=uri, group="test-group"))\n        assert coerce_to_core_timetable(dag.timetable).description == "Triggered by assets"\n\n    @pytest.mark.parametrize(\n        ("timetable", "expected_description"),\n        [\n            (NullTimetable(), "Never, external triggers only"),\n            (cron_timetable("0 0 * * *"), "At 00:00"),\n            (cron_timetable("@daily"), "At 00:00"),\n            (cron_timetable("0 0 * * 0"), "At 00:00, only on Sunday"),\n            (cron_timetable("@weekly"), "At 00:00, only on Sunday"),\n            (cron_timetable("0 0 1 * *"), "At 00:00, on day 1 of the month"),\n            (cron_timetable("@monthly"), "At 00:00, on day 1 of the month"),\n            (cron_timetable("0 0 1 */3 *"), "At 00:00, on day 1 of the month, every 3 months"),\n            (cron_timetable("@quarterly"), "At 00:00, on day 1 of the month, every 3 months"),\n            (cron_timetable("0 0 1 1 *"), "At 00:00, on day 1 of the month, only in January"),\n            (cron_timetable("@yearly"), "At 00:00, on day 1 of the month, only in January"),\n            (cron_timetable("5 0 * 8 *"), "At 00:05, only in August"),\n            (OnceTimetable(), "Once, as soon as possible"),\n            (delta_timetable(datetime.timedelta(days=1)), ""),\n            (cron_timetable("30 21 * * 5 1"), ""),\n        ],\n    )\n    def test_description_from_timetable(self, timetable, expected_description):\n        dag = DAG("test_schedule_description", schedule=timetable, start_date=TEST_DATE)\n        assert dag.timetable == timetable\n        assert coerce_to_core_timetable(dag.timetable).description == expected_description\n\n    def test_create_dagrun_job_id_is_set(self, testing_dag_bundle):\n        job_id = 42\n        dag = DAG(dag_id="test_create_dagrun_job_id_is_set", schedule=None)\n        scheduler_dag = sync_dag_to_db(dag)\n        dr = scheduler_dag.create_dagrun(\n            run_id="test_create_dagrun_job_id_is_set",\n            logical_date=DEFAULT_DATE,\n            data_interval=(DEFAULT_DATE, DEFAULT_DATE),\n            run_after=DEFAULT_DATE,\n            run_type=DagRunType.MANUAL,\n            state=State.NONE,\n            creating_job_id=job_id,\n            triggered_by=DagRunTriggeredByType.TEST,\n        )\n        assert dr.creating_job_id == job_id\n\n    def test_create_dagrun_note_is_set(self, testing_dag_bundle):\n        note = "This is a test note"\n        dag = DAG(dag_id="test_create_dagrun_note_is_set", schedule=None)\n        scheduler_dag = sync_dag_to_db(dag)\n        dr = scheduler_dag.create_dagrun(\n            run_id="test_create_dagrun_note_is_set",\n            logical_date=DEFAULT_DATE,\n            data_interval=(DEFAULT_DATE, DEFAULT_DATE),\n            run_after=DEFAULT_DATE,\n            run_type=DagRunType.MANUAL,\n            state=State.NONE,\n            note=note,\n            triggered_by=DagRunTriggeredByType.TEST,\n        )\n        assert dr.note == note\n\n    @pytest.mark.parametrize("partition_key", [None, "my-key", 123])\n    def test_create_dagrun_partition_key(self, partition_key, dag_maker):\n        with dag_maker("test_create_dagrun_partition_key"):\n            ...\n        cm = nullcontext()\n        if isinstance(partition_key, int):\n            cm = pytest.raises(ValueError, match="Expected partition_key to be `str` | `None` but got `int`")\n        with cm:\n            dr = dag_maker.create_dagrun(\n                run_id="test_create_dagrun_partition_key",\n                run_after=DEFAULT_DATE,\n                run_type=DagRunType.MANUAL,\n                state=State.NONE,\n                triggered_by=DagRunTriggeredByType.TEST,\n                partition_key=partition_key,\n            )\n            assert dr.partition_key == partition_key\n\n    def test_dag_add_task_sets_default_task_group(self):\n        dag = DAG(dag_id="test_dag_add_task_sets_default_task_group", schedule=None, start_date=DEFAULT_DATE)\n        task_without_task_group = EmptyOperator(task_id="task_without_group_id")\n        default_task_group = TaskGroupContext.get_current(dag)\n        dag.add_task(task_without_task_group)\n        assert default_task_group.get_child_by_label("task_without_group_id") == task_without_task_group\n\n        task_group = TaskGroup(group_id="task_group", dag=dag)\n        task_with_task_group = EmptyOperator(task_id="task_with_task_group", task_group=task_group)\n        dag.add_task(task_with_task_group)\n        assert task_group.get_child_by_label("task_with_task_group") == task_with_task_group\n        assert dag.get_task("task_group.task_with_task_group") == task_with_task_group\n\n    @pytest.mark.parametrize("dag_run_state", [DagRunState.QUEUED, DagRunState.RUNNING])\n    @pytest.mark.need_serialized_dag\n    def test_clear_set_dagrun_state(self, dag_run_state, dag_maker, session):\n        dag_id = "test_clear_set_dagrun_state"\n\n        with dag_maker(dag_id, start_date=DEFAULT_DATE, max_active_runs=1) as dag:\n            task_id = "t1"\n            EmptyOperator(task_id=task_id)\n\n        dr = dag_maker.create_dagrun(\n            run_type=DagRunType.BACKFILL_JOB,\n            state=State.FAILED,\n            start_date=DEFAULT_DATE,\n            logical_date=DEFAULT_DATE,\n            session=session,\n        )\n        session.commit()\n        session.refresh(dr)\n        assert dr.state == "failed"\n\n        dag.clear(\n            start_date=DEFAULT_DATE,\n            end_date=DEFAULT_DATE + datetime.timedelta(days=1),\n            dag_run_state=dag_run_state,\n            session=session,\n        )\n        session.refresh(dr)\n        assert dr.state == dag_run_state\n\n    @pytest.mark.parametrize("dag_run_state", [DagRunState.QUEUED, DagRunState.RUNNING])\n    def test_clear_set_dagrun_state_for_mapped_task(self, session, dag_run_state, dag_maker):\n        dag_id = "test_clear_set_dagrun_state"\n\n        task_id = "t1"\n\n        with dag_maker(\n            dag_id, schedule=None, start_date=DEFAULT_DATE, max_active_runs=1, serialized=True\n        ) as dag:\n\n            @task_decorator\n            def make_arg_lists():\n                return [[1], [2], [{"a": "b"}]]\n\n            def consumer(value):\n                print(value)\n\n            PythonOperator.partial(task_id=task_id, python_callable=consumer).expand(op_args=make_arg_lists())\n\n        dagrun_1 = dag_maker.create_dagrun(\n            run_type=DagRunType.BACKFILL_JOB,\n            state=DagRunState.FAILED,\n            start_date=DEFAULT_DATE,\n            logical_date=DEFAULT_DATE,\n            data_interval=(DEFAULT_DATE, DEFAULT_DATE),\n            session=session,\n        )\n\n        # Get the (de)serialized MappedOperator\n        mapped = dag.get_task(task_id)\n        expand_mapped_task(mapped, dagrun_1.run_id, "make_arg_lists", length=2, session=session)\n\n        upstream_ti = dagrun_1.get_task_instance("make_arg_lists", session=session)\n        ti = dagrun_1.get_task_instance(task_id, map_index=0, session=session)\n        ti2 = dagrun_1.get_task_instance(task_id, map_index=1, session=session)\n        upstream_ti.state = State.SUCCESS\n        ti.state = State.SUCCESS\n        ti2.state = State.SUCCESS\n        session.flush()\n\n        dag.clear(\n            task_ids=[(task_id, 0), ("make_arg_lists")],\n            start_date=DEFAULT_DATE,\n            end_date=DEFAULT_DATE + datetime.timedelta(days=1),\n            dag_run_state=dag_run_state,\n            session=session,\n        )\n        session.refresh(upstream_ti)\n        session.refresh(ti)\n        session.refresh(ti2)\n        assert upstream_ti.state is None  # cleared\n        assert ti.state is None  # cleared\n        assert ti2.state == State.SUCCESS  # not cleared\n        dagruns = session.scalars(select(DagRun).where(DagRun.dag_id == dag_id)).all()\n\n        assert len(dagruns) == 1\n        dagrun: DagRun = dagruns[0]\n        assert dagrun.state == dag_run_state\n\n    def test_dag_test_basic(self, testing_dag_bundle):\n        dag = DAG(dag_id="test_local_testing_conn_file", schedule=None, start_date=DEFAULT_DATE)\n        sync_dag_to_db(dag)\n\n        mock_object = mock.MagicMock()\n\n        @task_decorator\n        def check_task():\n            # we call a mock object to ensure that this task actually ran.\n            mock_object()\n\n        with dag:\n            check_task()\n        sync_dag_to_db(dag)\n\n        dag.test()\n        mock_object.assert_called_once()\n\n    def test_dag_test_with_dependencies(self, testing_dag_bundle):\n        dag = DAG(dag_id="test_local_testing_conn_file", schedule=None, start_date=DEFAULT_DATE)\n        sync_dag_to_db(dag)\n        mock_object = mock.MagicMock()\n\n        @task_decorator\n        def check_task():\n            return "output of first task"\n\n        @task_decorator\n        def check_task_2(my_input):\n            # we call a mock object to ensure that this task actually ran.\n            mock_object(my_input)\n\n        with dag:\n            check_task_2(check_task())\n        sync_dag_to_db(dag)\n\n        dag.test()\n        mock_object.assert_called_with("output of first task")\n\n    def test_dag_test_with_fail_handler(self, testing_dag_bundle):\n        mock_handle_object_1 = mock.MagicMock()\n        mock_handle_object_2 = mock.MagicMock()\n\n        def handle_task_failure(context):\n            ti = context["task_instance"]\n            mock_handle_object_1(f"task {ti.task_id} failed...")\n\n        def handle_dag_failure(context):\n            dag_id = context["dag"].dag_id\n            mock_handle_object_2(f"dag {dag_id} run failed...")\n\n        dag = DAG(\n            dag_id="test_local_testing_conn_file",\n            default_args={"on_failure_callback": handle_task_failure},\n            on_failure_callback=handle_dag_failure,\n            start_date=DEFAULT_DATE,\n            schedule=None,\n        )\n\n        mock_task_object_1 = mock.MagicMock()\n        mock_task_object_2 = mock.MagicMock()\n        sync_dag_to_db(dag)\n\n        @task_decorator\n        def check_task():\n            mock_task_object_1()\n            raise AirflowException("boooom")\n\n        @task_decorator\n        def check_task_2(my_input):\n            # we call a mock object to ensure that this task actually ran.\n            mock_task_object_2(my_input)\n\n        with dag:\n            check_task_2(check_task())\n        sync_dag_to_db(dag)\n\n        dr = dag.test()\n        ti1 = dr.get_task_instance("check_task")\n        ti2 = dr.get_task_instance("check_task_2")\n\n        assert ti1\n        assert ti2\n        assert ti1.state == TaskInstanceState.FAILED\n        assert ti2.state == TaskInstanceState.UPSTREAM_FAILED\n\n        mock_handle_object_1.assert_called_with("task check_task failed...")\n        mock_handle_object_2.assert_called_with("dag test_local_testing_conn_file run failed...")\n        mock_task_object_1.assert_called()\n        mock_task_object_2.assert_not_called()\n\n    def test_dag_connection_file(self, tmp_path, testing_dag_bundle):\n        test_connections_string = """\n---\nmy_postgres_conn:\n  - conn_id: my_postgres_conn\n    conn_type: postgres\n        """\n        dag = DAG(dag_id="test_local_testing_conn_file", schedule=None, start_date=DEFAULT_DATE)\n        sync_dag_to_db(dag)\n\n        @task_decorator\n        def check_task():\n            from airflow.configuration import secrets_backend_list\n            from airflow.secrets.local_filesystem import LocalFilesystemBackend\n\n            assert isinstance(secrets_backend_list[0], LocalFilesystemBackend)\n            local_secrets: LocalFilesystemBackend = secrets_backend_list[0]\n            assert local_secrets.get_connection("my_postgres_conn").conn_id == "my_postgres_conn"\n\n        with dag:\n            check_task()\n        path = tmp_path / "testfile.yaml"\n        path.write_text(test_connections_string)\n        dag.test(conn_file_path=os.fspath(path))\n\n    @pytest.mark.parametrize(\n        ("ti_state_begin", "ti_state_end"),\n        [\n            *((state, None) for state in State.task_states if state != TaskInstanceState.RUNNING),\n            (TaskInstanceState.RUNNING, TaskInstanceState.RESTARTING),\n        ],\n    )\n    def test_clear_dag(\n        self,\n        ti_state_begin: TaskInstanceState | None,\n        ti_state_end: TaskInstanceState | None,\n        dag_maker,\n        session,\n    ):\n        dag_id = "test_clear_dag"\n\n        task_id = "t1"\n        with dag_maker(\n            dag_id,\n            schedule=None,\n            start_date=DEFAULT_DATE,\n            max_active_runs=1,\n            serialized=True,\n        ) as dag:\n            EmptyOperator(task_id=task_id)\n\n        session = settings.get_session()()\n        dagrun_1 = dag_maker.create_dagrun(\n            run_id="backfill",\n            run_type=DagRunType.BACKFILL_JOB,\n            state=DagRunState.RUNNING,\n            start_date=DEFAULT_DATE,\n            logical_date=DEFAULT_DATE,\n            # triggered_by=DagRunTriggeredByType.TEST,\n            session=session,\n        )\n\n        task_instance_1 = dagrun_1.get_task_instance(task_id, session=session)\n        if TYPE_CHECKING:\n            assert task_instance_1\n        task_instance_1.state = ti_state_begin\n        task_instance_1.job_id = 123\n        session.commit()\n\n        create_scheduler_dag(dag).clear(\n            start_date=DEFAULT_DATE,\n            end_date=DEFAULT_DATE + datetime.timedelta(days=1),\n            session=session,\n        )\n\n        task_instances = session.scalars(select(TI).where(TI.dag_id == dag_id)).all()\n\n        assert len(task_instances) == 1\n        task_instance: TI = task_instances[0]\n        assert task_instance.state == ti_state_end\n\n    def test_next_dagrun_info_once(self):\n        dag = DAG("test_scheduler_dagrun_once", start_date=timezone.datetime(2015, 1, 1), schedule="@once")\n        scheduler_dag = create_scheduler_dag(dag)\n\n        next_info = scheduler_dag.next_dagrun_info(last_automated_run_info=None)\n        assert next_info\n        assert next_info.logical_date == timezone.datetime(2015, 1, 1)\n\n        next_info = scheduler_dag.next_dagrun_info(last_automated_run_info=next_info)\n        assert next_info is None\n\n    def test_next_dagrun_info_catchup(self):\n        """\n        Test to check that a DAG with catchup = False only schedules beginning now, not back to the start date\n        """\n\n        def make_dag(dag_id, schedule, start_date, catchup) -> SerializedDAG:\n            default_args = {\n                "owner": "airflow",\n                "depends_on_past": False,\n            }\n            dag = DAG(\n                dag_id,\n                schedule=schedule,\n                start_date=start_date,\n                catchup=catchup,\n                default_args=default_args,\n            )\n\n            op1 = EmptyOperator(task_id="t1", dag=dag)\n            op2 = EmptyOperator(task_id="t2", dag=dag)\n            op3 = EmptyOperator(task_id="t3", dag=dag)\n            op1 >> op2 >> op3\n\n            return create_scheduler_dag(dag)\n\n        now = timezone.utcnow()\n        six_hours_ago_to_the_hour = (now - datetime.timedelta(hours=6)).replace(\n            minute=0, second=0, microsecond=0\n        )\n        half_an_hour_ago = now - datetime.timedelta(minutes=30)\n        two_hours_ago = now - datetime.timedelta(hours=2)\n\n        dag1 = make_dag(\n            dag_id="dag_without_catchup_ten_minute",\n            schedule="*/10 * * * *",\n            start_date=six_hours_ago_to_the_hour,\n            catchup=False,\n        )\n        info = dag1.next_dagrun_info(last_automated_run_info=None)\n        next_date = info.run_after\n        # The DR should be scheduled in the last half an hour, not 6 hours ago\n        assert next_date > half_an_hour_ago\n        assert next_date < timezone.utcnow()\n\n        dag2 = make_dag(\n            dag_id="dag_without_catchup_hourly",\n            schedule="@hourly",\n            start_date=six_hours_ago_to_the_hour,\n            catchup=False,\n        )\n\n        info = dag2.next_dagrun_info(last_automated_run_info=None)\n        next_date = info.run_after\n        # The DR should be scheduled in the last 2 hours, not 6 hours ago\n        assert next_date > two_hours_ago\n        # The DR should be scheduled BEFORE now\n        assert next_date < timezone.utcnow()\n\n        dag3 = make_dag(\n            dag_id="dag_without_catchup_once",\n            schedule="@once",\n            start_date=six_hours_ago_to_the_hour,\n            catchup=False,\n        )\n\n        info = dag3.next_dagrun_info(last_automated_run_info=None)\n        next_date = info.run_after\n        # The DR should be scheduled in the last 2 hours, not 6 hours ago\n        assert next_date == six_hours_ago_to_the_hour\n\n    @time_machine.travel(timezone.datetime(2020, 1, 5))\n    @pytest.mark.parametrize("schedule", ("@daily", timedelta(days=1), cron_timetable("0 0 * * *")))\n    def test_next_dagrun_info_timedelta_schedule_and_catchup_false(self, schedule):\n        """\n        Test that the dag file processor does not create multiple dagruns\n        if a dag is scheduled with \'timedelta\' and catchup=False\n        """\n        dag = DAG(\n            "test_scheduler_dagrun_once_with_timedelta_and_catchup_false",\n            start_date=timezone.datetime(2015, 1, 1),\n            schedule=schedule,\n            catchup=False,\n        )\n        scheduler_dag = create_scheduler_dag(dag)\n\n        next_info = scheduler_dag.next_dagrun_info(last_automated_run_info=None)\n        assert next_info\n        assert next_info.logical_date == timezone.datetime(2020, 1, 4)\n\n        # The date to create is in the future, this is handled by "DagModel.dags_needing_dagruns"\n        next_info = scheduler_dag.next_dagrun_info(last_automated_run_info=next_info)\n        assert next_info\n        assert next_info.logical_date == timezone.datetime(2020, 1, 5)\n\n    @time_machine.travel(timezone.datetime(2020, 5, 4))\n    def test_next_dagrun_info_timedelta_schedule_and_catchup_true(self):\n        """\n        Test that the dag file processor creates multiple dagruns\n        if a dag is scheduled with \'timedelta\' and catchup=True\n        """\n        dag = DAG(\n            "test_scheduler_dagrun_once_with_timedelta_and_catchup_true",\n            start_date=timezone.datetime(2020, 5, 1),\n            schedule=timedelta(days=1),\n            catchup=True,\n        )\n        scheduler_dag = create_scheduler_dag(dag)\n\n        next_info = scheduler_dag.next_dagrun_info(last_automated_run_info=None)\n        assert next_info\n        assert next_info.logical_date == timezone.datetime(2020, 5, 1)\n\n        next_info = scheduler_dag.next_dagrun_info(last_automated_run_info=next_info)\n        assert next_info\n        assert next_info.logical_date == timezone.datetime(2020, 5, 2)\n\n        next_info = scheduler_dag.next_dagrun_info(last_automated_run_info=next_info)\n        assert next_info\n        assert next_info.logical_date == timezone.datetime(2020, 5, 3)\n\n        # The date to create is in the future, this is handled by "DagModel.dags_needing_dagruns"\n        next_info = scheduler_dag.next_dagrun_info(last_automated_run_info=next_info)\n        assert next_info\n        assert next_info.logical_date == timezone.datetime(2020, 5, 4)\n\n    def test_next_dagrun_info_timetable_exception(self, caplog):\n        """Test the DAG does not crash the scheduler if the timetable raises an exception."""\n\n        class FailingTimetable(Timetable):\n            def next_dagrun_info(self, last_automated_run_info, restriction):\n                raise RuntimeError("this fails")\n\n        def _find_registered_custom_timetable(s):\n            if s == qualname(FailingTimetable):\n                return FailingTimetable\n            raise ValueError(f"unexpected class {s!r}")\n\n        dag = DAG(\n            "test_next_dagrun_info_timetable_exception",\n            start_date=timezone.datetime(2020, 5, 1),\n            schedule=FailingTimetable(),\n            catchup=True,\n        )\n        with (\n            mock.patch(\n                "airflow.serialization.encoders.find_registered_custom_timetable",\n                _find_registered_custom_timetable,\n            ),\n            mock.patch(\n                "airflow.serialization.decoders.find_registered_custom_timetable",\n                _find_registered_custom_timetable,\n            ),\n        ):\n            scheduler_dag = create_scheduler_dag(dag)\n\n        def _check_logs(records: list[logging.LogRecord], data_interval: DataInterval) -> None:\n            assert len(records) == 1\n            record = records[0]\n            assert record.exc_info is not None, "Should contain exception"\n            assert record.message == "Failed to fetch run info"\n\n        with caplog.at_level(level=logging.ERROR):\n            next_info = scheduler_dag.next_dagrun_info(last_automated_run_info=None)\n        assert next_info is None, "failed next_dagrun_info should return None"\n        _check_logs(caplog.records, data_interval=None)\n        caplog.clear()\n        data_interval = DataInterval(timezone.datetime(2020, 5, 1), timezone.datetime(2020, 5, 2))\n        with caplog.at_level(level=logging.ERROR):\n            next_info = scheduler_dag.next_dagrun_info(last_automated_run_info=data_interval)\n        assert next_info is None, "failed next_dagrun_info should return None"\n        _check_logs(caplog.records, data_interval)\n\n    def test_next_dagrun_after_auto_align(self):\n        """\n        Test if the schedule will be auto aligned with the start_date\n        such that if the start_date coincides with the schedule the first\n        logical_date will be start_date, otherwise it will be start_date +\n        interval.\n\n        This test verifies both catchup=True and catchup=False scenarios:\n        - With catchup=True: The scheduler aligns with the historical start date\n        - With catchup=False: The scheduler aligns with the current date, ignoring historical dates\n        """\n        # Test catchup=True scenario (using historical dates)\n        dag = DAG(\n            dag_id="test_scheduler_auto_align_1",\n            start_date=timezone.datetime(2016, 1, 1, 10, 10, 0),\n            schedule="4 5 * * *",\n            catchup=True,\n        )\n        EmptyOperator(task_id="dummy", dag=dag, owner="airflow")\n        scheduler_dag = create_scheduler_dag(dag)\n\n        next_info = scheduler_dag.next_dagrun_info(last_automated_run_info=None)\n        assert next_info\n        assert next_info.logical_date == timezone.datetime(2016, 1, 2, 5, 4)\n\n        dag = DAG(\n            dag_id="test_scheduler_auto_align_2",\n            start_date=timezone.datetime(2016, 1, 1, 10, 10, 0),\n            schedule="10 10 * * *",\n            catchup=True,\n        )\n        EmptyOperator(task_id="dummy", dag=dag, owner="airflow")\n        scheduler_dag = create_scheduler_dag(dag)\n\n        next_info = scheduler_dag.next_dagrun_info(last_automated_run_info=None)\n        assert next_info\n        assert next_info.logical_date == timezone.datetime(2016, 1, 1, 10, 10)\n\n        # Test catchup=False scenario (using current dates)\n        start_date = timezone.datetime(2016, 1, 1, 10, 10, 0)\n        dag = DAG(\n            dag_id="test_scheduler_auto_align_3",\n            start_date=start_date,\n            schedule="4 5 * * *",\n            catchup=False,\n        )\n        EmptyOperator(task_id="dummy", dag=dag, owner="airflow")\n        scheduler_dag = create_scheduler_dag(dag)\n\n        next_info = scheduler_dag.next_dagrun_info(last_automated_run_info=None)\n        assert next_info\n        # With catchup=False, next_dagrun should be based on the current date\n        # Verify it\'s not using the old start_date\n        assert next_info.logical_date.year >= start_date.year\n        assert next_info.logical_date.month >= start_date.month\n\n        # Verify it\'s following the cron schedule pattern (4 5 * * *)\n        assert next_info.logical_date.hour == 5\n        assert next_info.logical_date.minute == 4\n\n        start_date = timezone.datetime(2016, 1, 1, 10, 10, 0)\n        dag = DAG(\n            dag_id="test_scheduler_auto_align_4",\n            start_date=start_date,\n            schedule="10 10 * * *",\n            catchup=False,\n        )\n        EmptyOperator(task_id="dummy", dag=dag, owner="airflow")\n        scheduler_dag = create_scheduler_dag(dag)\n\n        next_info = scheduler_dag.next_dagrun_info(last_automated_run_info=None)\n        assert next_info\n        # With catchup=False, next_dagrun should be based on the current date\n        # Verify it\'s not using the old start_date\n        assert next_info.logical_date.year >= start_date.year\n        assert next_info.logical_date.month >= start_date.month\n        # Verify it\'s following the cron schedule pattern (10 10 * * *)\n        assert next_info.logical_date.hour == 10\n        assert next_info.logical_date.minute == 10\n\n    def test_next_dagrun_info_on_29_feb(self):\n        dag = DAG(\n            "test_scheduler_dagrun_29_feb", start_date=timezone.datetime(2024, 1, 1), schedule="0 0 29 2 *"\n        )\n        scheduler_dag = create_scheduler_dag(dag)\n\n        next_info = scheduler_dag.next_dagrun_info(last_automated_run_info=None)\n        assert next_info\n        assert next_info.logical_date == timezone.datetime(2024, 2, 29)\n\n        next_info = scheduler_dag.next_dagrun_info(last_automated_run_info=next_info)\n        assert next_info.logical_date == timezone.datetime(2028, 2, 29)\n        assert next_info.data_interval.start == timezone.datetime(2028, 2, 29)\n        assert next_info.data_interval.end == timezone.datetime(2032, 2, 29)\n\n    def test_validate_params_on_trigger_dag(self, testing_dag_bundle):\n        dag = DAG("dummy-dag", schedule=None, params={"param1": Param(type="string")})\n        with pytest.raises(ValueError, match="No value passed"):\n            sync_dag_to_db(dag).create_dagrun(\n                run_id="test_dagrun_missing_param",\n                run_type=DagRunType.MANUAL,\n                state=State.RUNNING,\n                logical_date=TEST_DATE,\n                data_interval=(TEST_DATE, TEST_DATE),\n                run_after=TEST_DATE,\n                triggered_by=DagRunTriggeredByType.TEST,\n            )\n\n        dag = DAG("dummy-dag", schedule=None, params={"param1": Param(type="string")})\n        with pytest.raises(ValueError, match="None is not of type \'string\'"):\n            sync_dag_to_db(dag).create_dagrun(\n                run_id="test_dagrun_missing_param",\n                run_type=DagRunType.MANUAL,\n                state=State.RUNNING,\n                logical_date=TEST_DATE,\n                conf={"param1": None},\n                data_interval=(TEST_DATE, TEST_DATE),\n                run_after=TEST_DATE,\n                triggered_by=DagRunTriggeredByType.TEST,\n            )\n\n        dag = DAG("dummy-dag", schedule=None, params={"param1": Param(type="string")})\n        sync_dag_to_db(dag).create_dagrun(\n            run_id="test_dagrun_missing_param",\n            run_type=DagRunType.MANUAL,\n            state=State.RUNNING,\n            logical_date=TEST_DATE,\n            conf={"param1": "hello"},\n            data_interval=(TEST_DATE, TEST_DATE),\n            run_after=TEST_DATE,\n            triggered_by=DagRunTriggeredByType.TEST,\n        )\n\n    def test_dag_owner_links(self, testing_dag_bundle):\n        dag = DAG(\n            "dag",\n            schedule=None,\n            start_date=DEFAULT_DATE,\n            owner_links={"owner1": "https://mylink.com", "owner2": "mailto:someone@yoursite.com"},\n        )\n        session = settings.Session()\n        orm_dag = DagModel(\n            dag_id=dag.dag_id,\n            bundle_name="testing",\n            is_stale=False,\n        )\n        session.add(orm_dag)\n        session.flush()\n        assert dag.owner_links == {"owner1": "https://mylink.com", "owner2": "mailto:someone@yoursite.com"}\n        sync_dag_to_db(dag, session=session)\n\n        expected_owners = {"dag": {"owner1": "https://mylink.com", "owner2": "mailto:someone@yoursite.com"}}\n        orm_dag_owners = DagOwnerAttributes.get_all(session)\n        assert orm_dag_owners == expected_owners\n\n        # Test dag owner links are removed completely\n        dag = DAG("dag", schedule=None, start_date=DEFAULT_DATE)\n        sync_dag_to_db(dag, session=session)\n\n        orm_dag_owners = session.scalars(select(DagOwnerAttributes)).all()\n        assert not orm_dag_owners\n\n    @pytest.mark.need_serialized_dag\n    @pytest.mark.parametrize(\n        ("reference_type", "reference_column"),\n        [\n            pytest.param(DeadlineReference.DAGRUN_LOGICAL_DATE, "logical_date", id="logical_date"),\n            pytest.param(DeadlineReference.DAGRUN_QUEUED_AT, "queued_at", id="queued_at"),\n            pytest.param(DeadlineReference.FIXED_DATETIME(DEFAULT_DATE), "NONE", id="fixed_deadline"),\n        ],\n    )\n    def test_dagrun_deadline(self, reference_type, reference_column, testing_dag_bundle, session):\n        interval = datetime.timedelta(hours=1)\n        dag = DAG(\n            dag_id="test_deadline",\n            schedule=datetime.timedelta(days=1),\n            deadline=DeadlineAlert(\n                reference=reference_type,\n                interval=interval,\n                callback=AsyncCallback(empty_callback_for_deadline),\n            ),\n        )\n\n        # Sync the DAG to the database to create DeadlineAlert records\n        scheduler_dag = sync_dag_to_db(dag, session=session)\n\n        dr = scheduler_dag.create_dagrun(\n            run_id="test_dagrun_deadline",\n            run_type=DagRunType.SCHEDULED,\n            state=State.QUEUED,\n            logical_date=TEST_DATE,\n            run_after=TEST_DATE,\n            triggered_by=DagRunTriggeredByType.TEST,\n        )\n        session.flush()\n        dr = session.merge(dr)\n\n        assert len(dr.deadlines) == 1\n        assert dr.deadlines[0].deadline_time == getattr(dr, reference_column, DEFAULT_DATE) + interval\n\n    def test_dag_with_multiple_deadlines(self, testing_dag_bundle, session):\n        """Test that a Dag with multiple deadlines stores all deadlines and persists on re-serialization."""\n        deadlines = [\n            DeadlineAlert(\n                reference=DeadlineReference.DAGRUN_QUEUED_AT,\n                interval=datetime.timedelta(minutes=5),\n                callback=AsyncCallback(empty_callback_for_deadline),\n            ),\n            DeadlineAlert(\n                reference=DeadlineReference.DAGRUN_QUEUED_AT,\n                interval=datetime.timedelta(minutes=10),\n                callback=AsyncCallback(empty_callback_for_deadline),\n            ),\n            DeadlineAlert(\n                reference=DeadlineReference.DAGRUN_LOGICAL_DATE,\n                interval=datetime.timedelta(hours=1),\n                callback=AsyncCallback(empty_callback_for_deadline),\n            ),\n        ]\n        expected_num_deadlines = 3\n\n        dag = DAG(\n            dag_id="test_multiple_deadlines",\n            schedule=datetime.timedelta(days=1),\n            deadline=deadlines,\n        )\n\n        scheduler_dag = sync_dag_to_db(dag, session=session)\n\n        deadline_alerts = session.scalars(select(DeadlineAlertModel)).all()\n        assert len(deadline_alerts) == expected_num_deadlines\n        initial_uuids = {alert.id for alert in deadline_alerts}\n\n        # Re-serialize the Dag\n        SerializedDagModel.write_dag(\n            LazyDeserializedDAG.from_dag(dag),\n            bundle_name="testing",\n            session=session,\n        )\n        session.commit()\n\n        # Verify deadline alerts still exist after re-serialization\n        stored_alerts = session.scalars(\n            select(DeadlineAlertModel).where(DeadlineAlertModel.id.in_(initial_uuids))\n        ).all()\n        assert len(stored_alerts) == expected_num_deadlines\n\n        intervals = sorted([alert.interval for alert in stored_alerts])\n        assert intervals == [300.0, 600.0, 3600.0]\n\n        # Now create a dagrun and verify deadlines are created\n        dr = scheduler_dag.create_dagrun(\n            run_id="test_multiple_deadlines",\n            run_type=DagRunType.SCHEDULED,\n            state=State.QUEUED,\n            logical_date=TEST_DATE,\n            run_after=TEST_DATE,\n            triggered_by=DagRunTriggeredByType.TEST,\n        )\n        session.flush()\n        dr = session.merge(dr)\n\n        # Check that all deadlines were created\n        assert len(dr.deadlines) == expected_num_deadlines\n\n        # Verify each deadline has correct properties\n        deadline_times = [d.deadline_time for d in dr.deadlines]\n        expected_times = [\n            dr.queued_at + datetime.timedelta(minutes=5),\n            dr.queued_at + datetime.timedelta(minutes=10),\n            dr.logical_date + datetime.timedelta(hours=1),\n        ]\n\n        # Sort both lists to compare regardless of order\n        deadline_times.sort()\n        expected_times.sort()\n        assert deadline_times == expected_times\n\n\nclass TestDagModel:\n    def _clean(self):\n        clear_db_dags()\n        clear_db_assets()\n        clear_db_runs()\n        clear_db_dag_bundles()\n        clear_db_teams()\n\n    def setup_method(self):\n        self._clean()\n\n    def teardown_method(self):\n        self._clean()\n\n    def test_dags_needing_dagruns_not_too_early(self, testing_dag_bundle):\n        dag = DAG(dag_id="far_future_dag", schedule=None, start_date=timezone.datetime(2038, 1, 1))\n        EmptyOperator(task_id="dummy", dag=dag, owner="airflow")\n\n        session = settings.Session()\n        orm_dag = DagModel(\n            dag_id=dag.dag_id,\n            bundle_name="testing",\n            max_active_tasks=1,\n            has_task_concurrency_limits=False,\n            next_dagrun=dag.start_date,\n            next_dagrun_create_after=timezone.datetime(2038, 1, 2),\n            is_stale=False,\n        )\n        session.add(orm_dag)\n        session.flush()\n\n        query, _ = DagModel.dags_needing_dagruns(session)\n        dag_models = query.all()\n        assert dag_models == []\n\n        session.rollback()\n        session.close()\n\n    def test_dags_needing_dagruns_assets(self, dag_maker, session):\n        asset = Asset(uri="test://asset", group="test-group")\n        with dag_maker(\n            session=session,\n            dag_id="my_dag",\n            max_active_runs=1,\n            schedule=[asset],\n            start_date=pendulum.now().add(days=-2),\n        ) as dag:\n            EmptyOperator(task_id="dummy")\n\n        # there\'s no queue record yet, so no runs needed at this time.\n        query, _ = DagModel.dags_needing_dagruns(session)\n        dag_models = query.all()\n        assert dag_models == []\n\n        # add queue records so we\'ll need a run\n        dag_model = session.scalar(select(DagModel).where(DagModel.dag_id == dag.dag_id))\n        asset_model: AssetModel = dag_model.schedule_assets[0]\n        session.add(AssetDagRunQueue(asset_id=asset_model.id, target_dag_id=dag_model.dag_id))\n        session.flush()\n        query, _ = DagModel.dags_needing_dagruns(session)\n        dag_models = query.all()\n        assert dag_models == [dag_model]\n\n        # create run so we don\'t need a run anymore (due to max active runs)\n        dag_maker.create_dagrun(\n            run_type=DagRunType.ASSET_TRIGGERED,\n            state=DagRunState.QUEUED,\n            logical_date=pendulum.now("UTC"),\n        )\n        query, _ = DagModel.dags_needing_dagruns(session)\n        dag_models = query.all()\n        assert dag_models == []\n\n        # increase max active runs and we should now need another run\n        dag_maker.dag_model.max_active_runs = 2\n        session.flush()\n        query, _ = DagModel.dags_needing_dagruns(session)\n        dag_models = query.all()\n        assert dag_models == [dag_model]\n\n    def test_dags_needing_dagruns_query_count(self, dag_maker, session):\n        """Test that dags_needing_dagruns avoids N+1 on adrq.asset access."""\n        num_assets = 10\n        assets = [Asset(uri=f"test://asset{i}", group="test-group") for i in range(num_assets)]\n\n        with dag_maker(\n            session=session,\n            dag_id="my_dag",\n            max_active_runs=10,\n            schedule=assets,\n            start_date=pendulum.now().add(days=-2),\n        ):\n            EmptyOperator(task_id="dummy")\n\n        dag_model = dag_maker.dag_model\n        asset_models = dag_model.schedule_assets\n        assert len(asset_models) == num_assets\n        for asset_model in asset_models:\n            session.add(AssetDagRunQueue(asset_id=asset_model.id, target_dag_id=dag_model.dag_id))\n        session.flush()\n\n        # Clear identity map so N+1 on adrq.asset is exposed\n        session.expire_all()\n\n        with assert_queries_count(6):\n            query, _ = DagModel.dags_needing_dagruns(session)\n            query.all()\n\n    def test_dags_needing_dagruns_asset_aliases(self, dag_maker, session):\n        # link asset_alias hello_alias to asset hello\n        asset_model = AssetModel(uri="hello")\n        asset_alias_model = AssetAliasModel(name="hello_alias")\n        asset_alias_model.assets.append(asset_model)\n        session.add_all([asset_model, asset_alias_model])\n        session.commit()\n\n        with dag_maker(\n            session=session,\n            dag_id="my_dag",\n            max_active_runs=1,\n            schedule=[AssetAlias(name="hello_alias")],\n            start_date=pendulum.now().add(days=-2),\n        ):\n            EmptyOperator(task_id="dummy")\n\n        # there\'s no queue record yet, so no runs needed at this time.\n        query, _ = DagModel.dags_needing_dagruns(session)\n        dag_models = query.all()\n        assert dag_models == []\n\n        # add queue records so we\'ll need a run\n        dag_model = dag_maker.dag_model\n        session.add(AssetDagRunQueue(asset_id=asset_model.id, target_dag_id=dag_model.dag_id))\n        session.flush()\n        query, _ = DagModel.dags_needing_dagruns(session)\n        dag_models = query.all()\n        assert dag_models == [dag_model]\n\n        # create run so we don\'t need a run anymore (due to max active runs)\n        dag_maker.create_dagrun(\n            run_type=DagRunType.ASSET_TRIGGERED,\n            state=DagRunState.QUEUED,\n            logical_date=pendulum.now("UTC"),\n        )\n        query, _ = DagModel.dags_needing_dagruns(session)\n        dag_models = query.all()\n        assert dag_models == []\n\n        # increase max active runs and we should now need another run\n        dag_maker.dag_model.max_active_runs = 2\n        session.flush()\n        query, _ = DagModel.dags_needing_dagruns(session)\n        dag_models = query.all()\n        assert dag_models == [dag_model]\n\n    @pytest.mark.parametrize("ref", [Asset.ref(name="1"), Asset.ref(uri="s3://bucket/assets/1")])\n    @pytest.mark.want_activate_assets\n    @pytest.mark.need_serialized_dag\n    def test_dags_needing_dagruns_asset_refs(self, dag_maker, session, ref):\n        asset = Asset(name="1", uri="s3://bucket/assets/1")\n\n        with dag_maker(dag_id="producer", schedule=None, session=session) as dag:\n            op = EmptyOperator(task_id="op", outlets=asset)\n        ser_op = dag.get_task(op.task_id)\n\n        dr: DagRun = dag_maker.create_dagrun()\n\n        with dag_maker(dag_id="consumer", schedule=ref, max_active_runs=1):\n            pass\n\n        # Nothing from the upstream yet, no runs needed.\n        assert session.scalars(select(AssetDagRunQueue.target_dag_id)).all() == []\n        query, _ = DagModel.dags_needing_dagruns(session)\n        assert query.all() == []\n\n        # Upstream triggered, now we need a run.\n        ti = dr.get_task_instance("op")\n        ti.refresh_from_task(ser_op)\n        run_task_instance(ti, op)\n\n        assert session.scalars(select(AssetDagRunQueue.target_dag_id)).all() == ["consumer"]\n        query, _ = DagModel.dags_needing_dagruns(session)\n        assert [dm.dag_id for dm in query] == ["consumer"]\n\n    @pytest.mark.want_activate_assets\n    @pytest.mark.need_serialized_dag\n    def test_dags_needing_dagruns_checking_stale_adrq(self, dag_maker, session):\n        asset = Asset(name="1", uri="s3://bucket/assets/1")\n        dag_id_to_test = "test"\n\n        # Dag \'test\' depends on an outlet in \'producer\'.\n        with dag_maker(dag_id="producer", schedule=None, session=session) as dag:\n            op = EmptyOperator(task_id="op", outlets=asset)\n        dr = dag_maker.create_dagrun()\n        outlet_ti = dr.get_task_instance("op")\n        outlet_ti.refresh_from_task(dag.get_task(op.task_id))\n        with dag_maker(dag_id=dag_id_to_test, schedule=asset, session=session):\n            pass\n\n        # An adrq should be created when the outlet task is run.\n        run_task_instance(outlet_ti, op)\n        query, _ = DagModel.dags_needing_dagruns(session)\n        assert [dm.dag_id for dm in query] == [dag_id_to_test]\n        assert session.scalars(select(AssetDagRunQueue.target_dag_id)).all() == [dag_id_to_test]\n\n        # Now the dag is changed to NOT depend on \'producer\'.\n        # Rerunning dags_needing_dagruns should clear up that adrq.\n        with dag_maker(dag_id=dag_id_to_test, schedule=None, session=session):\n            pass\n        query, _ = DagModel.dags_needing_dagruns(session)\n        assert query.all() == []\n        assert session.scalars(select(AssetDagRunQueue.target_dag_id)).all() == []\n\n    def test_max_active_runs_not_none(self, testing_dag_bundle):\n        dag = DAG(\n            dag_id="test_max_active_runs_not_none",\n            schedule=None,\n            start_date=timezone.datetime(2038, 1, 1),\n        )\n        EmptyOperator(task_id="dummy", dag=dag, owner="airflow")\n\n        session = settings.Session()\n        orm_dag = DagModel(\n            dag_id=dag.dag_id,\n            bundle_name="testing",\n            has_task_concurrency_limits=False,\n            next_dagrun=None,\n            next_dagrun_create_after=None,\n            is_stale=False,\n        )\n        # assert max_active_runs updated\n        assert orm_dag.max_active_runs == 16\n        session.add(orm_dag)\n        session.flush()\n        assert orm_dag.max_active_runs is not None\n\n        session.rollback()\n        session.close()\n\n    def test_dags_needing_dagruns_only_unpaused(self, testing_dag_bundle):\n        """\n        We should never create dagruns for unpaused DAGs\n        """\n        dag = DAG(dag_id="test_dags", schedule=None, start_date=DEFAULT_DATE)\n        EmptyOperator(task_id="dummy", dag=dag, owner="airflow")\n\n        session = settings.Session()\n        orm_dag = DagModel(\n            dag_id=dag.dag_id,\n            bundle_name="testing",\n            has_task_concurrency_limits=False,\n            next_dagrun=DEFAULT_DATE,\n            next_dagrun_create_after=DEFAULT_DATE + timedelta(days=1),\n            is_stale=False,\n        )\n        session.merge(orm_dag)\n        session.flush()\n\n        query, _ = DagModel.dags_needing_dagruns(session)\n        needed = query.all()\n        assert [d.dag_id for d in needed] == [orm_dag.dag_id]\n\n        orm_dag.is_paused = True\n        session.merge(orm_dag)\n        session.flush()\n\n        query, _ = DagModel.dags_needing_dagruns(session)\n        dag_models = query.all()\n        assert dag_models == []\n\n        session.rollback()\n        session.close()\n\n    def test_dags_needing_dagruns_doesnot_send_dagmodel_with_import_errors(self, session, testing_dag_bundle):\n        """\n        We check that has_import_error is false for dags\n        being set to scheduler to create dagruns\n        """\n        dag = DAG(dag_id="test_dags", schedule=None, start_date=DEFAULT_DATE)\n        EmptyOperator(task_id="dummy", dag=dag, owner="airflow")\n\n        orm_dag = DagModel(\n            dag_id=dag.dag_id,\n            bundle_name="testing",\n            has_task_concurrency_limits=False,\n            next_dagrun=DEFAULT_DATE,\n            next_dagrun_create_after=DEFAULT_DATE + timedelta(days=1),\n            is_stale=False,\n        )\n        assert not orm_dag.has_import_errors\n        session.add(orm_dag)\n        session.flush()\n\n        query, _ = DagModel.dags_needing_dagruns(session)\n        needed = query.all()\n        assert needed == [orm_dag]\n\n        orm_dag.has_import_errors = True\n        session.merge(orm_dag)\n        session.flush()\n\n        query, _ = DagModel.dags_needing_dagruns(session)\n        dag_models = query.all()\n        assert dag_models == []\n\n        session.rollback()\n        session.close()\n\n    def test_relative_fileloc(self, session, testing_dag_bundle):\n        rel_path = "test_assets.py"\n        bundle_path = TEST_DAGS_FOLDER\n        file_path = bundle_path / rel_path\n        bag = BundleDagBag(dag_folder=file_path, bundle_path=bundle_path, bundle_name="testing")\n\n        dag = bag.get_dag("dag_with_skip_task")\n\n        bundle_name = "testing"\n\n        dag_model = DagModel(\n            dag_id=dag.dag_id,\n            bundle_name=bundle_name,\n        )\n        session.merge(dag_model)\n        session.flush()\n\n        sync_dag_to_db(dag, session=session)\n\n        assert dag.fileloc == str(file_path)\n        assert dag.relative_fileloc == str(rel_path)\n\n        SerializedDagModel.write_dag(\n            LazyDeserializedDAG.from_dag(dag),\n            bundle_name=bundle_name,\n            session=session,\n        )\n        dm = session.get(DagModel, dag.dag_id)\n        assert dm.fileloc == str(file_path)\n        assert dm.relative_fileloc == str(rel_path)\n        sdm = session.scalar(select(SerializedDagModel).where(SerializedDagModel.dag_id == dag.dag_id))\n        assert sdm.dag.fileloc == str(file_path)\n        assert sdm.dag.relative_fileloc == str(rel_path)\n\n    def test__processor_dags_folder(self, session, testing_dag_bundle):\n        """Only populated after deserializtion"""\n        bundle_name = "testing"\n\n        dag = DAG(dag_id="test", schedule=None)\n        dag.fileloc = "/abc/test.py"\n\n        dag_model = DagModel(\n            dag_id=dag.dag_id,\n            bundle_name=bundle_name,\n        )\n        session.merge(dag_model)\n        session.flush()\n\n        scheduler_dag = sync_dag_to_db(dag)\n        assert scheduler_dag._processor_dags_folder == settings.DAGS_FOLDER\n        sdm = SerializedDagModel.get(dag.dag_id, session)\n        assert sdm.dag._processor_dags_folder == settings.DAGS_FOLDER\n\n    @pytest.mark.need_serialized_dag\n    def test_dags_needing_dagruns_triggered_date_by_dag_queued_times(self, session, dag_maker):\n        asset1 = Asset(uri="test://asset1", group="test-group")\n        asset2 = Asset(uri="test://asset2", name="test_asset_2", group="test-group")\n\n        for dag_id, asset in [("assets-1", asset1), ("assets-2", asset2)]:\n            with dag_maker(dag_id=dag_id, start_date=timezone.utcnow(), session=session):\n                EmptyOperator(task_id="task", outlets=[asset])\n            dr = dag_maker.create_dagrun()\n\n            asset_id = session.scalar(select(AssetModel.id).where(AssetModel.uri == asset.uri))\n\n            session.add(\n                AssetEvent(\n                    asset_id=asset_id,\n                    source_task_id="task",\n                    source_dag_id=dr.dag_id,\n                    source_run_id=dr.run_id,\n                    source_map_index=-1,\n                )\n            )\n\n        asset1_id = session.scalar(select(AssetModel.id).where(AssetModel.uri == asset1.uri))\n        asset2_id = session.scalar(select(AssetModel.id).where(AssetModel.uri == asset2.uri))\n\n        with dag_maker(dag_id="assets-consumer-multiple", schedule=[asset1, asset2]) as dag:\n            pass\n\n        session.flush()\n        session.add_all(\n            [\n                AssetDagRunQueue(asset_id=asset1_id, target_dag_id=dag.dag_id, created_at=DEFAULT_DATE),\n                AssetDagRunQueue(\n                    asset_id=asset2_id,\n                    target_dag_id=dag.dag_id,\n                    created_at=DEFAULT_DATE + timedelta(hours=1),\n                ),\n            ]\n        )\n        session.flush()\n\n        query, triggered_date_by_dag = DagModel.dags_needing_dagruns(session)\n        assert len(triggered_date_by_dag) == 1\n        assert dag.dag_id in triggered_date_by_dag\n        last_queued_time = triggered_date_by_dag[dag.dag_id]\n        assert last_queued_time == DEFAULT_DATE + timedelta(hours=1)\n\n    def test_asset_expression(self, session: Session, testing_dag_bundle) -> None:\n        dag = DAG(\n            dag_id="test_dag_asset_expression",\n            schedule=AssetAny(\n                Asset(uri="s3://dag1/output_1.txt", extra={"hi": "bye"}, group="test-group"),\n                AssetAll(\n                    Asset(\n                        uri="s3://dag2/output_1.txt",\n                        name="test_asset_2",\n                        extra={"hi": "bye"},\n                        group="test-group",\n                    ),\n                    Asset("s3://dag3/output_3.txt", extra={"hi": "bye"}, group="test-group"),\n                    AssetAll(\n                        AssetAll(\n                            Asset("s3://dag3/output_4.txt", extra={"hi": "bye"}, group="test-group"),\n                            Asset("s3://dag3/output_5.txt", extra={"hi": "bye"}, group="test-group"),\n                        ),\n                        Asset("s3://dag3/output_6.txt", extra={"hi": "bye"}, group="test-group"),\n                    ),\n                ),\n                AssetAlias(name="test_name", group="test-group"),\n            ),\n            start_date=datetime.datetime.min,\n        )\n        SerializedDAG.bulk_write_to_db("testing", None, [dag], session=session)\n\n        expression: ScalarResult = session.scalars(\n            select(DagModel.asset_expression).where(DagModel.dag_id == dag.dag_id)\n        ).one()\n        assert expression == {\n            "any": [\n                {\n                    "asset": {\n                        "uri": "s3://dag1/output_1.txt",\n                        "name": "s3://dag1/output_1.txt",\n                        "group": "test-group",\n                        "id": ANY,\n                    }\n                },\n                {\n                    "all": [\n                        {\n                            "asset": {\n                                "uri": "s3://dag2/output_1.txt",\n                                "name": "test_asset_2",\n                                "group": "test-group",\n                                "id": ANY,\n                            }\n                        },\n                        {\n                            "asset": {\n                                "uri": "s3://dag3/output_3.txt",\n                                "name": "s3://dag3/output_3.txt",\n                                "group": "test-group",\n                                "id": ANY,\n                            }\n                        },\n                        {\n                            "all": [\n                                {\n                                    "all": [\n                                        {\n                                            "asset": {\n                                                "uri": "s3://dag3/output_4.txt",\n                                                "name": "s3://dag3/output_4.txt",\n                                                "group": "test-group",\n                                                "id": ANY,\n                                            }\n                                        },\n                                        {\n                                            "asset": {\n                                                "uri": "s3://dag3/output_5.txt",\n                                                "name": "s3://dag3/output_5.txt",\n                                                "group": "test-group",\n                                                "id": ANY,\n                                            }\n                                        },\n                                    ],\n                                },\n                                {\n                                    "asset": {\n                                        "uri": "s3://dag3/output_6.txt",\n                                        "name": "s3://dag3/output_6.txt",\n                                        "group": "test-group",\n                                        "id": ANY,\n                                    },\n                                },\n                            ]\n                        },\n                    ]\n                },\n                {"alias": {"name": "test_name", "group": "test-group"}},\n            ]\n        }\n\n    def test_get_team_name(self, testing_team):\n        session = settings.Session()\n        dag_bundle = DagBundleModel(name="testing-team")\n        dag_bundle.teams.append(testing_team)\n        session.add(dag_bundle)\n        session.flush()\n\n        dag_id = "test_get_team_name"\n        dag = DAG(dag_id, schedule=None)\n        orm_dag = DagModel(\n            dag_id=dag.dag_id,\n            bundle_name="testing-team",\n            is_stale=False,\n        )\n        session.add(orm_dag)\n        session.flush()\n        assert DagModel.get_dagmodel(dag_id) is not None\n        assert DagModel.get_team_name(dag_id, session=session) == "testing"\n\n    def test_get_team_name_no_team(self, testing_team):\n        session = settings.Session()\n        dag_bundle = DagBundleModel(name="testing")\n        session.add(dag_bundle)\n        session.flush()\n\n        dag_id = "test_get_team_name_no_team"\n        dag = DAG(dag_id, schedule=None)\n        orm_dag = DagModel(\n            dag_id=dag.dag_id,\n            bundle_name="testing",\n            is_stale=False,\n        )\n        session.add(orm_dag)\n        session.flush()\n        assert DagModel.get_dagmodel(dag_id) is not None\n        assert DagModel.get_team_name(dag_id, session=session) is None\n\n    def test_get_dag_id_to_team_name_mapping(self, testing_team):\n        session = settings.Session()\n        bundle1 = DagBundleModel(name="bundle1")\n        bundle1.teams.append(testing_team)\n        bundle2 = DagBundleModel(name="bundle2")\n        session.add(bundle1)\n        session.add(bundle2)\n        session.flush()\n\n        dag_id1 = "test_dag1"\n        dag1 = DAG(dag_id1, schedule=None)\n        orm_dag1 = DagModel(\n            dag_id=dag1.dag_id,\n            bundle_name="bundle1",\n            is_stale=False,\n        )\n        dag_id2 = "test_dag2"\n        dag2 = DAG(dag_id2, schedule=None)\n        orm_dag2 = DagModel(\n            dag_id=dag2.dag_id,\n            bundle_name="bundle2",\n            is_stale=False,\n        )\n        session.add(orm_dag1)\n        session.add(orm_dag2)\n        session.flush()\n        assert DagModel.get_dag_id_to_team_name_mapping([dag_id1, dag_id2], session=session) == {\n            dag_id1: "testing"\n        }\n\n\nclass TestQueries:\n    def setup_method(self) -> None:\n        clear_db_runs()\n        clear_db_dags()\n        clear_db_dag_bundles()\n\n    def teardown_method(self) -> None:\n        clear_db_runs()\n        clear_db_dags()\n        clear_db_dag_bundles()\n\n    @pytest.mark.parametrize("tasks_count", [3, 12])\n    def test_count_number_queries(self, tasks_count, testing_dag_bundle):\n        dag = DAG("test_dagrun_query_count", schedule=None, start_date=DEFAULT_DATE)\n        for i in range(tasks_count):\n            EmptyOperator(task_id=f"dummy_task_{i}", owner="test", dag=dag)\n        scheduler_dag = sync_dag_to_db(dag)\n        with assert_queries_count(5):\n            scheduler_dag.create_dagrun(\n                run_id="test_dagrun_query_count",\n                run_type=DagRunType.MANUAL,\n                state=State.RUNNING,\n                logical_date=TEST_DATE,\n                data_interval=(TEST_DATE, TEST_DATE),\n                run_after=TEST_DATE,\n                triggered_by=DagRunTriggeredByType.TEST,\n            )\n\n\n@pytest.mark.need_serialized_dag\n@pytest.mark.parametrize(\n    "run_id",\n    ["test-run-id"],\n)\ndef test_set_task_instance_state(run_id, session, dag_maker):\n    """Test that set_task_instance_state updates the TaskInstance state and clear downstream failed"""\n    start_date = datetime_tz(2020, 1, 1)\n    with dag_maker(\n        "test_set_task_instance_state",\n        start_date=start_date,\n        session=session,\n        serialized=True,\n    ) as dag:\n        task_1 = EmptyOperator(task_id="task_1")\n        task_2 = EmptyOperator(task_id="task_2")\n        task_3 = EmptyOperator(task_id="task_3")\n        task_4 = EmptyOperator(task_id="task_4")\n        task_5 = EmptyOperator(task_id="task_5")\n        task_1 >> [task_2, task_3, task_4, task_5]\n\n    dagrun = dag_maker.create_dagrun(\n        run_id=run_id,\n        state=State.FAILED,\n        run_type=DagRunType.SCHEDULED,\n    )\n\n    def get_ti_from_db(task):\n        return session.scalar(\n            select(TI).where(\n                TI.dag_id == dag.dag_id,\n                TI.task_id == task.task_id,\n                TI.run_id == dagrun.run_id,\n            )\n        )\n\n    get_ti_from_db(task_1).state = State.FAILED\n    get_ti_from_db(task_2).state = State.SUCCESS\n    get_ti_from_db(task_3).state = State.UPSTREAM_FAILED\n    get_ti_from_db(task_4).state = State.FAILED\n    get_ti_from_db(task_5).state = State.SKIPPED\n\n    session.flush()\n\n    altered = dag.set_task_instance_state(\n        task_id=task_1.task_id,\n        run_id=run_id,\n        state=State.SUCCESS,\n        session=session,\n    )\n    # After _mark_task_instance_state, task_1 is marked as SUCCESS\n    ti1 = get_ti_from_db(task_1)\n    assert ti1.state == State.SUCCESS\n    # TIs should have DagRun pre-loaded\n    assert isinstance(inspect(ti1).attrs.dag_run.loaded_value, DagRun)\n    # task_2 remains as SUCCESS\n    assert get_ti_from_db(task_2).state == State.SUCCESS\n    # task_3 and task_4 are cleared because they were in FAILED/UPSTREAM_FAILED state\n    assert get_ti_from_db(task_3).state == State.NONE\n    assert get_ti_from_db(task_4).state == State.NONE\n    # task_5 remains as SKIPPED\n    assert get_ti_from_db(task_5).state == State.SKIPPED\n    dagrun.refresh_from_db(session=session)\n    # dagrun should be set to QUEUED\n    assert dagrun.get_state() == State.QUEUED\n\n    assert {tuple(t.key) for t in altered} == {\n        ("test_set_task_instance_state", "task_1", dagrun.run_id, 0, -1)\n    }\n\n\n@pytest.mark.need_serialized_dag\ndef test_set_task_instance_state_mapped(dag_maker, session):\n    """Test that when setting an individual mapped TI that the other TIs are not affected"""\n    task_id = "t1"\n\n    # The catchup behavior isn\'t central to what\'s being tested. Setting catchup explicitly to True.\n    with dag_maker(session=session, catchup=True) as dag:\n\n        @task_decorator\n        def make_arg_lists():\n            return [[1], [2], [{"a": "b"}]]\n\n        def consumer(value):\n            print(value)\n\n        mapped = PythonOperator.partial(task_id=task_id, python_callable=consumer).expand(\n            op_args=make_arg_lists()\n        )\n\n        mapped >> BaseOperator(task_id="downstream")\n\n    dr1 = dag_maker.create_dagrun(\n        run_type=DagRunType.SCHEDULED,\n        state=DagRunState.FAILED,\n    )\n\n    mapped = dag.get_task(task_id)\n    expand_mapped_task(mapped, dr1.run_id, "make_arg_lists", length=2, session=session)\n\n    # set_state(future=True) only applies to scheduled runs\n    dr2 = dag_maker.create_dagrun(\n        run_type=DagRunType.SCHEDULED,\n        state=DagRunState.FAILED,\n        logical_date=DEFAULT_DATE + datetime.timedelta(days=1),\n    )\n    expand_mapped_task(mapped, dr2.run_id, "make_arg_lists", length=2, session=session)\n\n    session.execute(update(TI).where(TI.dag_id == dag.dag_id).values(state=TaskInstanceState.FAILED))\n\n    ti_query = (\n        select(TI.task_id, TI.map_index, TI.run_id, TI.state)\n        .where(TI.dag_id == dag.dag_id, TI.task_id.in_([task_id, "downstream"]))\n        .order_by(TI.run_id, TI.task_id, TI.map_index)\n    )\n\n    # Check pre-conditions\n    assert session.execute(ti_query).all() == [\n        ("downstream", -1, dr1.run_id, TaskInstanceState.FAILED),\n        (task_id, 0, dr1.run_id, TaskInstanceState.FAILED),\n        (task_id, 1, dr1.run_id, TaskInstanceState.FAILED),\n        ("downstream", -1, dr2.run_id, TaskInstanceState.FAILED),\n        (task_id, 0, dr2.run_id, TaskInstanceState.FAILED),\n        (task_id, 1, dr2.run_id, TaskInstanceState.FAILED),\n    ]\n\n    dag.set_task_instance_state(\n        task_id=task_id,\n        map_indexes=[1],\n        future=True,\n        run_id=dr1.run_id,\n        state=TaskInstanceState.SUCCESS,\n        session=session,\n    )\n    assert dr1 in session, "Check session is passed down all the way"\n\n    assert session.execute(ti_query).all() == [\n        ("downstream", -1, dr1.run_id, None),\n        (task_id, 0, dr1.run_id, TaskInstanceState.FAILED),\n        (task_id, 1, dr1.run_id, TaskInstanceState.SUCCESS),\n        ("downstream", -1, dr2.run_id, None),\n        (task_id, 0, dr2.run_id, TaskInstanceState.FAILED),\n        (task_id, 1, dr2.run_id, TaskInstanceState.SUCCESS),\n    ]\n\n\ndef test_dag_teardowns_property_lists_all_teardown_tasks():\n    @setup\n    def setup_task():\n        return 1\n\n    @teardown\n    def teardown_task():\n        return 1\n\n    @teardown\n    def teardown_task2():\n        return 1\n\n    @teardown\n    def teardown_task3():\n        return 1\n\n    @task_decorator\n    def mytask():\n        return 1\n\n    with DAG("dag") as dag:\n        t1 = setup_task()\n        t2 = teardown_task()\n        t3 = teardown_task2()\n        t4 = teardown_task3()\n        with t1 >> t2:\n            with t3:\n                with t4:\n                    mytask()\n\n    assert {t.task_id for t in dag.teardowns} == {"teardown_task", "teardown_task2", "teardown_task3"}\n    assert {t.task_id for t in dag.tasks_upstream_of_teardowns} == {"setup_task", "mytask"}\n\n\n@pytest.mark.parametrize(\n    ("start_date", "expected_infos"),\n    [\n        (\n            DEFAULT_DATE,\n            [DagRunInfo.interval(DEFAULT_DATE, DEFAULT_DATE + datetime.timedelta(hours=1))],\n        ),\n        (\n            DEFAULT_DATE - datetime.timedelta(hours=3),\n            [\n                DagRunInfo.interval(\n                    DEFAULT_DATE - datetime.timedelta(hours=3),\n                    DEFAULT_DATE - datetime.timedelta(hours=2),\n                ),\n                DagRunInfo.interval(\n                    DEFAULT_DATE - datetime.timedelta(hours=2),\n                    DEFAULT_DATE - datetime.timedelta(hours=1),\n                ),\n                DagRunInfo.interval(\n                    DEFAULT_DATE - datetime.timedelta(hours=1),\n                    DEFAULT_DATE,\n                ),\n                DagRunInfo.interval(\n                    DEFAULT_DATE,\n                    DEFAULT_DATE + datetime.timedelta(hours=1),\n                ),\n            ],\n        ),\n    ],\n    ids=["in-dag-restriction", "out-of-dag-restriction"],\n)\ndef test_iter_dagrun_infos_between(start_date, expected_infos):\n    dag = DAG(dag_id="test_get_dates", start_date=DEFAULT_DATE, schedule="@hourly")\n    EmptyOperator(task_id="dummy", dag=dag)\n\n    iterator = create_scheduler_dag(dag).iter_dagrun_infos_between(\n        earliest=pendulum.instance(start_date),\n        latest=pendulum.instance(DEFAULT_DATE),\n    )\n    assert expected_infos == list(iterator)\n\n\ndef test_iter_dagrun_infos_between_error(caplog):\n    start = pendulum.instance(DEFAULT_DATE - datetime.timedelta(hours=1))\n    end = pendulum.instance(DEFAULT_DATE)\n\n    class FailingAfterOneTimetable(Timetable):\n        def next_dagrun_info(self, last_automated_data_interval: DataInterval | None, restriction):\n            if last_automated_data_interval is None:\n                return DagRunInfo.interval(start, end)\n            raise RuntimeError("this fails")\n\n    def _get_registered_timetable(s):\n        if s == "unit.models.test_dag.FailingAfterOneTimetable":\n            return FailingAfterOneTimetable\n        raise ValueError(f"unexpected class {s!r}")\n\n    dag = DAG(\n        dag_id="test_iter_dagrun_infos_between_error",\n        start_date=DEFAULT_DATE,\n        schedule=FailingAfterOneTimetable(),\n    )\n    with (\n        mock.patch(\n            "airflow.serialization.decoders.find_registered_custom_timetable",\n            _get_registered_timetable,\n        ),\n        mock.patch(\n            "airflow.serialization.encoders.find_registered_custom_timetable",\n            _get_registered_timetable,\n        ),\n    ):\n        scheduler_dag = create_scheduler_dag(dag)\n\n    iterator = scheduler_dag.iter_dagrun_infos_between(earliest=start, latest=end)\n    with caplog.at_level(logging.ERROR):\n        infos = list(iterator)\n\n    # The second timetable.next_dagrun_info() call raises an exception, so only the first result is returned.\n    assert infos == [DagRunInfo.interval(start, end)]\n\n    assert caplog.record_tuples == [\n        (\n            "airflow.serialization.definitions.dag",\n            logging.ERROR,\n            "Failed to fetch run info",\n        ),\n    ]\n    assert caplog.entries[0].get("exception"), "should contain exception context"\n\n\n@pytest.mark.parametrize(\n    ("logical_date", "data_interval_start", "data_interval_end", "expected_data_interval"),\n    [\n        pytest.param(None, None, None, None, id="no-next-run"),\n        pytest.param(\n            DEFAULT_DATE,\n            DEFAULT_DATE,\n            DEFAULT_DATE + timedelta(days=2),\n            DataInterval(DEFAULT_DATE, DEFAULT_DATE + timedelta(days=2)),\n            id="modern",\n        ),\n        pytest.param(\n            DEFAULT_DATE,\n            None,\n            None,\n            DataInterval(DEFAULT_DATE, DEFAULT_DATE + timedelta(days=1)),\n            id="legacy",\n        ),\n    ],\n)\ndef test_get_next_data_interval(\n    logical_date,\n    data_interval_start,\n    data_interval_end,\n    expected_data_interval,\n):\n    dag = DAG(dag_id="test_get_next_data_interval", schedule="@daily", start_date=DEFAULT_DATE)\n    dag_model = DagModel(\n        dag_id="test_get_next_data_interval",\n        bundle_name="dags-folder",\n        next_dagrun=logical_date,\n        next_dagrun_data_interval_start=data_interval_start,\n        next_dagrun_data_interval_end=data_interval_end,\n    )\n\n    core_timetable = coerce_to_core_timetable(dag.timetable)\n    assert get_next_data_interval(core_timetable, dag_model) == expected_data_interval\n\n\n@pytest.mark.need_serialized_dag\n@pytest.mark.parametrize(\n    ("dag_date", "tasks_date", "catchup", "restrict"),\n    [\n        # catchup=True cases - respects task start dates\n        [\n            (DEFAULT_DATE, None),\n            [\n                (DEFAULT_DATE + timedelta(days=1), DEFAULT_DATE + timedelta(days=2)),\n                (DEFAULT_DATE + timedelta(days=3), DEFAULT_DATE + timedelta(days=4)),\n            ],\n            True,\n            TimeRestriction(DEFAULT_DATE, DEFAULT_DATE + timedelta(days=4), True),\n        ],\n        [\n            (DEFAULT_DATE, None),\n            [(DEFAULT_DATE, DEFAULT_DATE + timedelta(days=1)), (DEFAULT_DATE, None)],\n            True,\n            TimeRestriction(DEFAULT_DATE, None, True),\n        ],\n        # catchup=False cases - same time boundaries but different catchup flag\n        [\n            (DEFAULT_DATE, None),\n            [\n                (DEFAULT_DATE + timedelta(days=1), DEFAULT_DATE + timedelta(days=2)),\n                (DEFAULT_DATE + timedelta(days=3), DEFAULT_DATE + timedelta(days=4)),\n            ],\n            False,\n            TimeRestriction(DEFAULT_DATE, DEFAULT_DATE + timedelta(days=4), False),\n        ],\n        [\n            (DEFAULT_DATE, None),\n            [(DEFAULT_DATE, DEFAULT_DATE + timedelta(days=1)), (DEFAULT_DATE, None)],\n            False,\n            TimeRestriction(DEFAULT_DATE, None, False),\n        ],\n    ],\n)\ndef test__time_restriction(dag_maker, dag_date, tasks_date, catchup, restrict):\n    """\n    Test that _time_restriction correctly reflects the DAG\'s time constraints with different catchup settings.\n\n    With catchup=True, future task start dates are respected.\n    With catchup=False, the scheduler may schedule tasks regardless of their future start dates.\n    """\n    with dag_maker(\n        "test__time_restriction",\n        schedule=None,\n        catchup=catchup,  # Use the parametrized catchup value\n        start_date=dag_date[0],\n        end_date=dag_date[1],\n    ) as dag:\n        EmptyOperator(task_id="do1", start_date=tasks_date[0][0], end_date=tasks_date[0][1])\n        EmptyOperator(task_id="do2", start_date=tasks_date[1][0], end_date=tasks_date[1][1])\n\n    assert dag._time_restriction == restrict\n\n\ndef test_get_asset_triggered_next_run_info(dag_maker, clear_assets):\n    asset1 = Asset(uri="test://asset1", name="test_asset1", group="test-group")\n    asset2 = Asset(uri="test://asset2", group="test-group")\n    asset3 = Asset(uri="test://asset3", group="test-group")\n    with dag_maker(dag_id="assets-1", schedule=[asset2]):\n        pass\n    dag1 = dag_maker.dag\n\n    with dag_maker(dag_id="assets-2", schedule=[asset1, asset2]):\n        pass\n    dag2 = dag_maker.dag\n\n    with dag_maker(dag_id="assets-3", schedule=[asset1, asset2, asset3]):\n        pass\n    dag3 = dag_maker.dag\n\n    session = dag_maker.session\n    asset1_id = session.scalar(select(AssetModel.id).where(AssetModel.uri == asset1.uri))\n    session.bulk_save_objects(\n        [\n            AssetDagRunQueue(asset_id=asset1_id, target_dag_id=dag2.dag_id),\n            AssetDagRunQueue(asset_id=asset1_id, target_dag_id=dag3.dag_id),\n        ]\n    )\n    session.flush()\n\n    assets = session.execute(select(AssetModel.uri).order_by(AssetModel.id)).all()\n\n    info = get_asset_triggered_next_run_info([dag1.dag_id], session=session)\n    assert info[dag1.dag_id] == {\n        "ready": 0,\n        "total": 1,\n        "uri": assets[0].uri,\n    }\n\n    # This time, check both dag2 and dag3 at the same time (tests filtering)\n    info = get_asset_triggered_next_run_info([dag2.dag_id, dag3.dag_id], session=session)\n    assert info[dag2.dag_id] == {\n        "ready": 1,\n        "total": 2,\n        "uri": "",\n    }\n    assert info[dag3.dag_id] == {\n        "ready": 1,\n        "total": 3,\n        "uri": "",\n    }\n\n\n@pytest.mark.need_serialized_dag\ndef test_get_asset_triggered_next_run_info_with_unresolved_asset_alias(dag_maker, clear_assets):\n    asset_alias1 = AssetAlias(name="alias")\n    with dag_maker(dag_id="dag-1", schedule=[asset_alias1]):\n        pass\n    dag1 = dag_maker.dag\n    session = dag_maker.session\n    session.flush()\n\n    info = get_asset_triggered_next_run_info([dag1.dag_id], session=session)\n    assert info == {}\n\n    dag1_model = DagModel.get_dagmodel(dag1.dag_id)\n    assert dag1_model.get_asset_triggered_next_run_info(session=session) is None\n\n\n@pytest.mark.parametrize(\n    "run_id_type",\n    [DagRunType.BACKFILL_JOB, DagRunType.SCHEDULED, DagRunType.ASSET_TRIGGERED],\n)\ndef test_create_dagrun_disallow_manual_to_use_automated_run_id(run_id_type: DagRunType) -> None:\n    dag = DAG(dag_id="test", start_date=DEFAULT_DATE, schedule="@daily")\n    run_id = DagRun.generate_run_id(run_type=run_id_type, run_after=DEFAULT_DATE, logical_date=DEFAULT_DATE)\n\n    with pytest.raises(\n        ValueError,\n        match=re.escape(\n            f"A manual DAG run cannot use ID {run_id!r} since it is reserved for {run_id_type.value} runs"\n        ),\n    ):\n        create_scheduler_dag(dag).create_dagrun(\n            run_type=DagRunType.MANUAL,\n            run_id=run_id,\n            logical_date=DEFAULT_DATE,\n            data_interval=(DEFAULT_DATE, DEFAULT_DATE),\n            run_after=DEFAULT_DATE,\n            state=DagRunState.QUEUED,\n            triggered_by=DagRunTriggeredByType.TEST,\n        )\n\n\nclass TestTaskClearingSetupTeardownBehavior:\n    """\n    Task clearing behavior is mainly controlled by dag.partial_subset.\n    Here we verify, primarily with regard to setups and teardowns, the\n    behavior of dag.partial_subset but also the supporting methods defined\n    on AbstractOperator.\n    """\n\n    @staticmethod\n    def make_tasks(dag, input_str):\n        """\n        Helper for building setup and teardown tasks for testing.\n\n        Given an input such as \'s1, w1, t1, tf1\', returns setup task "s1", normal task "w1"\n        (the w means *work*), teardown task "t1", and teardown task "tf1" where the f means\n        on_failure_fail_dagrun has been set to true.\n        """\n\n        def teardown_task(task_id):\n            return BaseOperator(task_id=task_id).as_teardown()\n\n        def teardown_task_f(task_id):\n            return BaseOperator(task_id=task_id).as_teardown(on_failure_fail_dagrun=True)\n\n        def work_task(task_id):\n            return BaseOperator(task_id=task_id)\n\n        def setup_task(task_id):\n            return BaseOperator(task_id=task_id).as_setup()\n\n        def make_task(task_id):\n            """\n            Task factory helper.\n\n            Will give a setup, teardown, work, or teardown-with-dagrun-failure task depending on input.\n            """\n            if task_id.startswith("s"):\n                factory = setup_task\n            elif task_id.startswith("w"):\n                factory = work_task\n            elif task_id.startswith("tf"):\n                factory = teardown_task_f\n            elif task_id.startswith("t"):\n                factory = teardown_task\n            else:\n                raise ValueError("unexpected")\n            return dag.task_dict.get(task_id) or factory(task_id=task_id)\n\n        return (make_task(x) for x in input_str.split(", "))\n\n    @staticmethod\n    def cleared_downstream(task):\n        """Helper to return tasks that would be cleared if **downstream** selected."""\n        upstream = False\n        return set(\n            task.dag.partial_subset(\n                task_ids=[task.task_id],\n                include_downstream=not upstream,\n                include_upstream=upstream,\n            ).tasks\n        )\n\n    @staticmethod\n    def cleared_upstream(task):\n        """Helper to return tasks that would be cleared if **upstream** selected."""\n        upstream = True\n        return set(\n            task.dag.partial_subset(\n                task_ids=task.task_id,\n                include_downstream=not upstream,\n                include_upstream=upstream,\n            ).tasks\n        )\n\n    @staticmethod\n    def cleared_neither(task):\n        """Helper to return tasks that would be cleared if **upstream** selected."""\n        return set(\n            task.dag.partial_subset(\n                task_ids=[task.task_id],\n                include_downstream=False,\n                include_upstream=False,\n            ).tasks\n        )\n\n    def test_get_flat_relative_ids_with_setup(self):\n        with DAG(dag_id="test_dag", schedule=None, start_date=pendulum.now()) as dag:\n            s1, w1, w2, w3, w4, t1 = self.make_tasks(dag, "s1, w1, w2, w3, w4, t1")\n\n        s1 >> w1 >> w2 >> w3\n\n        # w1 is downstream of s1, and s1 has no teardown, so clearing w1 clears s1\n        assert set(w1.get_upstreams_only_setups_and_teardowns()) == {s1}\n        # same with w2 and w3\n        assert set(w2.get_upstreams_only_setups_and_teardowns()) == {s1}\n        assert set(w3.get_upstreams_only_setups_and_teardowns()) == {s1}\n        # so if we clear w2, we should also get s1, and w3, but not w1\n        assert self.cleared_downstream(w2) == {s1, w2, w3}\n\n        w3 >> t1\n\n        # now, w2 has a downstream teardown, but it\'s not connected directly to s1\n        assert set(w2.get_upstreams_only_setups_and_teardowns()) == {s1}\n        # so if we clear downstream then s1 will be cleared, and t1 will be cleared but only by virtue of\n        # being downstream of w2 -- not as a result of being the teardown for s1, which it ain\'t\n        assert self.cleared_downstream(w2) == {s1, w2, w3, t1}\n        # and, another consequence of not linking s1 and t1 is that when we clear upstream, note that\n        # t1 doesn\'t get cleared -- cus it\'s not upstream and it\'s not linked to s1\n        assert self.cleared_upstream(w2) == {s1, w1, w2}\n        # note also that if we add a 4th work task after t1, it will still be "in scope" for s1\n        t1 >> w4\n        assert self.cleared_downstream(w4) == {s1, w4}\n\n        s1 >> t1\n\n        # now, we know that t1 is the teardown for s1, so now we know that s1 will be "torn down"\n        # by the time w4 runs, so we now know that w4 no longer requires s1, so when we clear w4,\n        # s1 will not also be cleared\n        self.cleared_downstream(w4) == {w4}\n        assert set(w1.get_upstreams_only_setups_and_teardowns()) == {s1, t1}\n        assert self.cleared_downstream(w1) == {s1, w1, w2, w3, t1, w4}\n        assert self.cleared_upstream(w1) == {s1, w1, t1}\n        assert set(w2.get_upstreams_only_setups_and_teardowns()) == {s1, t1}\n        assert set(w2.get_upstreams_follow_setups()) == {s1, w1, t1}\n        assert self.cleared_downstream(w2) == {s1, w2, w3, t1, w4}\n        assert self.cleared_upstream(w2) == {s1, w1, w2, t1}\n        assert self.cleared_downstream(w3) == {s1, w3, t1, w4}\n        assert self.cleared_upstream(w3) == {s1, w1, w2, w3, t1}\n\n    def test_get_flat_relative_ids_with_setup_nested_ctx_mgr(self):\n        """Let\'s test some gnarlier cases here"""\n        with DAG(dag_id="test_dag", schedule=None, start_date=pendulum.now()) as dag:\n            s1, t1, s2, t2 = self.make_tasks(dag, "s1, t1, s2, t2")\n            with s1 >> t1:\n                BaseOperator(task_id="w1")\n                with s2 >> t2:\n                    BaseOperator(task_id="w2")\n                    BaseOperator(task_id="w3")\n        # to_do: implement tests\n\n    def test_get_flat_relative_ids_with_setup_nested_no_ctx_mgr(self):\n        """Let\'s test some gnarlier cases here"""\n        with DAG(dag_id="test_dag", schedule=None, start_date=pendulum.now()) as dag:\n            s1, t1, s2, t2, w1, w2, w3 = self.make_tasks(dag, "s1, t1, s2, t2, w1, w2, w3")\n        s1 >> t1\n        s1 >> w1 >> t1\n        s1 >> s2\n        s2 >> t2\n        s2 >> w2 >> w3 >> t2\n\n        assert w1.get_flat_relative_ids(upstream=True) == {"s1"}\n        assert w1.get_flat_relative_ids(upstream=False) == {"t1"}\n        assert self.cleared_downstream(w1) == {s1, w1, t1}\n        assert self.cleared_upstream(w1) == {s1, w1, t1}\n        assert w3.get_flat_relative_ids(upstream=True) == {"s1", "s2", "w2"}\n        assert w3.get_flat_relative_ids(upstream=False) == {"t2"}\n        assert t1 not in w2.get_flat_relatives(upstream=False)  # t1 not required by w2\n        # t1 only included because s1 is upstream\n        assert self.cleared_upstream(w2) == {s1, t1, s2, w2, t2}\n        # t1 not included because t1 is not downstream\n        assert self.cleared_downstream(w2) == {s2, w2, w3, t2}\n        # t1 only included because s1 is upstream\n        assert self.cleared_upstream(w3) == {s1, t1, s2, w2, w3, t2}\n        # t1 not included because t1 is not downstream\n        assert self.cleared_downstream(w3) == {s2, w3, t2}\n\n    def test_get_flat_relative_ids_follows_teardowns(self):\n        with DAG(dag_id="test_dag", schedule=None, start_date=pendulum.now()) as dag:\n            s1, w1, w2, t1 = self.make_tasks(dag, "s1, w1, w2, t1")\n        s1 >> w1 >> [w2, t1]\n        s1 >> t1\n        # w2, we infer, does not require s1, since t1 does not come after it\n        assert set(w2.get_upstreams_only_setups_and_teardowns()) == set()\n        # w1, however, *does* require s1, since t1 is downstream of it\n        assert set(w1.get_upstreams_only_setups_and_teardowns()) == {s1, t1}\n        # downstream is just downstream and includes teardowns\n        assert self.cleared_downstream(w1) == {s1, w1, w2, t1}\n        assert self.cleared_downstream(w2) == {w2}\n        # and if there\'s a downstream setup, it will be included as well\n        s2 = BaseOperator(task_id="s2", dag=dag).as_setup()\n        t1 >> s2\n        assert w1.get_flat_relative_ids(upstream=False) == {"t1", "w2", "s2"}\n        assert self.cleared_downstream(w1) == {s1, w1, w2, t1, s2}\n\n    def test_get_flat_relative_ids_two_tasks_diff_setup_teardowns(self):\n        with DAG(dag_id="test_dag", schedule=None, start_date=pendulum.now()) as dag:\n            s1, t1, s2, t2, w1, w2 = self.make_tasks(dag, "s1, t1, s2, t2, w1, w2")\n        s1 >> w1 >> [w2, t1]\n        s1 >> t1\n        s2 >> t2\n        s2 >> w2 >> t2\n\n        assert set(w1.get_upstreams_only_setups_and_teardowns()) == {s1, t1}\n        # s2 is included because w2 is included\n        assert self.cleared_downstream(w1) == {s1, w1, t1, s2, w2, t2}\n        assert self.cleared_neither(w1) == {s1, w1, t1}\n        assert set(w2.get_upstreams_only_setups_and_teardowns()) == {s2, t2}\n        assert self.cleared_downstream(w2) == {s2, w2, t2}\n\n    def test_get_flat_relative_ids_one_task_multiple_setup_teardowns(self):\n        with DAG(dag_id="test_dag", schedule=None, start_date=pendulum.now()) as dag:\n            s1a, s1b, t1, s2, t2, s3, t3a, t3b, w1, w2 = self.make_tasks(\n                dag, "s1a, s1b, t1, s2, t2, s3, t3a, t3b, w1, w2"\n            )\n        # teardown t1 has two setups, s1a and s1b\n        [s1a, s1b] >> t1\n        # work 1 requires s1a and s1b, both of which are torn down by t1\n        [s1a, s1b] >> w1 >> [w2, t1]\n\n        # work 2 requires s2, and s3. s2 is torn down by t2. s3 is torn down by two teardowns, t3a and t3b.\n        s2 >> t2\n        s2 >> w2 >> t2\n        s3 >> w2 >> [t3a, t3b]\n        s3 >> [t3a, t3b]\n        assert set(w1.get_upstreams_only_setups_and_teardowns()) == {s1a, s1b, t1}\n        # since w2 is downstream of w1, w2 gets cleared.\n        # and since w2 gets cleared, we should also see s2 and s3 in here\n        assert self.cleared_downstream(w1) == {s1a, s1b, w1, t1, s3, t3a, t3b, w2, s2, t2}\n        assert set(w2.get_upstreams_only_setups_and_teardowns()) == {s2, t2, s3, t3a, t3b}\n        assert self.cleared_downstream(w2) == {s2, s3, w2, t2, t3a, t3b}\n\n    def test_get_flat_relative_ids_with_setup_and_groups(self):\n        """\n        This is a dag with a setup / teardown at dag level and two task groups that have\n        their own setups / teardowns.\n\n        When we do tg >> dag_teardown, teardowns should be excluded from tg leaves.\n        """\n        dag = DAG(dag_id="test_dag", schedule=None, start_date=pendulum.now())\n        with dag:\n            dag_setup = BaseOperator(task_id="dag_setup").as_setup()\n            dag_teardown = BaseOperator(task_id="dag_teardown").as_teardown()\n            dag_setup >> dag_teardown\n            for group_name in ("g1", "g2"):\n                with TaskGroup(group_name) as tg:\n                    group_setup = BaseOperator(task_id="group_setup").as_setup()\n                    w1 = BaseOperator(task_id="w1")\n                    w2 = BaseOperator(task_id="w2")\n                    w3 = BaseOperator(task_id="w3")\n                    group_teardown = BaseOperator(task_id="group_teardown").as_teardown()\n                    group_setup >> w1 >> w2 >> w3 >> group_teardown\n                    group_setup >> group_teardown\n                dag_setup >> tg >> dag_teardown\n        g2_w2 = dag.task_dict["g2.w2"]\n        g2_w3 = dag.task_dict["g2.w3"]\n        g2_group_teardown = dag.task_dict["g2.group_teardown"]\n\n        # the line `dag_setup >> tg >> dag_teardown` should be equivalent to\n        # dag_setup >> group_setup; w3 >> dag_teardown\n        # i.e. not group_teardown >> dag_teardown\n        # this way the two teardowns can run in parallel\n        # so first, check that dag_teardown not downstream of group 2 teardown\n        # this means they can run in parallel\n        assert "dag_teardown" not in g2_group_teardown.downstream_task_ids\n        # and just document that g2 teardown is in effect a dag leaf\n        assert g2_group_teardown.downstream_task_ids == set()\n        # group 2 task w3 is in the scope of 2 teardowns -- the dag teardown and the group teardown\n        # it is arrowed to both of them\n        assert g2_w3.downstream_task_ids == {"g2.group_teardown", "dag_teardown"}\n        # dag teardown should have 3 upstreams: the last work task in groups 1 and 2, and its setup\n        assert dag_teardown.upstream_task_ids == {"g1.w3", "g2.w3", "dag_setup"}\n\n        assert {x.task_id for x in g2_w2.get_upstreams_only_setups_and_teardowns()} == {\n            "dag_setup",\n            "dag_teardown",\n            "g2.group_setup",\n            "g2.group_teardown",\n        }\n\n        # clearing g2.w2 clears all setups and teardowns and g2.w2 and g2.w2\n        # but not anything from g1\n        assert {x.task_id for x in self.cleared_downstream(g2_w2)} == {\n            "dag_setup",\n            "dag_teardown",\n            "g2.group_setup",\n            "g2.group_teardown",\n            "g2.w3",\n            "g2.w2",\n        }\n        assert {x.task_id for x in self.cleared_upstream(g2_w2)} == {\n            "dag_setup",\n            "dag_teardown",\n            "g2.group_setup",\n            "g2.group_teardown",\n            "g2.w1",\n            "g2.w2",\n        }\n\n    def test_clear_upstream_not_your_setup(self):\n        """\n        When you have a work task that comes after a setup, then if you clear upstream\n        the setup (and its teardown) will be cleared even though strictly speaking you don\'t\n        "require" it since, depending on speed of execution, it might be torn down by t1\n        before / while w2 runs.  It just gets cleared by virtue of it being upstream, and\n        that\'s what you requested.  And its teardown gets cleared too.  But w1 doesn\'t.\n        """\n        with DAG(dag_id="test_dag", schedule=None, start_date=pendulum.now()) as dag:\n            s1, w1, w2, t1 = self.make_tasks(dag, "s1, w1, w2, t1")\n            s1 >> w1 >> t1.as_teardown(setups=s1)\n            s1 >> w2\n            # w2 is downstream of s1, so when clearing upstream, it should clear s1 (since it\n            # is upstream of w2) and t1 since it\'s the teardown for s1 even though not downstream of w1\n            assert self.cleared_upstream(w2) == {s1, w2, t1}\n\n    def test_clearing_teardown_no_clear_setup(self):\n        with DAG(dag_id="test_dag", schedule=None, start_date=pendulum.now()) as dag:\n            s1, w1, t1 = self.make_tasks(dag, "s1, w1, t1")\n            s1 >> t1\n            # clearing t1 does not clear s1\n            assert self.cleared_downstream(t1) == {t1}\n            s1 >> w1 >> t1\n            # that isn\'t changed with the introduction of w1\n            assert self.cleared_downstream(t1) == {t1}\n            # though, of course, clearing w1 clears them all\n            assert self.cleared_downstream(w1) == {s1, w1, t1}\n\n    def test_clearing_setup_clears_teardown(self):\n        with DAG(dag_id="test_dag", schedule=None, start_date=pendulum.now()) as dag:\n            s1, w1, t1 = self.make_tasks(dag, "s1, w1, t1")\n            s1 >> t1\n            s1 >> w1 >> t1\n            # clearing w1 clears all always\n            assert self.cleared_upstream(w1) == {s1, w1, t1}\n            assert self.cleared_downstream(w1) == {s1, w1, t1}\n            assert self.cleared_neither(w1) == {s1, w1, t1}\n            # clearing s1 clears t1 always\n            assert self.cleared_upstream(s1) == {s1, t1}\n            assert self.cleared_downstream(s1) == {s1, w1, t1}\n            assert self.cleared_neither(s1) == {s1, t1}\n\n    @pytest.mark.parametrize(\n        ("upstream", "downstream", "expected"),\n        [\n            (False, False, {"my_teardown", "my_setup"}),\n            (False, True, {"my_setup", "my_work", "my_teardown"}),\n            (True, False, {"my_teardown", "my_setup"}),\n            (True, True, {"my_setup", "my_work", "my_teardown"}),\n        ],\n    )\n    def test_clearing_setup_clears_teardown_taskflow(self, upstream, downstream, expected):\n        with DAG(dag_id="test_dag", schedule=None, start_date=pendulum.now()) as dag:\n\n            @setup\n            def my_setup(): ...\n\n            @task_decorator\n            def my_work(): ...\n\n            @teardown\n            def my_teardown(): ...\n\n            s1 = my_setup()\n            w1 = my_work()\n            t1 = my_teardown()\n            s1 >> w1 >> t1\n            s1 >> t1\n        assert {\n            x.task_id\n            for x in dag.partial_subset(\n                "my_setup", include_upstream=upstream, include_downstream=downstream\n            ).tasks\n        } == expected\n\n    def test_get_flat_relative_ids_two_tasks_diff_setup_teardowns_deeper(self):\n        with DAG(dag_id="test_dag", schedule=None, start_date=pendulum.now()) as dag:\n            s1, t1, s2, t2, w1, w2, s3, w3, t3 = self.make_tasks(dag, "s1, t1, s2, t2, w1, w2, s3, w3, t3")\n        s1 >> w1 >> t1\n        s1 >> t1\n        w1 >> w2\n\n        # with the below, s2 is not downstream of w1, but it\'s the setup for w2\n        # so it should be cleared when w1 is cleared\n        s2 >> w2 >> t2\n        s2 >> t2\n\n        assert set(w1.get_upstreams_only_setups_and_teardowns()) == {s1, t1}\n        assert set(w2.get_upstreams_only_setups_and_teardowns()) == {s2, t2}\n        assert self.cleared_downstream(w1) == {s1, w1, t1, s2, w2, t2}\n        assert self.cleared_downstream(w2) == {s2, w2, t2}\n\n        # now, what if s2 itself has a setup and teardown?\n        s3 >> s2 >> t3\n        s3 >> t3\n        # note that s3 is excluded because it\'s assumed that a setup won\'t have a setup\n        # so, we don\'t continue to recurse for setups after reaching the setups for\n        # the downstream work tasks\n        # but, t3 is included since it\'s a teardown for s2\n        assert self.cleared_downstream(w1) == {s1, w1, t1, s2, w2, t2, t3}\n\n    def test_clearing_behavior_multiple_setups_for_work_task(self):\n        with DAG(dag_id="test_dag", schedule=None, start_date=pendulum.now()) as dag:\n            s1, t1, s2, t2, w1, w2, s3, w3, t3 = self.make_tasks(dag, "s1, t1, s2, t2, w1, w2, s3, w3, t3")\n        s1 >> t1\n        s2 >> t2\n        s3 >> t3\n        s1 >> s2 >> s3 >> w1 >> w2 >> [t1, t2, t3]\n\n        assert self.cleared_downstream(w1) == {s1, s2, s3, w1, w2, t1, t2, t3}\n        assert self.cleared_downstream(w2) == {s1, s2, s3, w2, t1, t2, t3}\n        assert self.cleared_downstream(s3) == {s1, s2, s3, w1, w2, t1, t2, t3}\n        # even if we don\'t include upstream / downstream, setups and teardowns are cleared\n        assert self.cleared_neither(w2) == {s3, t3, s2, t2, s1, t1, w2}\n        assert self.cleared_neither(w1) == {s3, t3, s2, t2, s1, t1, w1}\n        # but, a setup doesn\'t formally have a setup, so if we only clear s3, say then its upstream setups\n        # are not also cleared\n        assert self.cleared_neither(s3) == {s3, t3}\n        assert self.cleared_neither(s2) == {s2, t2}\n\n    def test_clearing_behavior_multiple_setups_for_work_task2(self):\n        with DAG(dag_id="test_dag", schedule=None, start_date=pendulum.now()) as dag:\n            s1, t1, s2, t2, w1, w2, s3, w3, t3 = self.make_tasks(dag, "s1, t1, s2, t2, w1, w2, s3, w3, t3")\n        s1 >> t1\n        s2 >> t2\n        s3 >> t3\n        [s1, s2, s3] >> w1 >> w2 >> [t1, t2, t3]\n\n        assert self.cleared_downstream(w1) == {s1, s2, s3, w1, w2, t1, t2, t3}\n        assert self.cleared_downstream(w2) == {s1, s2, s3, w2, t1, t2, t3}\n\n    def test_clearing_behavior_more_tertiary_weirdness(self):\n        with DAG(dag_id="test_dag", schedule=None, start_date=pendulum.now()) as dag:\n            s1, t1, s2, t2, w1, w2, s3, t3 = self.make_tasks(dag, "s1, t1, s2, t2, w1, w2, s3, t3")\n        s1 >> t1\n        s2 >> t2\n        s1 >> w1 >> s2 >> w2 >> [t1, t2]\n        s2 >> w2 >> t2\n        s3 >> s2 >> t3\n        s3 >> t3\n\n        def sort(task_list):\n            return sorted(x.task_id for x in task_list)\n\n        assert set(w1.get_upstreams_only_setups_and_teardowns()) == {s1, t1}\n        # s2 is included because w2 is included\n        assert self.cleared_downstream(w1) == {s1, w1, t1, s2, w2, t2, t3}\n        assert self.cleared_downstream(w2) == {s1, t1, s2, w2, t2, t3}\n        # t3 is included since s2 is included and s2 >> t3\n        # but s3 not included because it\'s assumed that a setup doesn\'t have a setup\n        assert self.cleared_neither(w2) == {s1, w2, t1, s2, t2, t3}\n\n        # since we\'re clearing upstream, s3 is upstream of w2, so s3 and t3 are included\n        # even though w2 doesn\'t require them\n        # s2 and t2 are included for obvious reasons, namely that w2 requires s2\n        # and s1 and t1 are included for the same reason\n        # w1 included since it is upstream of w2\n        assert sort(self.cleared_upstream(w2)) == sort({s1, t1, s2, t2, s3, t3, w1, w2})\n\n        # t3 is included here since it\'s a teardown for s2\n        assert set(w2.get_upstreams_only_setups_and_teardowns()) == {s2, t2, s1, t1, t3}\n\n    def test_clearing_behavior_more_tertiary_weirdness2(self):\n        with DAG(dag_id="test_dag", schedule=None, start_date=pendulum.now()) as dag:\n            s1, t1, s2, t2, w1, w2, s3, t3 = self.make_tasks(dag, "s1, t1, s2, t2, w1, w2, s3, t3")\n        s1 >> t1\n        s2 >> t2\n        s1 >> w1 >> t1\n        s2 >> t1 >> t2\n\n        def sort(task_list):\n            return sorted(x.task_id for x in task_list)\n\n        # t2 included since downstream, but s2 not included since it\'s not required by t2\n        # and clearing teardown does not clear the setup\n        assert self.cleared_downstream(w1) == {s1, w1, t1, t2}\n\n        # even though t1 is cleared here, s2 and t2 are not "setup and teardown" for t1\n        # so they are not included\n        assert self.cleared_neither(w1) == {s1, w1, t1}\n        assert self.cleared_upstream(w1) == {s1, w1, t1}\n\n        # t1 does not have a setup or teardown\n        # but t2 is downstream so it\'s included\n        # and s2 is not included since clearing teardown does not clear the setup\n        assert self.cleared_downstream(t1) == {t1, t2}\n        # t1 does not have a setup or teardown\n        assert self.cleared_neither(t1) == {t1}\n        # s2 included since upstream, and t2 included since s2 included\n        assert self.cleared_upstream(t1) == {s1, t1, s2, t2, w1}\n\n    def test_clearing_behavior_just_teardown(self):\n        with DAG(dag_id="test_dag", schedule=None, start_date=pendulum.now()) as dag:\n            s1, t1 = self.make_tasks(dag, "s1, t1")\n        s1 >> t1\n        assert set(t1.get_upstreams_only_setups_and_teardowns()) == set()\n        assert self.cleared_upstream(t1) == {s1, t1}\n        assert self.cleared_downstream(t1) == {t1}\n        assert self.cleared_neither(t1) == {t1}\n        assert set(s1.get_upstreams_only_setups_and_teardowns()) == set()\n        assert self.cleared_upstream(s1) == {s1, t1}\n        assert self.cleared_downstream(s1) == {s1, t1}\n        assert self.cleared_neither(s1) == {s1, t1}\n\n    def test_validate_setup_teardown_trigger_rule(self):\n        with DAG(\n            dag_id="direct_setup_trigger_rule", start_date=pendulum.now(), schedule=None, catchup=False\n        ) as dag:\n            s1, w1 = self.make_tasks(dag, "s1, w1")\n            s1 >> w1\n            dag.validate_setup_teardown()\n            w1.trigger_rule = TriggerRule.ONE_FAILED\n            with pytest.raises(\n                Exception, match="Setup tasks must be followed with trigger rule ALL_SUCCESS."\n            ):\n                dag.validate_setup_teardown()\n\n\n@pytest.mark.parametrize(\n    ("disable", "bundle_version", "expected"),\n    [\n        (True, "some-version", None),\n        (False, "some-version", "some-version"),\n    ],\n)\ndef test_disable_bundle_versioning(disable, bundle_version, expected, dag_maker, session, clear_dags):\n    """When bundle versioning is disabled for a dag, the dag run should not have a bundle version."""\n\n    def hello():\n        print("hello")\n\n    with dag_maker(disable_bundle_versioning=disable, session=session, serialized=True) as dag:\n        PythonOperator(task_id="hi", python_callable=hello)\n\n    assert dag.disable_bundle_versioning is disable\n\n    # the dag *always* has bundle version\n    dag_model = session.scalar(select(DagModel).where(DagModel.dag_id == dag.dag_id))\n    dag_model.bundle_version = bundle_version\n    session.commit()\n\n    dr = dag.create_dagrun(\n        run_id="abcoercuhcrh",\n        run_after=pendulum.now(),\n        run_type="manual",\n        triggered_by=DagRunTriggeredByType.TEST,\n        state=None,\n    )\n\n    # but it only gets stamped on the dag run when bundle versioning not disabled\n    assert dr.bundle_version == expected\n\n\ndef test_get_run_data_interval():\n    with DAG("dag", schedule=None, start_date=DEFAULT_DATE) as dag:\n        EmptyOperator(task_id="empty_task")\n\n    dr = _create_dagrun(\n        dag,\n        logical_date=timezone.utcnow(),\n        data_interval=(DEFAULT_DATE, DEFAULT_DATE),\n        run_type=DagRunType.MANUAL,\n    )\n    timetable = coerce_to_core_timetable(dag.timetable)\n    assert get_run_data_interval(timetable, dr) == DataInterval(start=DEFAULT_DATE, end=DEFAULT_DATE)\n\n\n@pytest.mark.need_serialized_dag\ndef test_get_run_data_interval_pre_aip_39():\n    with DAG(\n        "dag",\n        schedule="0 0 * * *",\n        start_date=DEFAULT_DATE,\n    ) as dag:\n        EmptyOperator(task_id="empty_task")\n\n    current_ts = timezone.utcnow()\n    dr = _create_dagrun(\n        dag,\n        logical_date=current_ts,\n        data_interval=(None, None),\n        run_type=DagRunType.MANUAL,\n    )\n    ds_start = current_ts.replace(hour=0, minute=0, second=0, microsecond=0) - timedelta(days=1)\n    ds_end = current_ts.replace(hour=0, minute=0, second=0, microsecond=0)\n    timetable = coerce_to_core_timetable(dag.timetable)\n    assert get_run_data_interval(timetable, dr) == DataInterval(start=ds_start, end=ds_end)\n\n\n@pytest.mark.parametrize(\n    ("schedule", "next_run", "next_interval", "next_run_after", "next_partition_key", "next_partition_date"),\n    [\n        (\n            CronPartitionTimetable(\n                "0 0 * * *",\n                timezone=pendulum.UTC,\n            ),\n            None,\n            None,\n            TEST_DATE + timedelta(days=1),\n            (TEST_DATE + timedelta(days=1)).strftime(r"%Y-%m-%dT%H:%M:%S"),\n            TEST_DATE + timedelta(days=1),\n        ),\n        (\n            "0 0 * * *",\n            TEST_DATE,\n            DataInterval(start=TEST_DATE, end=TEST_DATE + timedelta(days=1)),\n            TEST_DATE + timedelta(days=1),\n            None,\n            None,\n        ),\n        (\n            None,\n            None,\n            None,\n            None,\n            None,\n            None,\n        ),\n        (\n            "@once",\n            None,\n            None,\n            None,\n            None,\n            None,\n        ),\n    ],\n)\ndef test_calculate_dagrun_date_fields(\n    schedule,\n    dag_maker,\n    next_run,\n    next_interval,\n    next_run_after,\n    next_partition_key,\n    next_partition_date,\n):\n    with dag_maker(schedule=schedule, catchup=True, start_date=TEST_DATE):\n        BashOperator(task_id="hi", bash_command="yo")\n\n    run = dag_maker.create_dagrun()\n    serdag = dag_maker.serialized_dag\n    dag_model = dag_maker.dag_model\n    dag_model.calculate_dagrun_date_fields(dag=serdag, last_automated_run=run)\n    assert dag_model.next_dagrun_data_interval == next_interval\n    assert dag_model.next_dagrun == next_run\n    assert dag_model.next_dagrun_create_after == next_run_after\n    assert dag_model.next_dagrun_partition_key == next_partition_key\n    assert dag_model.next_dagrun_partition_date == next_partition_date\n',
        }
